// ─── Trial & Subscription Helpers ────────────────────────────────────────────
const TRIAL_DAYS = 7;

function getTrialStatus() {
  // Returns: "trial" | "expired" | "pending" | "active"
  try {
    const p = JSON.parse(localStorage.getItem(sk("user_profile")) || "{}");
    // Admin override — always active
    if (p.subscriptionActive === true) return "active";
    // Payment submitted, awaiting approval
    if (p.paymentSubmitted === true) return "pending";
    // Hardcoded USERS (admin accounts) are always active
    const u = getCurrentUser();
    if (u && USERS.some(x => x.username === u.username)) return "active";
    // Check trial period
    if (!p.registeredAt) return "active"; // no date = old account, grace
    const regDate = new Date(p.registeredAt);
    const now = new Date();
    const daysSince = (now - regDate) / (1000 * 60 * 60 * 24);
    if (daysSince < TRIAL_DAYS) return "trial";
    return "expired";
  } catch { return "active"; }
}

function getTrialDaysLeft() {
  try {
    const p = JSON.parse(localStorage.getItem(sk("user_profile")) || "{}");
    if (!p.registeredAt) return TRIAL_DAYS;
    const daysSince = (new Date() - new Date(p.registeredAt)) / (1000 * 60 * 60 * 24);
    return Math.max(0, Math.ceil(TRIAL_DAYS - daysSince));
  } catch { return 0; }
}

function markPaymentSubmitted(bankDetails, selectedPlan) {
  try {
    const p = JSON.parse(localStorage.getItem(sk("user_profile")) || "{}");
    p.paymentSubmitted = true;
    p.paymentSubmittedAt = new Date().toISOString();
    p.bankDetails = bankDetails; // stored locally only, also emailed to admin
    if (selectedPlan) p.plan = selectedPlan;
    localStorage.setItem(sk("user_profile"), JSON.stringify(p));
  } catch {}
}

// ─── Plan Tier Helpers ──────────────────────────────────────────────────────
const PLAN_CERT_LIMITS = { lite: 20, pro: Infinity, proplus: Infinity };

function getUserPlan() {
  try {
    const u = getCurrentUser();
    if (u && USERS.some(x => x.username === u.username)) return "proplus";
    const p = JSON.parse(localStorage.getItem(sk("user_profile")) || "{}");
    return p.plan || "proplus";
  } catch { return "proplus"; }
}

function getMonthCertCount(records) {
  const now = new Date();
  const monthStart = new Date(now.getFullYear(), now.getMonth(), 1);
  return (records || []).filter(r => {
    if (!r.savedAt) return false;
    return new Date(r.savedAt) >= monthStart;
  }).length;
}

// Admin unlock — called from DevTools or admin panel: unlockUser("username")
window.unlockUser = function(username) {
  try {
    const key = `${username}_user_profile`;
    const p = JSON.parse(localStorage.getItem(key) || "{}");
    p.subscriptionActive = true;
    p.paymentSubmitted = false;
    localStorage.setItem(key, JSON.stringify(p));
    console.log(`✅ ${username} unlocked successfully`);
  } catch(e) { console.error(e); }
};
