// ── helpers ──────────────────────────────────────────────────────────────────
function today() {
  return new Date();
}
function todayISO() {
  return new Date().toISOString().slice(0,10);
}
// Converts UK dates (DD/MM/YY or DD/MM/YYYY) and ISO dates to YYYY-MM-DD.
// Returns empty string if unparseable.
function normaliseDate(str) {
  if (!str) return "";
  str = str.trim();
  // Already ISO: YYYY-MM-DD
  if (/^\d{4}-\d{2}-\d{2}$/.test(str)) return str;
  // DD/MM/YYYY or D/M/YYYY or DD/MM/YY or D/M/YY
  const ukSlash = str.match(/^(\d{1,2})\/(\d{1,2})\/(\d{2,4})$/);
  if (ukSlash) {
    let [, d, m, y] = ukSlash;
    if (y.length === 2) y = "20" + y;
    return `${y}-${m.padStart(2,"0")}-${d.padStart(2,"0")}`;
  }
  // DD-MM-YYYY or D-M-YYYY or DD-MM-YY or D-M-YY
  const ukDash = str.match(/^(\d{1,2})-(\d{1,2})-(\d{2,4})$/);
  if (ukDash) {
    let [, d, m, y] = ukDash;
    if (y.length === 2) y = "20" + y;
    return `${y}-${m.padStart(2,"0")}-${d.padStart(2,"0")}`;
  }
  return str;
}
function formatDate(d) {
  const days = ["SUN","MON","TUE","WED","THU","FRI","SAT"];
  const months = ["JAN","FEB","MAR","APR","MAY","JUN","JUL","AUG","SEP","OCT","NOV","DEC"];
  return `${days[d.getDay()]}-${String(d.getDate()).padStart(2,"0")}-${months[d.getMonth()]}-${d.getFullYear()}`;
}
function nextYear() {
  const d = new Date();
  d.setFullYear(d.getFullYear() + 1);
  return d;
}

// ── shared components ─────────────────────────────────────────────────────────
const GSR_LOGO = "data:image/png;base64,";

// Returns the current user's logo from their profile, falling back to the WLG_LOGO default
function getCompanyLogo() {
  try {
    const p = JSON.parse(localStorage.getItem(sk("user_profile")) || "{}");
    return p.logoImage || WLG_LOGO;
  } catch { return WLG_LOGO; }
}
// Returns the current user's full profile object (or empty object if not set up yet)
function getCompanyProfile() {
  try { return JSON.parse(localStorage.getItem(sk("user_profile")) || "{}"); } catch { return {}; }
}

function Header({ title, onBack, right }) {
  return (
    <div style={{ padding:"12px 16px", display:"flex", alignItems:"center", gap:10, borderBottom:"1px solid rgba(255,255,255,0.08)", flexShrink:0 }}>
      {onBack && (
        <button onClick={onBack} style={{ width:36, height:36, borderRadius:10, background:"#1e3044", border:"1px solid #2a4058", display:"flex", alignItems:"center", justifyContent:"center", cursor:"pointer", color:"#8b9db0", flexShrink:0 }}>
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" width="18" height="18"><path d="M15 18l-6-6 6-6"/></svg>
        </button>
      )}
      <span style={{ flex:1, color:"#e8edf2", fontWeight:700, fontSize:15, fontFamily:"'Segoe UI',sans-serif" }}>{title}</span>
      {right}
    </div>
  );
}

function BottomBar({ onHome, onNext, onOptions, nextLabel="Next" }) {
  return (
    <div style={{ position:"sticky", bottom:0, left:0, right:0, padding:"10px 16px 16px", background:"linear-gradient(0deg, #0d1f2d 70%, transparent 100%)", display:"flex", gap:8, zIndex:10 }}>
      <button onClick={onHome} style={{ padding:"13px 18px", borderRadius:12, background:"rgba(255,255,255,0.08)", color:"#e8edf2", fontWeight:700, fontSize:14, border:"1px solid rgba(255,255,255,0.15)", cursor:"pointer", fontFamily:"'Segoe UI',sans-serif" }}>Home</button>
      {onOptions ? (
        <button onClick={onOptions} style={{ flex:1, padding:"13px", borderRadius:12, background:"rgba(255,255,255,0.08)", color:"#e8edf2", fontWeight:700, fontSize:14, border:"1px solid rgba(255,255,255,0.15)", cursor:"pointer", fontFamily:"'Segoe UI',sans-serif" }}>Options</button>
      ) : onNext ? (
        <button onClick={onNext} style={{ flex:1, padding:"13px", borderRadius:12, background:"#3b82f6", color:"#fff", fontWeight:700, fontSize:15, border:"none", cursor:"pointer", fontFamily:"'Segoe UI',sans-serif" }}>{nextLabel}</button>
      ) : null}
    </div>
  );
}

function FormInput({ label, value, onChange, placeholder, type="text", multiline=false, maxLength, step, inputMode }) {
  return (
    <div style={{ margin:"0 14px 8px" }}>
      {label && <div style={{ fontSize:11, color:"rgba(255,255,255,0.6)", padding:"0 0 4px", fontWeight:600, fontFamily:"'Segoe UI',sans-serif", textTransform:"uppercase", letterSpacing:0.5 }}>{label}</div>}
      {multiline ? (
        <textarea value={value} onChange={e=>onChange(e.target.value)} placeholder={placeholder} maxLength={maxLength}
          style={{ width:"100%", boxSizing:"border-box", padding:"10px 12px", border:"1px solid #2a4058", background:"#1e3044", borderRadius:10, fontSize:14, fontFamily:"'Segoe UI',sans-serif", resize:"vertical", minHeight:80, outline:"none", color:"#e8edf2" }}/>
      ) : (
        <input type={type} value={value} onChange={e=>onChange(e.target.value)} placeholder={placeholder} step={step} inputMode={inputMode}
          onFocus={e => setTimeout(() => e.target.scrollIntoView({ behavior:"smooth", block:"center" }), 300)}
          style={{ width:"100%", boxSizing:"border-box", padding:"10px 12px", border:"1px solid #2a4058", background:"#1e3044", borderRadius:10, fontSize:14, fontFamily:"'Segoe UI',sans-serif", outline:"none", color:"#e8edf2" }}/>
      )}
      {maxLength && <div style={{ fontSize:11, color:"rgba(255,255,255,0.4)", padding:"4px 0 0" }}>You Can Enter {maxLength} Characters</div>}
    </div>
  );
}

function RadioGroup({ options, value, onChange }) {
  return (
    <div style={{ display:"flex", gap:8, flexWrap:"wrap" }}>
      {options.map(opt => (
        <button key={opt} onClick={()=>onChange(opt)} style={{
          flex:1, padding:"8px", borderRadius:8, fontSize:12, fontWeight:700, cursor:"pointer", fontFamily:"'Segoe UI',sans-serif",
          border:"1px solid", minWidth:60, textAlign:"center",
          borderColor: value===opt ? "#3b82f6" : "rgba(255,255,255,0.12)",
          background: value===opt ? "rgba(59,130,246,0.15)" : "rgba(255,255,255,0.04)",
          color: value===opt ? "#3b82f6" : "rgba(255,255,255,0.45)"
        }}>{opt}</button>
      ))}
    </div>
  );
}

function SectionHeader({ title, actions }) {
  return (
    <div style={{ margin:"14px 14px 8px", padding:"10px 14px", display:"flex", alignItems:"center", justifyContent:"space-between", borderBottom:"1px solid rgba(59,130,246,0.3)" }}>
      <span style={{ color:"#3b82f6", fontWeight:700, fontSize:14, fontFamily:"'Segoe UI',sans-serif", textTransform:"uppercase", letterSpacing:0.8 }}>{title}</span>
      {actions && <div style={{ display:"flex", gap:8 }}>{actions}</div>}
    </div>
  );
}

function Modal({ title, children, onClose }) {
  return (
    <div style={{ position:"fixed", inset:0, background:"rgba(0,0,0,0.5)", display:"flex", alignItems:"center", justifyContent:"center", zIndex:1000, padding:"20px 20px 88px" }}>
      <div style={{ background:"#fff", borderRadius:16, width:"100%", maxWidth:400, overflow:"hidden", boxShadow:"0 20px 60px rgba(0,0,0,0.3)" }}>
        {title && <div style={{ padding:"16px 20px", borderBottom:`2px solid ${BLUE}`, fontWeight:700, fontSize:16, fontFamily:"'Segoe UI',sans-serif", textAlign:"center" }}>{title}</div>}
        <div style={{ padding:"20px 20px 88px" }}>{children}</div>
        {onClose && (
          <button onClick={onClose} style={{ width:"100%", padding:16, background:BLUE, color:"#fff", border:"none", fontWeight:700, fontSize:16, cursor:"pointer", fontFamily:"'Segoe UI',sans-serif" }}>OK</button>
        )}
      </div>
    </div>
  );
}

function PickerScreen({ title, options, onSelect, onBack, allowCustom=false, onSaveCustom }) {
  const [search, setSearch] = useState("");
  const filtered = options.filter(o => o.toLowerCase().includes(search.toLowerCase()));
  const trimmed = search.trim();
  // Show "Use custom" option when typed text doesn't exactly match any existing option
  const exactMatch = options.some(o => o.toLowerCase() === trimmed.toLowerCase());
  const showCustom = allowCustom && trimmed.length > 0 && !exactMatch;

  function handleSelect(opt) {
    onSelect(opt);
  }

  function handleUseCustom() {
    if (onSaveCustom) onSaveCustom(trimmed);
    onSelect(trimmed);
  }

  return (
    <div style={{ display:"flex", flexDirection:"column", height:"100dvh", background:LIGHT_BG, fontFamily:"'Segoe UI',sans-serif" }}>
      <Header title={title} onBack={onBack}/>
      <div style={{ padding:16, background:LIGHT_BG }}>
        <p style={{ color:"#888", fontSize:14, margin:"0 0 12px" }}>Type to search or enter a custom value</p>
        <input value={search} onChange={e=>setSearch(e.target.value)}
          placeholder={`Search ${title.toLowerCase()}...`}
          style={{ width:"100%", boxSizing:"border-box", padding:"10px 14px", border:`2px solid ${BLUE}`, borderRadius:8, fontSize:15, outline:"none" }}/>
      </div>
      <div style={{ flex:1, overflowY:"auto" }}>
        {/* Custom value option — appears at top when typed value doesn't match */}
        {showCustom && (
          <div onClick={handleUseCustom}
            style={{ padding:"14px 16px", background:"#f0f9ff", borderBottom:"2px solid #bfdbfe", fontSize:15, cursor:"pointer",
              display:"flex", alignItems:"center", gap:10 }}
            onMouseEnter={e=>e.currentTarget.style.background="#dbeafe"}
            onMouseLeave={e=>e.currentTarget.style.background="#f0f9ff"}>
            <span style={{ fontSize:18 }}>✏️</span>
            <div>
              <div style={{ fontWeight:700, color:"#1a3a4a" }}>Use "{trimmed}"</div>
              <div style={{ fontSize:12, color:"#666", marginTop:2 }}>Tap to use this custom value — it will be saved for future use</div>
            </div>
          </div>
        )}
        {filtered.map(opt => (
          <div key={opt} onClick={()=>handleSelect(opt)}
            style={{ padding:"14px 16px", background:"#fff", borderBottom:"1px solid #eee", fontSize:15, cursor:"pointer" }}
            onMouseEnter={e=>e.currentTarget.style.background="#eef0ff"}
            onMouseLeave={e=>e.currentTarget.style.background="#fff"}>
            {opt}
          </div>
        ))}
        {filtered.length === 0 && !showCustom && (
          <div style={{ padding:"32px 16px", textAlign:"center", color:"#aaa", fontSize:14 }}>
            No matches found
          </div>
        )}
      </div>
    </div>
  );
}

// ── Calendar ──────────────────────────────────────────────────────────────────
function CalendarModal({ value, onChange, onClose }) {
  const [view, setView] = useState(value || new Date());
  const year = view.getFullYear();
  const month = view.getMonth();
  const months = ["January","February","March","April","May","June","July","August","September","October","November","December"];
  const firstDay = new Date(year, month, 1).getDay();
  const daysInMonth = new Date(year, month+1, 0).getDate();
  const cells = [];
  for(let i=0;i<firstDay;i++) cells.push(null);
  for(let d=1;d<=daysInMonth;d++) cells.push(d);

  const selected = value;
  return (
    <div style={{ position:"fixed", inset:0, background:"rgba(0,0,0,0.5)", display:"flex", alignItems:"center", justifyContent:"center", zIndex:1000, padding:"20px 20px 88px" }}>
      <div style={{ background:"#fff", borderRadius:16, width:"100%", maxWidth:360, overflow:"hidden" }}>
        <div style={{ background:BLUE, padding:"16px 20px" }}>
          <div style={{ color:"rgba(255,255,255,0.8)", fontSize:13 }}>{year}</div>
          <div style={{ color:"#fff", fontSize:26, fontWeight:700 }}>
            {["Sun","Mon","Tue","Wed","Thu","Fri","Sat"][selected?.getDay()]}, {months[selected?.getMonth()].slice(0,3)} {selected?.getDate()}
          </div>
        </div>
        <div style={{ padding:16 }}>
          <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:12 }}>
            <button onClick={()=>setView(new Date(year,month-1,1))} style={{ background:"none", border:"none", fontSize:20, cursor:"pointer", color:BLUE }}>‹</button>
            <span style={{ fontWeight:600, fontSize:15, fontFamily:"'Segoe UI',sans-serif" }}>{months[month]} {year}</span>
            <button onClick={()=>setView(new Date(year,month+1,1))} style={{ background:"none", border:"none", fontSize:20, cursor:"pointer", color:BLUE }}>›</button>
          </div>
          <div style={{ display:"grid", gridTemplateColumns:"repeat(7,1fr)", gap:4, textAlign:"center" }}>
            {["S","M","T","W","T","F","S"].map((d,i)=><div key={i} style={{ fontSize:12, color:"#999", fontWeight:600, padding:"4px 0" }}>{d}</div>)}
            {cells.map((d,i) => {
              const isSelected = d && selected && selected.getDate()===d && selected.getMonth()===month && selected.getFullYear()===year;
              return (
                <div key={i} onClick={d?()=>onChange(new Date(year,month,d)):undefined}
                  style={{ padding:"6px 0", borderRadius:"50%", fontSize:14, cursor:d?"pointer":"default",
                    background:isSelected?BLUE:"transparent", color:isSelected?"#fff":d?"#333":"transparent", fontWeight:isSelected?700:400 }}>
                  {d||""}
                </div>
              );
            })}
          </div>
        </div>
        <div style={{ display:"flex", justifyContent:"flex-end", gap:16, padding:"8px 20px 16px" }}>
          <button onClick={onClose} style={{ background:"none", border:"none", color:"#888", fontWeight:600, cursor:"pointer", fontSize:14 }}>CANCEL</button>
          <button onClick={onClose} style={{ background:"none", border:"none", color:BLUE, fontWeight:600, cursor:"pointer", fontSize:14 }}>OK</button>
        </div>
      </div>
    </div>
  );
}

// ── SCREENS ───────────────────────────────────────────────────────────────────

// 2. Home
// ─── Monthly Report Screen ────────────────────────────────────────────────────
// Parses a bank statement CSV, matches transactions to app invoices, builds xlsx report

const EXPENSE_CATEGORIES = [
  "Accommodation", "Accountant", "Bills", "Charity", "Dividends", "Entertainment",
  "Equipment", "General", "Insurance", "Materials", "Meals", "Pension", "Rent",
  "Services", "Software", "Tax", "Travel", "Vehicle Expenses", "Wages", "Other"
];

// ─── Account Reports Screen ───────────────────────────────────────────────────
function ReportPreviewScreen({ report, onBack, onHome }) {
  const [sheetRows, setSheetRows] = useState(null);
  const [loading, setLoading] = useState(true);

  async function loadXLSX() {
    if (!window.XLSX) {
      await new Promise((res,rej) => {
        const s = document.createElement("script");
        s.src = "https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js";
        s.onload = res; s.onerror = rej;
        document.head.appendChild(s);
      });
    }
    const wb = window.XLSX.read(report.xlsxBase64, { type:"base64" });
    const ws = wb.Sheets[wb.SheetNames[0]];
    const rows = window.XLSX.utils.sheet_to_json(ws, { header:1, defval:"" });
    setSheetRows(rows); setLoading(false);
  }

  useEffect(() => { loadXLSX(); }, []);

  function doDownload() {
    if (!window.XLSX) { loadXLSX().then(doDownload); return; }
    const wb = window.XLSX.read(report.xlsxBase64, { type:"base64" });
    window.XLSX.writeFile(wb, report.fileName);
  }

  let incomeRows = [], expenseGroups = {}, currentCat = null, inIncome = false, inExpenses = false;
  let summaryIncome = report.totalIncome||"", summaryExpenses = report.totalExpenses||"", summaryNet = report.net||"";
  if (sheetRows) {
    for (let i = 0; i < sheetRows.length; i++) {
      const r = sheetRows[i];
      const a = String(r[0]||"").trim(), b = String(r[1]||"").trim();
      if (a === "Total income") { summaryIncome = b; continue; }
      if (a === "Total expenses") { summaryExpenses = b; continue; }
      if (a === "Net" && b) { summaryNet = b; continue; }
      if (a === "Income") { inIncome = true; inExpenses = false; continue; }
      if (a === "Expenses (grouped by category)") { inIncome = false; inExpenses = true; continue; }
      if (a === "Bank Transaction" || a === "") continue;
      if (inIncome) { incomeRows.push({ date:a, description:b, payment:String(r[2]||""), invoiceNo:String(r[5]||"") }); }
      if (inExpenses) {
        const hasAmt = r[3] && String(r[3]).trim() !== "";
        if (!hasAmt && a) { currentCat = a; if (!expenseGroups[currentCat]) expenseGroups[currentCat]=[]; }
        else if (hasAmt && currentCat) { expenseGroups[currentCat].push({ date:a, description:b, amount:String(r[3]||"") }); }
      }
    }
  }

  return (
    <div style={{ display:"flex", flexDirection:"column", height:"100dvh", background:LIGHT_BG, fontFamily:"'Segoe UI',sans-serif" }}>
      <Header title="📊 Report Preview" onBack={onBack} onHome={onHome}/>
      <div style={{ flex:1, overflowY:"auto", padding:16, paddingBottom:80 }}>
        {loading ? (
          <div style={{ textAlign:"center", marginTop:60, color:"#888", fontSize:14 }}>Loading preview…</div>
        ) : (<>
          <div style={{ background:"#fff", borderRadius:12, padding:16, marginBottom:12, boxShadow:"0 2px 8px rgba(0,0,0,0.06)", borderLeft:`4px solid ${BLUE}` }}>
            <div style={{ fontWeight:700, fontSize:15, color:"#222", marginBottom:4 }}>{report.fileName}</div>
            <div style={{ fontSize:12, color:"#888", marginBottom:10 }}>{report.period}</div>
            {[["Total Income","£"+summaryIncome,INV_GREEN],["Total Expenses","£"+summaryExpenses,"#c00"],["Net","£"+summaryNet,parseFloat(summaryNet)>=0?INV_GREEN:"#c00"]].map(([l,v,c])=>(
              <div key={l} style={{ display:"flex", justifyContent:"space-between", fontSize:13, padding:"3px 0", borderBottom:"1px solid #f5f5f5" }}>
                <span style={{ color:"#888" }}>{l}</span><span style={{ fontWeight:700, color:c }}>{v}</span>
              </div>
            ))}
          </div>
          {incomeRows.length > 0 && (
            <div style={{ background:"#fff", borderRadius:12, padding:16, marginBottom:12, boxShadow:"0 2px 8px rgba(0,0,0,0.06)" }}>
              <div style={{ fontWeight:700, fontSize:13, color:INV_GREEN, marginBottom:8 }}>💰 Income ({incomeRows.length})</div>
              {incomeRows.map((r,i)=>(
                <div key={i} style={{ display:"flex", justifyContent:"space-between", alignItems:"center", padding:"5px 0", borderBottom:"1px solid #f5f5f5", fontSize:12 }}>
                  <div style={{ flex:1, minWidth:0 }}>
                    <div style={{ fontWeight:600, color:"#222", overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>{r.description}</div>
                    <div style={{ color:"#aaa", fontSize:11 }}>{r.date}{r.invoiceNo?<span style={{ color:BLUE, marginLeft:8 }}>{r.invoiceNo}</span>:null}</div>
                  </div>
                  <div style={{ fontWeight:700, color:INV_GREEN, marginLeft:8, flexShrink:0 }}>£{r.payment}</div>
                </div>
              ))}
            </div>
          )}
          {Object.entries(expenseGroups).filter(([,rows])=>rows.length>0).map(([cat,rows])=>(
            <div key={cat} style={{ background:"#fff", borderRadius:12, padding:16, marginBottom:12, boxShadow:"0 2px 8px rgba(0,0,0,0.06)" }}>
              <div style={{ fontWeight:700, fontSize:13, color:"#c00", marginBottom:8 }}>📤 {cat}</div>
              {rows.map((r,i)=>(
                <div key={i} style={{ display:"flex", justifyContent:"space-between", alignItems:"center", padding:"5px 0", borderBottom:"1px solid #f5f5f5", fontSize:12 }}>
                  <div style={{ flex:1, minWidth:0 }}>
                    <div style={{ fontWeight:600, color:"#222", overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>{r.description}</div>
                    <div style={{ color:"#aaa", fontSize:11 }}>{r.date}</div>
                  </div>
                  <div style={{ fontWeight:700, color:"#c00", marginLeft:8, flexShrink:0 }}>£{r.amount}</div>
                </div>
              ))}
            </div>
          ))}
          <button onClick={doDownload} style={{ width:"100%", padding:"13px 0", background:BLUE, color:"#fff", border:"none", borderRadius:10, fontWeight:700, fontSize:14, cursor:"pointer", marginBottom:16 }}>
            ⬇ Download .xlsx
          </button>
        </>)}
      </div>
      <BottomBar onHome={onHome}/>
    </div>
  );
}

// ─── Yearly Report Builder ────────────────────────────────────────────────────
function buildYearlyReport(year, monthlyReports) {
  const yearReports = monthlyReports.filter(r => {
    if (!r.createdAt) return false;
    return new Date(r.createdAt).getFullYear() === year;
  });
  if (!yearReports.length) return null;
  yearReports.sort((a,b) => new Date(a.createdAt) - new Date(b.createdAt));

  const XL = window.XLSX;

  // Extract full rows from a stored monthly xlsx (for old reports lacking structured data)
  function extractFromXlsx(report) {
    let incomeRows = [], expenseRows = [];
    if (!report.xlsxBase64) return { incomeRows, expenseRows };
    try {
      const srcWb = XL.read(report.xlsxBase64, { type:"base64" });
      const ws = srcWb.Sheets[srcWb.SheetNames[0]];
      const rows = XL.utils.sheet_to_json(ws, { header:1, defval:"" });
      let inIncome = false, inExpenses = false, currentCat = null;
      for (const r of rows) {
        const a = String(r[0]||"").trim();
        const b = String(r[1]||"").trim();
        const c = r[2]; const d = r[3]; const e = r[4]; const f = r[5];
        if (a === "Income") { inIncome = true; inExpenses = false; continue; }
        if (a === "Expenses (grouped by category)") { inIncome = false; inExpenses = true; continue; }
        if (a === "Bank Transaction" || a === "") continue;
        if (inIncome) {
          const pmt = parseFloat(String(c||"").replace(/[£,]/g,""));
          if (!isNaN(pmt) && pmt > 0) {
            incomeRows.push({ date:a, description:b, payment:pmt, deduction:"", balance:String(e||""), invoiceNo:String(f||"") });
          }
        }
        if (inExpenses) {
          const ded = parseFloat(String(d||"").replace(/[£,]/g,""));
          if (!isNaN(ded) && ded > 0 && currentCat) {
            expenseRows.push({ date:a, description:b, payment:"", deduction:ded, balance:String(e||""), category:currentCat });
          } else if ((isNaN(ded) || String(d||"").trim()==="") && a && a !== "Bank Transaction") {
            currentCat = a;
          }
        }
      }
    } catch(err) {}
    return { incomeRows, expenseRows };
  }

  // Resolve display rows for each report
  const resolvedReports = yearReports.map(r => {
    const hasIncome = r.incomeRows && r.incomeRows.length > 0;
    const hasExpenses = r.expenseRows && r.expenseRows.length > 0;
    if (hasIncome || hasExpenses) {
      return {
        ...r,
        _incomeRows: (r.incomeRows||[]).map(row => ({
          date: row.date, description: row.description,
          payment: parseFloat(row.amount)||0, deduction: "", balance: "",
          invoiceNo: row.invoiceNo||""
        })),
        _expenseRows: (r.expenseRows||[]).map(row => ({
          date: row.date, description: row.description,
          payment: "", deduction: parseFloat(row.amount)||0, balance: "",
          category: row.category||"General"
        })),
      };
    }
    const ex = extractFromXlsx(r);
    return { ...r, _incomeRows: ex.incomeRows, _expenseRows: ex.expenseRows };
  });

  // ── Helper functions ──
  function parseRowDate(s) {
    if (!s) return null;
    s = String(s).trim();
    if (/^\d{4}-\d{2}-\d{2}/.test(s)) return new Date(s.slice(0,10));
    const dm = s.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})/);
    if (dm) return new Date(`${dm[3]}-${dm[2].padStart(2,'0')}-${dm[1].padStart(2,'0')}`);
    const d = new Date(s);
    return isNaN(d) ? null : d;
  }

  function fmtDateShort(d) {
    if (!d) return "";
    return d.toLocaleDateString("en-GB", { day:"2-digit", month:"short", year:"numeric" });
  }

  function detectActualPeriod(r) {
    const allRows = [...(r._incomeRows||[]), ...(r._expenseRows||[])];
    const dates = allRows.map(row => parseRowDate(row.date)).filter(Boolean);
    if (!dates.length) return null;
    const start = new Date(Math.min(...dates));
    const end   = new Date(Math.max(...dates));
    return { start, end, span: end - start };
  }

  // For each resolved report, detect actual period from rows
  const reportsWithPeriod = resolvedReports.map(r => {
    const actual = detectActualPeriod(r);
    return {
      ...r,
      _parsedPeriod: actual,
      _actualPeriodLabel: actual
        ? `${fmtDateShort(actual.start)} to ${fmtDateShort(actual.end)}`
        : (r.period || "")
    };
  });

  // Sort by span ascending — shortest (most specific) periods first for dedup ownership
  reportsWithPeriod.sort((a, b) => {
    const sa = a._parsedPeriod ? a._parsedPeriod.span : Infinity;
    const sb = b._parsedPeriod ? b._parsedPeriod.span : Infinity;
    return sa - sb;
  });

  // Sort chronologically for display
  const reportsChronological = [...reportsWithPeriod].sort((a,b) => {
    const sa = a._parsedPeriod ? a._parsedPeriod.start : new Date(0);
    const sb = b._parsedPeriod ? b._parsedPeriod.start : new Date(0);
    return sa - sb;
  });

  const firstActual = reportsChronological[0]?._parsedPeriod?.start;
  const lastActual  = reportsChronological[reportsChronological.length-1]?._parsedPeriod?.end;
  const fullPeriod  = firstActual && lastActual
    ? `${fmtDateShort(firstActual)} to ${fmtDateShort(lastActual)}`
    : (yearReports[0]?.period || year.toString());

  // Collect unique rows — a transaction is claimed by the shortest-span report whose period contains its date
  const allIncomeRows = [];
  const allExpenseRows = [];
  const _incomeSeen = new Map();  // key -> count seen
  const _expenseSeen = new Map(); // key -> count seen

  for (const r of reportsWithPeriod) {
    const rp = r._parsedPeriod;

    // Count occurrences of each key within this report first
    const reportIncomeCount = new Map();
    for (const row of r._incomeRows) {
      const rowDate = parseRowDate(row.date);
      if (rp && rowDate && (rowDate < rp.start || rowDate > rp.end)) continue;
      const amt = typeof row.payment === "number" ? row.payment.toFixed(2) : (parseFloat(row.payment)||0).toFixed(2);
      const key = `${row.date}|${amt}`;
      reportIncomeCount.set(key, (reportIncomeCount.get(key)||0) + 1);
    }
    const reportExpenseCount = new Map();
    for (const row of r._expenseRows) {
      const rowDate = parseRowDate(row.date);
      if (rp && rowDate && (rowDate < rp.start || rowDate > rp.end)) continue;
      const amt = typeof row.deduction === "number" ? row.deduction.toFixed(2) : (parseFloat(row.deduction)||0).toFixed(2);
      const key = `${row.date}|${amt}|${row.category||"General"}`;
      reportExpenseCount.set(key, (reportExpenseCount.get(key)||0) + 1);
    }

    // Add rows, allowing up to max(previously seen, this report's count) occurrences
    const localIncomeCount = new Map();
    for (const row of r._incomeRows) {
      const rowDate = parseRowDate(row.date);
      if (rp && rowDate && (rowDate < rp.start || rowDate > rp.end)) continue;
      const amt = typeof row.payment === "number" ? row.payment.toFixed(2) : (parseFloat(row.payment)||0).toFixed(2);
      const key = `${row.date}|${amt}`;
      const localCount = (localIncomeCount.get(key)||0) + 1;
      localIncomeCount.set(key, localCount);
      const globalSeen = _incomeSeen.get(key)||0;
      const reportMax = reportIncomeCount.get(key)||1;
      if (localCount > Math.max(globalSeen, reportMax)) continue;
      if (globalSeen >= localCount) continue;
      _incomeSeen.set(key, localCount);
      allIncomeRows.push(row);
    }

    const localExpenseCount = new Map();
    for (const row of r._expenseRows) {
      const rowDate = parseRowDate(row.date);
      if (rp && rowDate && (rowDate < rp.start || rowDate > rp.end)) continue;
      const amt = typeof row.deduction === "number" ? row.deduction.toFixed(2) : (parseFloat(row.deduction)||0).toFixed(2);
      const key = `${row.date}|${amt}|${row.category||"General"}`;
      const localCount = (localExpenseCount.get(key)||0) + 1;
      localExpenseCount.set(key, localCount);
      const globalSeen = _expenseSeen.get(key)||0;
      if (globalSeen >= localCount) continue;
      _expenseSeen.set(key, localCount);
      allExpenseRows.push({ ...row, _period: r._actualPeriodLabel });
    }
  }

  // Sort all rows chronologically
  allIncomeRows.sort((a,b) => { const da=parseRowDate(a.date), db=parseRowDate(b.date); return (da&&db) ? da-db : 0; });
  allExpenseRows.sort((a,b) => { const da=parseRowDate(a.date), db=parseRowDate(b.date); return (da&&db) ? da-db : 0; });

  const grandIncome   = allIncomeRows.reduce((s,r) => s + (typeof r.payment === "number" ? r.payment : parseFloat(r.payment)||0), 0);
  const grandExpenses = allExpenseRows.reduce((s,r) => s + (typeof r.deduction === "number" ? r.deduction : parseFloat(r.deduction)||0), 0);
  const grandNet      = grandIncome - grandExpenses;

  // Build one sheet in the exact same 6-column format as a monthly report
  const wsData = [];

  // Row 1 — column headers (same as monthly)
  wsData.push(["Bank Transaction","Description","Payment","Deduction","Balance","Invoice Number"]);
  wsData.push(["Bank Statement"]);
  try { const _p = JSON.parse(localStorage.getItem(sk("user_profile"))||"{}");
  wsData.push(["Business: " + (_p.companyName||""), "Type: " + (_p.companyType||"")]);
  wsData.push(["Prepared by: " + (_p.engineerName||""), (_p.companyEmail||"")]);
  wsData.push(["Gas Safe No: " + (_p.gasSafeNo||""), "Engineer ID: " + (_p.gasId||"")]);
  wsData.push([(_p.companyAddr||""), (_p.companyPostcode||"")]);
  } catch {}
  wsData.push(["Source: Bank statement CSV export", "Period: " + fullPeriod]);
  wsData.push([]);

  // Summary
  wsData.push(["Summary Total"]);
  wsData.push(["Total income", grandIncome.toFixed(2)]);
  wsData.push(["Total expenses", grandExpenses.toFixed(2)]);
  wsData.push(["Net", grandNet.toFixed(2)]);
  wsData.push([]);

  // Monthly breakdown — actual totals from claimed rows, chronological order
  wsData.push(["Monthly Breakdown"]);
  wsData.push(["Bank Transaction","Description","Payment","Deduction","Balance","Invoice Number"]);
  for (const r of reportsChronological) {
    const rp = r._parsedPeriod;
    const label = r._actualPeriodLabel || r.period || "";
    const mIncome = allIncomeRows.filter(row => {
      const rowDate = parseRowDate(row.date);
      return rp && rowDate && rowDate >= rp.start && rowDate <= rp.end;
    }).reduce((s, row) => s + (typeof row.payment === "number" ? row.payment : parseFloat(row.payment)||0), 0);
    const mExpenses = allExpenseRows.filter(row => {
      const rowDate = parseRowDate(row.date);
      return rp && rowDate && rowDate >= rp.start && rowDate <= rp.end;
    }).reduce((s, row) => s + (typeof row.deduction === "number" ? row.deduction : parseFloat(row.deduction)||0), 0);
    wsData.push([label, "", mIncome.toFixed(2), mExpenses.toFixed(2), (mIncome-mExpenses).toFixed(2), ""]);
  }
  wsData.push([]);

  // Income — already deduplicated
  wsData.push(["Income"]);
  wsData.push(["Bank Transaction","Description","Payment","Deduction","Balance","Invoice Number"]);
  for (const row of allIncomeRows) {
    wsData.push([
      row.date, row.description,
      typeof row.payment === "number" ? row.payment.toFixed(2) : (row.payment||""),
      row.deduction||"",
      row.balance||"",
      row.invoiceNo||""
    ]);
  }
  wsData.push([]);

  // Expenses grouped by category — already deduplicated
  wsData.push(["Expenses (grouped by category)"]);
  const catGroups = {};
  for (const row of allExpenseRows) {
    const cat = row.category || "General";
    if (!catGroups[cat]) catGroups[cat] = [];
    catGroups[cat].push(row);
  }
  for (const [cat, rows] of Object.entries(catGroups).sort((a,b) => a[0].localeCompare(b[0]))) {
    wsData.push([cat]);
    wsData.push(["Bank Transaction","Description","Payment","Deduction","Balance","Invoice Number"]);
    for (const row of rows) {
      wsData.push([
        row.date, row.description,
        row.payment||"",
        typeof row.deduction === "number" ? row.deduction.toFixed(2) : (row.deduction||""),
        row.balance||"",
        ""
      ]);
    }
  }

  const ws = XL.utils.aoa_to_sheet(wsData);
  ws["!cols"] = [{ wch:38 },{ wch:45 },{ wch:12 },{ wch:12 },{ wch:12 },{ wch:16 }];

  const wb = XL.utils.book_new();
  XL.utils.book_append_sheet(wb, ws, ("Yearly Account " + year).slice(0,31));

  // ── Tax Summary Sheet (SA103 Self-Employment) ──
  const taxData = [];
  const b = (s) => s; // cell value helper

  // Category totals — from deduplicated rows
  const catTotals = {};
  for (const row of allExpenseRows) {
    const amt = typeof row.deduction === "number" ? row.deduction : (parseFloat(row.deduction)||parseFloat(row.amount)||0);
    const cat = row.category || "General";
    catTotals[cat] = (catTotals[cat]||0) + amt;
  }
  const catTotal = (cat) => catTotals[cat] || 0;
  const catsTotal = (...cats) => cats.reduce((s,c) => s + catTotal(c), 0);

  // Allowable expenses mapped to HMRC SA103 boxes
  const staffCosts       = catsTotal("Wages");
  const premises         = catsTotal("Rent", "Bills");
  const repairs          = 0;
  const travel           = catsTotal("Travel", "Vehicle Expenses", "Accommodation");
  const advertising      = catsTotal("Entertainment", "Services");
  const financeCosts     = 0;
  const office           = catsTotal("Software", "Equipment", "General");
  const accountingLegal  = catsTotal("Accountant");
  const depreciation     = 0;
  const otherBusiness    = catsTotal("Materials", "Meals", "Other", "Insurance");
  const totalAllowable   = staffCosts + premises + repairs + travel + advertising + financeCosts + office + accountingLegal + depreciation + otherBusiness;

  // Non-allowable / personal
  const pension          = catTotal("Pension");
  const charity          = catTotal("Charity");
  const dividends        = catTotal("Dividends");
  const taxPaid          = catTotal("Tax");
  const totalNonBusiness = pension + charity + dividends + taxPaid;

  const netProfit        = grandIncome - totalAllowable;

  taxData.push(["YEAR END TAX SUMMARY", "", year.toString()]);
  try { const _tp = JSON.parse(localStorage.getItem(sk("user_profile"))||"{}");
  taxData.push([_tp.companyName||"", _tp.companyEmail||""]);
  taxData.push([_tp.engineerName||"", "Gas Safe No: " + (_tp.gasSafeNo||"")]);
  taxData.push([_tp.companyAddr||"", _tp.companyPostcode||""]);
  } catch {}
  taxData.push(["Tax Year:", `6 Apr ${year} to 5 Apr ${year+1}`]);
  taxData.push(["Prepared by:", getCompanyProfile().companyName || ""]);
  taxData.push(["Period covered by records:", fullPeriod]);
  taxData.push([]);
  taxData.push(["─────────────────────────────────────────"]);
  taxData.push(["INCOME", "", "£"]);
  taxData.push(["Total turnover / gross income", "", grandIncome.toFixed(2)]);
  taxData.push([]);
  taxData.push(["─────────────────────────────────────────"]);
  taxData.push(["ALLOWABLE BUSINESS EXPENSES (SA103)", "", "£"]);
  taxData.push(["  Staff costs (wages, salaries)", "Box 17", staffCosts.toFixed(2)]);
  taxData.push(["  Premises costs (rent, bills, rates)", "Box 20", premises.toFixed(2)]);
  taxData.push(["  Repairs and renewals", "Box 21", repairs.toFixed(2)]);
  taxData.push(["  Travel and vehicle costs", "Box 24", travel.toFixed(2)]);
  taxData.push(["  Advertising and entertainment", "Box 25", advertising.toFixed(2)]);
  taxData.push(["  Finance charges", "Box 26", financeCosts.toFixed(2)]);
  taxData.push(["  Office and admin costs (software, equipment)", "Box 27", office.toFixed(2)]);
  taxData.push(["  Legal and professional fees (accountant)", "Box 22", accountingLegal.toFixed(2)]);
  taxData.push(["  Depreciation / loss on sale of assets", "Box 23", depreciation.toFixed(2)]);
  taxData.push(["  Other business expenses (materials, insurance, meals)", "Box 28", otherBusiness.toFixed(2)]);
  taxData.push(["TOTAL ALLOWABLE EXPENSES", "", totalAllowable.toFixed(2)]);
  taxData.push([]);
  taxData.push(["─────────────────────────────────────────"]);
  taxData.push(["NET PROFIT (Turnover minus Allowable Expenses)", "", netProfit.toFixed(2)]);
  taxData.push([]);
  taxData.push(["─────────────────────────────────────────"]);
  taxData.push(["NON-BUSINESS ITEMS (for information only)", "", "£"]);
  taxData.push(["  Pension contributions", "", pension.toFixed(2)]);
  taxData.push(["  Charitable donations", "", charity.toFixed(2)]);
  taxData.push(["  Dividends paid", "", dividends.toFixed(2)]);
  taxData.push(["  Tax / HMRC payments", "", taxPaid.toFixed(2)]);
  taxData.push(["TOTAL NON-BUSINESS", "", totalNonBusiness.toFixed(2)]);
  taxData.push([]);
  taxData.push(["─────────────────────────────────────────"]);
  taxData.push(["EXPENSE CATEGORY BREAKDOWN", "", "£"]);
  for (const [cat, total] of Object.entries(catTotals).sort((a,b)=>a[0].localeCompare(b[0]))) {
    taxData.push(["  " + cat, "", total.toFixed(2)]);
  }
  taxData.push(["  TOTAL", "", Object.values(catTotals).reduce((s,v)=>s+v,0).toFixed(2)]);
  taxData.push([]);
  taxData.push(["─────────────────────────────────────────"]);
  taxData.push(["NOTE: These figures are based on bank transactions imported from a bank statement CSV."]);
  taxData.push(["Please review with your accountant before submitting to HMRC."]);
  taxData.push(["Category to SA103 box mapping is indicative — verify with your accountant."]);

  const wsTax = XL.utils.aoa_to_sheet(taxData);
  wsTax["!cols"] = [{ wch:52 }, { wch:10 }, { wch:14 }];
  XL.utils.book_append_sheet(wb, wsTax, "Tax Summary");

  const fileName    = "Yearly_Account_" + year + ".xlsx";
  const xlsxBase64  = XL.write(wb, { bookType:"xlsx", type:"base64" });

  return {
    id: "yearly_" + year, year, fileName, isYearly: true,
    period: fullPeriod,
    totalIncome: grandIncome.toFixed(2),
    totalExpenses: grandExpenses.toFixed(2),
    net: grandNet.toFixed(2),
    monthCount: resolvedReports.length,
    updatedAt: new Date().toISOString(),
    xlsxBase64,
  };
}
function ReportEditCategoriesScreen({ report, onBack, onHome, onSave }) {
  const [expenseRows, setExpenseRows] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    async function load() {
      // If report has structured expenseRows use them, otherwise extract from xlsx
      if (report.expenseRows && report.expenseRows.length > 0) {
        setExpenseRows(report.expenseRows.map((r,i) => ({ ...r, _idx: i })));
        setLoading(false);
        return;
      }
      // Extract from xlsx
      if (!window.XLSX) {
        await new Promise((res,rej) => {
          const s = document.createElement("script");
          s.src = "https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js";
          s.onload = res; s.onerror = rej;
          document.head.appendChild(s);
        });
      }
      const XL = window.XLSX;
      const srcWb = XL.read(report.xlsxBase64, { type:"base64" });
      const ws = srcWb.Sheets[srcWb.SheetNames[0]];
      const rows = XL.utils.sheet_to_json(ws, { header:1, defval:"" });
      let inExpenses = false, currentCat = null, extracted = [];
      for (const r of rows) {
        const a = String(r[0]||"").trim();
        const b = String(r[1]||"").trim();
        const d = r[3];
        if (a === "Expenses (grouped by category)") { inExpenses = true; continue; }
        if (!inExpenses) continue;
        if (a === "Bank Transaction" || a === "") continue;
        const ded = parseFloat(String(d||"").replace(/[£,]/g,""));
        if (!isNaN(ded) && ded > 0 && currentCat) {
          extracted.push({ date:a, description:b, amount:ded, category:currentCat, _idx:extracted.length });
        } else if ((isNaN(ded) || String(d||"").trim()==="") && a && a !== "Bank Transaction") {
          currentCat = a;
        }
      }
      setExpenseRows(extracted);
      setLoading(false);
    }
    load();
  }, []);

  function saveChanges() {
    // Rebuild the updated report with new category assignments
    const updated = {
      ...report,
      expenseRows: expenseRows.map(r => ({
        date: r.date, description: r.description,
        amount: r.amount, category: r.category
      }))
    };
    onSave(updated);
    alert("✅ Categories saved! The yearly report will be updated automatically.");
  }

  return (
    <div style={{ display:"flex", flexDirection:"column", height:"100dvh", background:LIGHT_BG, fontFamily:"'Segoe UI',sans-serif" }}>
      <Header title="✏️ Edit Categories" onBack={onBack} onHome={onHome}/>
      <div style={{ flex:1, overflowY:"auto", padding:16, paddingBottom:80 }}>
        {loading ? (
          <div style={{ textAlign:"center", marginTop:60, color:"#888", fontSize:14 }}>Loading expenses…</div>
        ) : (
          <>
            <div style={{ background:"#fff", borderRadius:12, padding:14, marginBottom:14, boxShadow:"0 2px 8px rgba(0,0,0,0.06)" }}>
              <div style={{ fontWeight:700, fontSize:14, color:"#222", marginBottom:4 }}>{report.fileName}</div>
              <div style={{ fontSize:12, color:"#888" }}>{report.period} · {expenseRows.length} expenses</div>
            </div>

            <div style={{ background:"#fff", borderRadius:12, padding:16, marginBottom:14, boxShadow:"0 2px 8px rgba(0,0,0,0.06)" }}>
              <div style={{ fontWeight:700, fontSize:13, color:"#c00", marginBottom:10 }}>📤 Expenses</div>
              {expenseRows.map((row, i) => (
                <div key={i} style={{ display:"flex", justifyContent:"space-between", alignItems:"center", padding:"7px 0", borderBottom:"1px solid #f5f5f5", fontSize:13 }}>
                  <div style={{ flex:1, minWidth:0 }}>
                    <div style={{ fontWeight:600, color:"#222", overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>{row.description}</div>
                    <div style={{ fontSize:11, color:"#aaa" }}>{row.date}</div>
                  </div>
                  <div style={{ textAlign:"right", marginLeft:8, flexShrink:0 }}>
                    <div style={{ fontWeight:700, color:"#c00", marginBottom:3 }}>£{parseFloat(row.amount||0).toFixed(2)}</div>
                    <select
                      value={row.category}
                      onChange={e => setExpenseRows(rows => rows.map((r,idx) => idx===i ? {...r, category:e.target.value} : r))}
                      style={{ fontSize:11, border:"1px solid #ddd", borderRadius:6, padding:"3px 6px", background:"#fff" }}>
                      {EXPENSE_CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
                    </select>
                  </div>
                </div>
              ))}
            </div>

            <button onClick={saveChanges}
              style={{ width:"100%", padding:"14px 0", background:INV_GREEN, color:"#fff", border:"none", borderRadius:10, fontWeight:700, fontSize:15, cursor:"pointer", marginBottom:16 }}>
              💾 Save Changes
            </button>
          </>
        )}
      </div>
      <BottomBar onHome={onHome}/>
    </div>
  );
}

function AccountReportsScreen({ reports, onBack, onHome, onDelete, yearlyReports, onDeleteYearly, onRebuildYearly, onUpdateReport }) {
  const [selected, setSelected] = useState(null);
  const [confirmDelete, setConfirmDelete] = useState(null);
  const [previewing, setPreviewing] = useState(null);
  const [editing, setEditing] = useState(null); // index of monthly report being edited

  async function ensureXLSX() {
    if (!window.XLSX) {
      await new Promise((res,rej) => {
        const s = document.createElement("script");
        s.src = "https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js";
        s.onload = res; s.onerror = rej;
        document.head.appendChild(s);
      });
    }
  }

  async function downloadReport(report) {
    await ensureXLSX();
    const wb = window.XLSX.read(report.xlsxBase64, { type:"base64" });
    window.XLSX.writeFile(wb, report.fileName);
  }

  if (previewing !== null) return <ReportPreviewScreen report={previewing} onBack={()=>setPreviewing(null)} onHome={onHome}/>;

  if (editing !== null) {
    const report = reports[editing];
    return <ReportEditCategoriesScreen
      report={report}
      onBack={()=>setEditing(null)}
      onHome={onHome}
      onSave={(updatedReport)=>{
        if (onUpdateReport) onUpdateReport(editing, updatedReport);
        setEditing(null);
      }}
    />;
  }

  const selectedReport = selected ? (selected.type === "yearly" ? (yearlyReports||[])[selected.index] : reports[selected.index]) : null;

  return (
    <div style={{ display:"flex", flexDirection:"column", height:"100dvh", background:LIGHT_BG, fontFamily:"'Segoe UI',sans-serif" }}>
      <Header title="📊 Account Reports" onBack={onBack} onHome={onHome}/>
      <div style={{ flex:1, overflowY:"auto", padding:16, paddingBottom:80 }}>

        {/* Regenerate button */}
        {(yearlyReports||[]).length > 0 && onRebuildYearly && (
          <button onClick={()=>{ const years=[...new Set((yearlyReports||[]).map(y=>y.year))]; years.forEach(y=>onRebuildYearly(y)); }}
            style={{ width:"100%", padding:"11px 0", background:"#f5f5f5", color:BLUE, border:`2px solid ${BLUE}`, borderRadius:10, fontWeight:700, fontSize:13, cursor:"pointer", marginBottom:14 }}>
            🔄 Regenerate Yearly Reports from Monthly Data
          </button>
        )}

        {/* ── Yearly Reports ── */}
        {(yearlyReports||[]).length > 0 && (
          <>
            <div style={{ fontWeight:700, fontSize:13, color:"#7c3aed", marginBottom:8, marginTop:4 }}>📅 Yearly Reports</div>
            {(yearlyReports||[]).map((report,i) => (
              <div key={report.id||i} onClick={()=>setSelected({ type:"yearly", index:i })}
                style={{ background:"#fff", borderRadius:12, padding:"14px 16px", marginBottom:10, boxShadow:"0 2px 8px rgba(0,0,0,0.06)", borderLeft:`4px solid #7c3aed`, cursor:"pointer" }}>
                <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start" }}>
                  <div style={{ flex:1, minWidth:0 }}>
                    <div style={{ fontWeight:700, fontSize:15, color:"#222" }}>{report.fileName}</div>
                    <div style={{ fontSize:12, color:"#888", marginTop:2 }}>{report.monthCount} month{report.monthCount!==1?"s":""} · Last updated {report.updatedAt?new Date(report.updatedAt).toLocaleDateString("en-GB"):""}</div>
                  </div>
                  <div style={{ textAlign:"right", flexShrink:0, marginLeft:8 }}>
                    <div style={{ fontSize:12, color:INV_GREEN, fontWeight:700 }}>↑ £{report.totalIncome}</div>
                    <div style={{ fontSize:12, color:"#c00", fontWeight:700 }}>↓ £{report.totalExpenses}</div>
                    <div style={{ fontSize:12, color:parseFloat(report.net)>=0?INV_GREEN:"#c00", fontWeight:700 }}>= £{report.net}</div>
                  </div>
                </div>
              </div>
            ))}
            <div style={{ fontWeight:700, fontSize:13, color:"#555", marginBottom:8, marginTop:12 }}>📋 Monthly Reports</div>
          </>
        )}

        {/* ── Monthly Reports ── */}
        {(!reports||reports.length===0) && (!yearlyReports||yearlyReports.length===0) ? (
          <div style={{ textAlign:"center", marginTop:60 }}>
            <div style={{ fontSize:48, marginBottom:12 }}>📊</div>
            <div style={{ fontWeight:700, fontSize:17, color:"#222", marginBottom:8 }}>No reports yet</div>
            <div style={{ fontSize:13, color:"#888" }}>Generate a monthly report from the Reports button on the home screen — it will be saved here automatically.</div>
          </div>
        ) : reports.map((report,i)=>(
          <div key={report.id||i} onClick={()=>setSelected({ type:"monthly", index:i })}
            style={{ background:"#fff", borderRadius:12, padding:"14px 16px", marginBottom:10, boxShadow:"0 2px 8px rgba(0,0,0,0.06)", borderLeft:`4px solid ${BLUE}`, cursor:"pointer" }}>
            <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start" }}>
              <div style={{ flex:1, minWidth:0 }}>
                <div style={{ fontWeight:700, fontSize:14, color:"#222", overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>{report.fileName}</div>
                <div style={{ fontSize:12, color:"#888", marginTop:2 }}>{report.period}</div>
                <div style={{ fontSize:12, color:"#aaa", marginTop:2 }}>{report.createdAt?new Date(report.createdAt).toLocaleDateString("en-GB"):""}</div>
              </div>
              <div style={{ textAlign:"right", flexShrink:0, marginLeft:8 }}>
                <div style={{ fontSize:12, color:INV_GREEN, fontWeight:700 }}>↑ £{report.totalIncome}</div>
                <div style={{ fontSize:12, color:"#c00", fontWeight:700 }}>↓ £{report.totalExpenses}</div>
                <div style={{ fontSize:12, color:parseFloat(report.net)>=0?INV_GREEN:"#c00", fontWeight:700 }}>= £{report.net}</div>
              </div>
            </div>
          </div>
        ))}
      </div>
      <BottomBar onHome={onHome}/>

      {/* Action sheet */}
      {selected !== null && selectedReport && (
        <div style={{ position:"fixed", inset:0, background:"rgba(0,0,0,0.5)", display:"flex", alignItems:"flex-end", zIndex:2000 }} onClick={()=>setSelected(null)}>
          <div style={{ background:"#fff", width:"100%", borderRadius:"20px 20px 0 0", padding:24 }} onClick={e=>e.stopPropagation()}>
            <div style={{ fontWeight:700, fontSize:15, color:"#222", marginBottom:4, textAlign:"center" }}>{selectedReport.fileName}</div>
            <div style={{ fontSize:12, color:"#aaa", textAlign:"center", marginBottom:20 }}>{selectedReport.period}</div>
            {[
              { label:"👁 Preview", fn:()=>{ setPreviewing(selectedReport); setSelected(null); }, color:"#222" },
              { label:"⬇ Download .xlsx", fn:()=>{ downloadReport(selectedReport); setSelected(null); }, color:"#222" },
              ...(selected.type === "monthly" ? [{ label:"✏️ Edit Categories", fn:()=>{ setEditing(selected.index); setSelected(null); }, color:BLUE }] : []),
              ...(selected.type === "yearly" && onRebuildYearly ? [{ label:"🔄 Rebuild from monthly reports", fn:()=>{ onRebuildYearly(selectedReport.year); setSelected(null); }, color:BLUE }] : []),
              { label:"🗑 Delete", fn:()=>{ setConfirmDelete(selected); setSelected(null); }, color:"#c00" },
            ].map(({label,fn,color})=>(
              <button key={label} onClick={fn} style={{ display:"block", width:"100%", padding:"14px 20px", marginBottom:10, borderRadius:12, border:"1px solid #e8eaf0", background:"#fafafa", fontSize:15, fontWeight:600, color, cursor:"pointer", textAlign:"left" }}>
                {label}
              </button>
            ))}
            <button onClick={()=>setSelected(null)} style={{ display:"block", width:"100%", padding:"14px 20px", borderRadius:12, border:"none", background:"#f0f0f0", fontSize:15, fontWeight:600, color:"#666", cursor:"pointer", textAlign:"center" }}>Cancel</button>
          </div>
        </div>
      )}
      {confirmDelete !== null && (
        <ConfirmDeleteModal
          onCancel={()=>setConfirmDelete(null)}
          onConfirm={()=>{
            if (confirmDelete.type === "yearly") { if(onDeleteYearly) onDeleteYearly(confirmDelete.index); }
            else { onDelete(confirmDelete.index); }
            setConfirmDelete(null);
          }}
        />
      )}
    </div>
  );
}
function MonthlyReportScreen({ onBack, onHome, invoices, onSaveReport, userId }) {
  const [step, setStep] = useState("upload"); // upload | review | done
  const [csvRows, setCsvRows] = useState([]);
  const [period, setPeriod] = useState("");
  const [transactions, setTransactions] = useState([]); // enriched rows
  const [generating, setGenerating] = useState(false);
  const [uploadedFileName, setUploadedFileName] = useState("");
  const [previewData, setPreviewData] = useState(null); // for in-app preview
  const fileRef = useRef(null);

  // Parse bank statement CSV text into rows
  function parseCSV(text) {
    const lines = text.split(/\r?\n/).filter(l => l.trim());
    if (!lines.length) return [];
    const headers = lines[0].split(",").map(h => h.replace(/^"|"$/g,"").trim());
    const rows = [];
    for (let i = 1; i < lines.length; i++) {
      const parts = splitCSVLine(lines[i]);
      if (parts.length < headers.length) continue;
      const obj = {};
      headers.forEach((h, idx) => { obj[h] = (parts[idx]||"").replace(/^"|"$/g,"").trim(); });
      rows.push(obj);
    }
    return rows;
  }

  function splitCSVLine(line) {
    const result = []; let cur = ""; let inQ = false;
    for (let i = 0; i < line.length; i++) {
      const c = line[i];
      if (c === '"') { inQ = !inQ; }
      else if (c === "," && !inQ) { result.push(cur); cur = ""; }
      else { cur += c; }
    }
    result.push(cur);
    return result;
  }

  // Try to match a bank transaction to an app invoice
  function matchInvoice(row, allInvoices) {
    const amount = parseFloat(row["Amount"]) || 0;
    const name = (row["Name"] || "").toLowerCase();
    const notes = (row["Notes and #tags"] || "").toLowerCase();
    const combined = name + " " + notes;

    if (amount <= 0) return null; // outgoing, skip matching

    // Check against paid invoices
    for (const inv of (allInvoices || [])) {
      if (!inv.fullyPaid && !inv.total) continue;
      const invTotal = parseFloat(inv.total) || 0;
      const invNo = (inv.invoiceNo || "").toLowerCase().replace(/^inv0*/,"");
      const clientN = (inv.clientName || "").toLowerCase();
      const instA = (inv.instAddr1 || "").toLowerCase();

      // Match by invoice number mentioned in notes/name
      if (combined.includes(invNo) || combined.includes((inv.invoiceNo||"").toLowerCase())) return inv.invoiceNo;
      // Match by amount + client name fragment
      if (Math.abs(invTotal - amount) < 0.02) {
        const nameParts = clientN.split(/\s+/);
        if (nameParts.some(p => p.length > 3 && combined.includes(p))) return inv.invoiceNo;
      }
    }
    return null;
  }

  // Learned category memory: description (normalised) → category, stored in localStorage
  const LEARNED_KEY = `${userId || "default"}_wlg_expense_categories`;
  function loadLearned() {
    try { return JSON.parse(localStorage.getItem(LEARNED_KEY) || "{}"); } catch { return {}; }
  }
  function saveLearned(desc, cat) {
    try {
      const map = loadLearned();
      map[desc.trim().toLowerCase()] = cat;
      localStorage.setItem(LEARNED_KEY, JSON.stringify(map));
    } catch {}
  }

  function handleFile(file) {
    if (!file) return;
    const name = file.name.toLowerCase();
    const baseName = file.name.replace(/\.(csv|xlsx|xls|qif|pdf)$/i,"").replace(/\s+/g,"_");
    setUploadedFileName(baseName);

    // ── Shared: process normalised row objects ──────────────────────────────
    function processRows(rows) {
      if (!rows.length) { alert("No transactions found. Check this is a valid bank statement export."); return; }
      const dates = rows.map(r => r["Date"]).filter(Boolean).sort();
      if (dates.length) {
        const pd = (s) => { let d=new Date(s); if(isNaN(d)){const m=s.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})/); if(m)d=new Date(`${m[3]}-${m[2].padStart(2,"0")}-${m[1].padStart(2,"0")}`);} return d; };
        const mn=["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"];
        const fmt=d=>isNaN(d.getTime())?"?":`${String(d.getDate()).padStart(2,"0")} ${mn[d.getMonth()]} ${d.getFullYear()}`;
        setPeriod(`${fmt(pd(dates[0]))} to ${fmt(pd(dates[dates.length-1]))}`);
      }
      const learned = loadLearned();
      // Bank-category map (Monzo / Starling category names → app categories)
      const catMap = { "bills":"Bills","entertainment":"General","eating out":"Meals","transport":"Travel","shopping":"General","expenses":"General","holidays":"Travel","insurance":"Insurance","savings":"General","taxes":"Tax","wages":"Wages","software":"Software" };
      // Merchant keyword pre-map: applied on first import when no learned category exists.
      // Keys are lowercase substrings to match against the transaction description.
      const MERCHANT_MAP = [
        // Fuel & travel
        { kw:["shell","bp ","esso","texaco","fuel","petrol","diesel","moto ","welcome break","roadchef"], cat:"Travel" },
        { kw:["trainline","scotrail","avanti","lner","tfl ","oyster","uber ","lyft","taxi","parking","nccp","ringo"], cat:"Travel" },
        // Materials & trade
        { kw:["screwfix","toolstation","jewson","travis perkins","b&q","wickes","selco","city plumbing","mkm ","national heating","city merchant"], cat:"Materials" },
        { kw:["amazon","ebay","rs components","farnell","cpc ","electrical"], cat:"Materials" },
        // Software & subscriptions
        { kw:["google ","microsoft","adobe","dropbox","xero","quickbooks","sage ","slack","zoom","apple ","icloud","netflix","spotify","aws ","digitalocean"], cat:"Software" },
        // Meals
        { kw:["greggs","costa ","starbucks","mcdonald","kfc ","burger king","subway","domino","deliveroo","just eat","uber eat","nandos","morrison","tesco","sainsbury","asda","lidl","aldi","co-op food","marks & spencer food"], cat:"Meals" },
        // Insurance
        { kw:["aviva","axa","ageas","allianz","admiral","direct line","churchill","esure","comparethemarket","moneysupermarket","hastings","hiscox","simply business","gasinsur","corgi direct","bgus","gas insur"], cat:"Insurance" },
        // Rent & premises
        { kw:["rent","storage","lock-up","lockup","garage rent","self storage","safestore","big yellow"], cat:"Rent" },
        // Phone & broadband
        { kw:["bt ","sky ","virgin media","vodafone","o2 ","ee ","three ","talktalk","plusnet","giffgaff","iD mobile"], cat:"Bills" },
        // Equipment & tools
        { kw:["hilti","dewalt","milwaukee","makita","snap-on","sealey","halfords","machine mart","powertools"], cat:"Equipment" },
        // Wages / payroll
        { kw:["payroll","salary","bacs payment","wages","hmrc ","paye","p60","p45"], cat:"Wages" },
        // Tax & accountancy
        { kw:["hmrc","vat payment","corporation tax","self assessment","accountant","bookkeeper"], cat:"Tax" },
        // Pension
        { kw:["pension","nest ","aviva pension","scottish widows","royal london pension"], cat:"Pension" },
      ];
      // Helper: look up merchant category from description
      function merchantCategory(desc) {
        const d = desc.toLowerCase();
        for (const entry of MERCHANT_MAP) {
          if (entry.kw.some(kw => d.includes(kw.toLowerCase()))) return entry.cat;
        }
        return null;
      }
      const enriched = rows.map(row => {
        const amount = parseFloat(row["Amount"]) || 0;
        const isIncome = amount > 0;
        const bankCategory = row["Category"] || row["Type"] || row["Transaction Type"] || "General";
        const desc = (row["Name"] || row["Description"] || "").trim();
        const learnedCat = learned[desc.toLowerCase()] || null;
        // Category priority: 1) user-learned, 2) merchant keyword, 3) bank category name, 4) General
        const autoCategory = learnedCat || merchantCategory(desc) || catMap[bankCategory.toLowerCase()] || "General";
        const matchedInvoice = isIncome ? matchInvoice(row, invoices) : null;
        return { date:row["Date"]||"", description:desc, amount:Math.abs(amount), isIncome, balance:parseFloat(row["Balance"])||0, category:isIncome?"Income":autoCategory, invoiceNo:matchedInvoice||"", bankCategory, _learned:!isIncome&&!!learnedCat, _raw:row };
      });
      setCsvRows(rows);
      setTransactions(enriched);
      setStep("review");
    }

    // ── Normalise XLSX/CSV column names ────────────────────────────────────
    function norm(r) {
      const o={};
      for (const [k,v] of Object.entries(r)) {
        const key=k.trim();
        if (/^date$/i.test(key))                              o["Date"]        = String(v||"");
        else if (/^name|description|payee|merchant/i.test(key)) o["Name"]      = String(v||"");
        else if (/^amount|payment|credit|value/i.test(key))   o["Amount"]      = String(v||"");
        else if (/^balance/i.test(key))                        o["Balance"]     = String(v||"");
        else if (/^category/i.test(key))                       o["Category"]    = String(v||"");
        else if (/^notes?|memo|reference/i.test(key))          o["Notes"]       = String(v||"");
        else o[key] = String(v||"");
      }
      return o;
    }

    // ── QIF parser ─────────────────────────────────────────────────────────
    function parseQIF(text) {
      const rows=[]; let cur={};
      for (const raw of text.split(/\r?\n/)) {
        const line=raw.trim();
        if (!line||/^!Type/i.test(line)) continue;
        if (line==="^") {
          if (cur.Date||cur.Amount) rows.push({ Date:cur.Date||"", Amount:cur.Amount||"0", Name:cur.Payee||cur.Memo||"", Description:cur.Memo||"", Balance:"0", Category:cur.Category||"General" });
          cur={};
        } else {
          const c=line[0],v=line.slice(1);
          if (c==="D") cur.Date=v; else if (c==="T"||c==="U") cur.Amount=v.replace(/,/g,""); else if (c==="P") cur.Payee=v; else if (c==="M") cur.Memo=v; else if (c==="L") cur.Category=v;
        }
      }
      return rows;
    }

    // ── Load XLSX lib async ────────────────────────────────────────────────
    function withXLSX(cb) {
      if (window.XLSX) { cb(window.XLSX); return; }
      const s=document.createElement("script");
      s.src="https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js";
      s.onload=()=>cb(window.XLSX);
      s.onerror=()=>alert("Could not load spreadsheet library. Please try again.");
      document.head.appendChild(s);
    }

    // ── Route by format ────────────────────────────────────────────────────
    if (name.endsWith(".qif")) {
      const r=new FileReader();
      r.onload=ev=>processRows(parseQIF(ev.target.result));
      r.readAsText(file);

    } else if (name.endsWith(".pdf")) {
      const loadPDF = (cb) => {
        if (window.pdfjsLib) { cb(); return; }
        const s=document.createElement("script");
        s.src="https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.min.js";
        s.onload=()=>{ window.pdfjsLib.GlobalWorkerOptions.workerSrc="https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js"; cb(); };
        s.onerror=()=>alert("Could not load PDF library.");
        document.head.appendChild(s);
      };
      loadPDF(() => {
        const r=new FileReader();
        r.onload=ev=>{
          window.pdfjsLib.getDocument({data:new Uint8Array(ev.target.result)}).promise.then(pdf=>{
            const pages=[]; for(let p=1;p<=pdf.numPages;p++) pages.push(p);
            pages.reduce((chain,p)=>chain.then(txt=>pdf.getPage(p).then(pg=>pg.getTextContent()).then(ct=>txt+ct.items.map(i=>i.str).join(" ")+"\n")), Promise.resolve(""))
            .then(txt=>{
              const re=/(\d{2}[\/\-]\d{2}[\/\-]\d{4}|\d{4}-\d{2}-\d{2})\s+(.+?)\s+([-+]?\d[\d,]*\.?\d*)\s+([-+]?\d[\d,]*\.?\d*)?/g;
              const rows=[]; let m;
              while((m=re.exec(txt))!==null) rows.push({Date:m[1],Name:m[2].trim(),Amount:m[3].replace(/,/g,""),Balance:(m[4]||"0").replace(/,/g,""),Description:m[2].trim(),Category:"General"});
              if(!rows.length){alert("Could not extract transactions from this PDF. Try CSV or XLSX instead.");return;}
              processRows(rows);
            }).catch(e=>alert("PDF read error: "+e.message));
          }).catch(e=>alert("PDF error: "+e.message));
        };
        r.readAsArrayBuffer(file);
      });

    } else if (name.endsWith(".xlsx")||name.endsWith(".xls")) {
      const r=new FileReader();
      r.onload=ev=>withXLSX(XL=>{
        try {
          const wb=XL.read(ev.target.result,{type:"binary"});
          const ws=wb.Sheets[wb.SheetNames[0]];
          processRows(XL.utils.sheet_to_json(ws,{defval:""}).map(norm));
        } catch(e) { alert("Could not read spreadsheet: "+e.message); }
      });
      r.readAsBinaryString(file);

    } else {
      // CSV default
      const r=new FileReader();
      r.onload=ev=>processRows(parseCSV(ev.target.result));
      r.readAsText(file);
    }
  }

  async function generateReport() {
    setGenerating(true);
    try {
      // Load SheetJS
      if (!window.XLSX) {
        await new Promise((res,rej) => {
          const s = document.createElement("script");
          s.src = "https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js";
          s.onload = res; s.onerror = rej;
          document.head.appendChild(s);
        });
      }
      const XL = window.XLSX;

      const income = transactions.filter(t => t.isIncome);
      const expenses = transactions.filter(t => !t.isIncome);
      const totalIncome = income.reduce((s,t) => s+t.amount, 0);
      const totalExpenses = expenses.reduce((s,t) => s+t.amount, 0);
      const net = totalIncome - totalExpenses;

      // Group expenses by category
      const expenseGroups = {};
      for (const t of expenses) {
        if (!expenseGroups[t.category]) expenseGroups[t.category] = [];
        expenseGroups[t.category].push(t);
      }

      // Use uploaded CSV filename as the report name
      const monthName = uploadedFileName || period.replace(" to ", "_").replace(/\s/g,"_");
      const wb = XL.utils.book_new();
      const wsData = [];

      // ── Header block ──
      wsData.push(["Bank Transaction", "Description", "Payment", "Deduction", "Balance", "Invoice Number"]);
      wsData.push(["Bank Statement"]);
      try { const _p = JSON.parse(localStorage.getItem(sk("user_profile"))||"{}");
      wsData.push(["Business: " + (_p.companyName||""), "Type: " + (_p.companyType||"")]);
      wsData.push(["Prepared by: " + (_p.engineerName||""), (_p.companyEmail||"")]);
      wsData.push(["Gas Safe No: " + (_p.gasSafeNo||""), "Engineer ID: " + (_p.gasId||"")]);
      wsData.push([(_p.companyAddr||""), (_p.companyPostcode||"")]);
      } catch {}
      wsData.push(["Source: Bank statement CSV export", `Period: ${period}`]);
      wsData.push([]);

      // ── Summary ──
      wsData.push(["Summary Total"]);
      wsData.push(["Total income", totalIncome.toFixed(2)]);
      wsData.push(["Total expenses", totalExpenses.toFixed(2)]);
      wsData.push(["Net", net.toFixed(2)]);
      wsData.push([]);

      // ── Income section ──
      wsData.push(["Income"]);
      wsData.push(["Bank Transaction", "Description", "Payment", "Deduction", "Balance", "Invoice Number"]);
      for (const t of income) {
        wsData.push([t.date, t.description, t.amount.toFixed(2), "", t.balance.toFixed(2), t.invoiceNo]);
      }
      wsData.push([]);

      // ── Expenses by category ──
      wsData.push(["Expenses (grouped by category)"]);
      for (const [cat, rows] of Object.entries(expenseGroups).sort((a,b) => a[0].localeCompare(b[0]))) {
        wsData.push([cat]);
        wsData.push(["Bank Transaction", "Description", "Payment", "Deduction", "Balance", "Invoice Number"]);
        for (const t of rows) {
          wsData.push([t.date, t.description, "", t.amount.toFixed(2), t.balance.toFixed(2), ""]);
        }
      }

      const ws = XL.utils.aoa_to_sheet(wsData);

      // Column widths matching the template
      ws["!cols"] = [
        { wch: 38 }, { wch: 45 }, { wch: 12 }, { wch: 12 }, { wch: 12 }, { wch: 16 }
      ];

      XL.utils.book_append_sheet(wb, ws, monthName.slice(0,31));
      const fileName = `West_Lothian_Gas_${monthName}.xlsx`;

      // Save to Account Reports folder (base64 encoded workbook)
      const wbBase64 = XL.write(wb, { bookType:"xlsx", type:"base64" });
      if (onSaveReport) {
        onSaveReport({
          id: Date.now(),
          fileName,
          period,
          totalIncome: totalIncome.toFixed(2),
          totalExpenses: totalExpenses.toFixed(2),
          net: net.toFixed(2),
          createdAt: new Date().toISOString(),
          xlsxBase64: wbBase64,
          // Structured data for yearly report aggregation
          incomeRows: income.map(t => ({ date:t.date, description:t.description, amount:t.amount, invoiceNo:t.invoiceNo })),
          expenseRows: expenses.map(t => ({ date:t.date, description:t.description, amount:t.amount, category:t.category })),
        });
      }

      XL.writeFile(wb, fileName);

      // Build in-app preview data
      const incomeRows = income.map(t => ({ date:t.date, description:t.description, payment:t.amount.toFixed(2), deduction:"", balance:t.balance.toFixed(2), invoiceNo:t.invoiceNo }));
      const expGroups = {};
      for (const t of expenses) { if (!expGroups[t.category]) expGroups[t.category]=[]; expGroups[t.category].push(t); }
      setPreviewData({ fileName, period, totalIncome:totalIncome.toFixed(2), totalExpenses:totalExpenses.toFixed(2), net:net.toFixed(2), incomeRows, expGroups });
      setStep("preview");
    } catch(e) {
      alert("Error generating report: " + e.message);
    }
    setGenerating(false);
  }

  function saveReportOnly() {
    const income = transactions.filter(t => t.isIncome);
    const expenses = transactions.filter(t => !t.isIncome);
    const totalInc = income.reduce((s,t) => s+t.amount, 0);
    const totalExp = expenses.reduce((s,t) => s+t.amount, 0);
    const monthName = uploadedFileName || period.replace(" to ", "_").replace(/\s/g,"_");
    const fileName = `West_Lothian_Gas_${monthName}.xlsx`;
    if (onSaveReport) {
      onSaveReport({
        id: Date.now(),
        fileName,
        period,
        totalIncome: totalInc.toFixed(2),
        totalExpenses: totalExp.toFixed(2),
        net: (totalInc - totalExp).toFixed(2),
        createdAt: new Date().toISOString(),
        incomeRows: income.map(t => ({ date:t.date, description:t.description, amount:t.amount, invoiceNo:t.invoiceNo })),
        expenseRows: expenses.map(t => ({ date:t.date, description:t.description, amount:t.amount, category:t.category })),
      });
      alert("✅ Report saved to your Account Reports.");
    }
  }

  const BLUE_BTN = { padding:"13px 0", background:BLUE, color:"#fff", border:"none", borderRadius:10, fontWeight:700, fontSize:14, cursor:"pointer", width:"100%" };
  const OUTLINE_BTN = { padding:"13px 0", background:"#f5f5f5", color:BLUE, border:`2px solid ${BLUE}`, borderRadius:10, fontWeight:700, fontSize:14, cursor:"pointer", width:"100%" };
  const SAVE_BTN = { padding:"13px 0", background:"#1a3a4a", color:"#fff", border:"none", borderRadius:10, fontWeight:700, fontSize:14, cursor:"pointer", width:"100%" };

  if (step === "upload") return (
    <div style={{ display:"flex", flexDirection:"column", height:"100dvh", background:LIGHT_BG, fontFamily:"'Segoe UI',sans-serif" }}>
      <Header title="📊 Monthly Report" onBack={onBack} onHome={onHome}/>
      <div style={{ flex:1, overflowY:"auto", padding:16, paddingBottom:80 }}>
        <div style={{ background:"#fff", borderRadius:12, padding:20, marginBottom:14, boxShadow:"0 2px 8px rgba(0,0,0,0.06)", textAlign:"center" }}>
          <div style={{ fontSize:48, marginBottom:8 }}>📂</div>
          <div style={{ fontWeight:700, fontSize:16, color:"#222", marginBottom:6 }}>Upload Bank Statement</div>
          <div style={{ fontSize:13, color:"#888", marginBottom:8, lineHeight:1.6 }}>
            Supports <strong>CSV</strong>, <strong>XLSX</strong>, <strong>QIF</strong> and <strong>PDF</strong> exports.<br/>
            The app will match payments to your invoices automatically.
          </div>
          <input ref={fileRef} type="file" accept=".csv,.xlsx,.xls,.qif,.pdf,text/csv,text/plain,application/csv,application/vnd.ms-excel,application/vnd.openxmlformats-officedocument.spreadsheetml.sheet,application/pdf,application/x-qif" style={{ display:"none" }}
            onChange={e => { if(e.target.files[0]) handleFile(e.target.files[0]); }}/>
          <button onClick={()=>fileRef.current?.click()} style={BLUE_BTN}>
            📁 Choose File (CSV, XLSX, QIF or PDF)
          </button>
        </div>

        <div style={{ background:"#fff", borderRadius:12, padding:16, boxShadow:"0 2px 8px rgba(0,0,0,0.06)" }}>
          <div style={{ fontWeight:700, fontSize:13, color:"#444", marginBottom:8 }}>What this does:</div>
          {["Reads your bank statement CSV",
            "Automatically matches payments to your paid invoices",
            "Groups expenses by category",
            "Generates an .xlsx report in the same format as your existing statements"
          ].map((t,i) => (
            <div key={i} style={{ fontSize:13, color:"#666", marginBottom:6, display:"flex", gap:8 }}>
              <span style={{ color:BLUE, fontWeight:700 }}>✓</span> {t}
            </div>
          ))}
        </div>
      </div>
      <BottomBar onHome={onHome}/>
    </div>
  );

  if (step === "review") {
    const income = transactions.filter(t => t.isIncome);
    const expenses = transactions.filter(t => !t.isIncome);
    const totalIncome = income.reduce((s,t)=>s+t.amount,0);
    const totalExpenses = expenses.reduce((s,t)=>s+t.amount,0);
    const matched = income.filter(t=>t.invoiceNo).length;

    return (
      <div style={{ display:"flex", flexDirection:"column", height:"100dvh", background:LIGHT_BG, fontFamily:"'Segoe UI',sans-serif" }}>
        <Header title="📊 Review & Generate" onBack={()=>setStep("upload")} onHome={onHome}/>
        <div style={{ flex:1, overflowY:"auto", padding:16, paddingBottom:80 }}>

          {/* Summary card */}
          <div style={{ background:"#fff", borderRadius:12, padding:16, marginBottom:12, boxShadow:"0 2px 8px rgba(0,0,0,0.06)" }}>
            <div style={{ fontWeight:700, fontSize:14, color:"#222", marginBottom:10, borderBottom:"1px solid #f0f0f0", paddingBottom:8 }}>📅 {period}</div>
            {[
              ["Total Income", `£${totalIncome.toFixed(2)}`, INV_GREEN],
              ["Total Expenses", `£${totalExpenses.toFixed(2)}`, "#c00"],
              ["Net", `£${(totalIncome-totalExpenses).toFixed(2)}`, (totalIncome-totalExpenses)>=0 ? INV_GREEN : "#c00"],
              ["Transactions", `${transactions.length}`, "#555"],
              ["Invoice Matches", `${matched} of ${income.length} income`, BLUE],
            ].map(([label, val, col]) => (
              <div key={label} style={{ display:"flex", justifyContent:"space-between", fontSize:13, padding:"4px 0", borderBottom:"1px solid #f5f5f5" }}>
                <span style={{ color:"#888" }}>{label}</span>
                <span style={{ fontWeight:700, color:col }}>{val}</span>
              </div>
            ))}
          </div>

          {/* Income rows */}
          <div style={{ background:"#fff", borderRadius:12, padding:16, marginBottom:12, boxShadow:"0 2px 8px rgba(0,0,0,0.06)" }}>
            <div style={{ fontWeight:700, fontSize:14, color:INV_GREEN, marginBottom:10 }}>💰 Income ({income.length})</div>
            {income.map((t,i) => {
              const globalIdx = transactions.indexOf(t);
              return (
              <div key={i} style={{ padding:"8px 0", borderBottom:"1px solid #f5f5f5", fontSize:13 }}>
                <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start" }}>
                  <div style={{ flex:1, minWidth:0 }}>
                    <div style={{ fontWeight:600, color:"#222", overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>{t.description}</div>
                    <div style={{ fontSize:11, color:"#aaa" }}>{t.date}</div>
                  </div>
                  <div style={{ fontWeight:700, color:INV_GREEN, marginLeft:8, flexShrink:0 }}>£{t.amount.toFixed(2)}</div>
                </div>
                <div style={{ display:"flex", alignItems:"center", gap:6, marginTop:4 }}>
                  <span style={{ fontSize:11, color:"#888", flexShrink:0 }}>Invoice:</span>
                  <input value={t.invoiceNo} onChange={e=>setTransactions(tx=>tx.map((x,idx)=>idx===globalIdx?{...x,invoiceNo:e.target.value}:x))}
                    placeholder="e.g. INV00001 or type manually"
                    style={{ flex:1, fontSize:11, border:"1px solid #ddd", borderRadius:6, padding:"4px 8px", outline:"none" }}/>
                  {(invoices||[]).filter(inv=>inv.fullyPaid).length > 0 && (
                    <select onChange={e=>{ if(e.target.value) setTransactions(tx=>tx.map((x,idx)=>idx===globalIdx?{...x,invoiceNo:e.target.value}:x)); }}
                      style={{ fontSize:11, border:"1px solid #ddd", borderRadius:6, padding:"4px 6px", maxWidth:120 }}>
                      <option value="">Pick invoice</option>
                      {(invoices||[]).filter(inv=>inv.fullyPaid).map(inv=>(
                        <option key={inv.invoiceNo} value={inv.invoiceNo}>{inv.invoiceNo} £{(inv.total||0).toFixed(2)}</option>
                      ))}
                    </select>
                  )}
                </div>
              </div>
              );
            })}
          </div>

          {/* Expense rows with category editor */}
          <div style={{ background:"#fff", borderRadius:12, padding:16, marginBottom:14, boxShadow:"0 2px 8px rgba(0,0,0,0.06)" }}>
            <div style={{ fontWeight:700, fontSize:14, color:"#c00", marginBottom:10 }}>📤 Expenses ({expenses.length})</div>
            {expenses.map((t,i) => {
              const globalIdx = transactions.indexOf(t);
              return (
                <div key={i} style={{ display:"flex", justifyContent:"space-between", alignItems:"center", padding:"6px 0", borderBottom:"1px solid #f5f5f5", fontSize:13 }}>
                  <div style={{ flex:1, minWidth:0 }}>
                    <div style={{ fontWeight:600, color:"#222", overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>{t.description}</div>
                    <div style={{ fontSize:11, color:"#aaa" }}>{t.date}{t._learned ? <span style={{ color:BLUE, marginLeft:6 }}>🧠</span> : null}</div>
                  </div>
                  <div style={{ textAlign:"right", marginLeft:8, flexShrink:0 }}>
                    <div style={{ fontWeight:700, color:"#c00" }}>£{t.amount.toFixed(2)}</div>
                    <select value={t.category} onChange={e=>{ saveLearned(t.description, e.target.value); setTransactions(tx=>tx.map((x,idx)=>idx===globalIdx?{...x,category:e.target.value}:x)); }}
                      style={{ fontSize:11, border:"1px solid #ddd", borderRadius:4, padding:"1px 4px", marginTop:2 }}>
                      {EXPENSE_CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
                    </select>
                  </div>
                </div>
              );
            })}
          </div>

          <button onClick={saveReportOnly} style={{...SAVE_BTN, marginBottom:10}}>
            💾 Save Report
          </button>
          <button onClick={generateReport} disabled={generating} style={{...BLUE_BTN, background:generating?"#aaa":BLUE, marginBottom:16}}>
            {generating ? "⏳ Generating..." : "⬇ Download .xlsx Report"}
          </button>
        </div>
        <BottomBar onHome={onHome}/>
      </div>
    );
  }

  if (step === "preview" && previewData) {
    const pd = previewData;
    return (
      <div style={{ display:"flex", flexDirection:"column", height:"100dvh", background:LIGHT_BG, fontFamily:"'Segoe UI',sans-serif" }}>
        <Header title="📊 Report Preview" onBack={()=>setStep("review")} onHome={onHome}/>
        <div style={{ flex:1, overflowY:"auto", padding:16, paddingBottom:80 }}>
          {/* Summary */}
          <div style={{ background:"#fff", borderRadius:12, padding:16, marginBottom:12, boxShadow:"0 2px 8px rgba(0,0,0,0.06)", borderLeft:`4px solid ${BLUE}` }}>
            <div style={{ fontWeight:700, fontSize:15, color:"#222", marginBottom:4 }}>{pd.fileName}</div>
            <div style={{ fontSize:12, color:"#888", marginBottom:10 }}>Period: {pd.period}</div>
            {[["Total Income","£"+pd.totalIncome,INV_GREEN],["Total Expenses","£"+pd.totalExpenses,"#c00"],["Net","£"+pd.net,parseFloat(pd.net)>=0?INV_GREEN:"#c00"]].map(([l,v,c])=>(
              <div key={l} style={{ display:"flex", justifyContent:"space-between", fontSize:13, padding:"3px 0", borderBottom:"1px solid #f5f5f5" }}>
                <span style={{ color:"#888" }}>{l}</span><span style={{ fontWeight:700, color:c }}>{v}</span>
              </div>
            ))}
          </div>

          {/* Income table */}
          <div style={{ background:"#fff", borderRadius:12, padding:16, marginBottom:12, boxShadow:"0 2px 8px rgba(0,0,0,0.06)" }}>
            <div style={{ fontWeight:700, fontSize:13, color:INV_GREEN, marginBottom:8 }}>💰 Income</div>
            <table style={{ width:"100%", borderCollapse:"collapse", fontSize:11 }}>
              <thead>
                <tr style={{ background:"#f5f5f5" }}>
                  {["Date","Description","Payment","Invoice No"].map(h=>(
                    <th key={h} style={{ padding:"5px 6px", textAlign:"left", fontWeight:700, color:"#555", borderBottom:"1px solid #ddd" }}>{h}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {pd.incomeRows.map((r,i)=>(
                  <tr key={i} style={{ background:i%2===0?"#fafafa":"#fff" }}>
                    <td style={{ padding:"5px 6px", color:"#666", whiteSpace:"nowrap" }}>{r.date.slice(0,10)}</td>
                    <td style={{ padding:"5px 6px", color:"#222", maxWidth:140, overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>{r.description}</td>
                    <td style={{ padding:"5px 6px", color:INV_GREEN, fontWeight:700 }}>£{r.payment}</td>
                    <td style={{ padding:"5px 6px", color:BLUE, fontSize:10 }}>{r.invoiceNo}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          {/* Expenses by category */}
          {Object.entries(pd.expGroups).sort((a,b)=>a[0].localeCompare(b[0])).map(([cat, rows])=>(
            <div key={cat} style={{ background:"#fff", borderRadius:12, padding:16, marginBottom:12, boxShadow:"0 2px 8px rgba(0,0,0,0.06)" }}>
              <div style={{ fontWeight:700, fontSize:13, color:"#c00", marginBottom:8 }}>📤 {cat}</div>
              <table style={{ width:"100%", borderCollapse:"collapse", fontSize:11 }}>
                <thead>
                  <tr style={{ background:"#f5f5f5" }}>
                    {["Date","Description","Amount"].map(h=>(
                      <th key={h} style={{ padding:"5px 6px", textAlign:"left", fontWeight:700, color:"#555", borderBottom:"1px solid #ddd" }}>{h}</th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {rows.map((r,i)=>(
                    <tr key={i} style={{ background:i%2===0?"#fafafa":"#fff" }}>
                      <td style={{ padding:"5px 6px", color:"#666", whiteSpace:"nowrap" }}>{r.date.slice(0,10)}</td>
                      <td style={{ padding:"5px 6px", color:"#222", maxWidth:160, overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>{r.description}</td>
                      <td style={{ padding:"5px 6px", color:"#c00", fontWeight:700 }}>£{r.amount.toFixed(2)}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          ))}

          <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:10, marginBottom:16 }}>
            <button onClick={()=>setStep("review")} style={{ padding:"13px 0", background:"#f0f0f0", color:"#555", border:"none", borderRadius:10, fontWeight:700, fontSize:14, cursor:"pointer" }}>← Edit</button>
            <button onClick={()=>setStep("done")} style={{ padding:"13px 0", background:INV_GREEN, color:"#fff", border:"none", borderRadius:10, fontWeight:700, fontSize:14, cursor:"pointer" }}>✅ Done</button>
          </div>
        </div>
        <BottomBar onHome={onHome}/>
      </div>
    );
  }

  return (
    <div style={{ display:"flex", flexDirection:"column", height:"100dvh", background:LIGHT_BG, fontFamily:"'Segoe UI',sans-serif" }}>
      <Header title="📊 Monthly Report" onBack={onBack} onHome={onHome}/>
      <div style={{ flex:1, display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center", padding:24, textAlign:"center" }}>
        <div style={{ fontSize:64, marginBottom:16 }}>✅</div>
        <div style={{ fontWeight:700, fontSize:20, color:"#222", marginBottom:8 }}>Report Saved!</div>
        <div style={{ fontSize:14, color:"#666", marginBottom:28 }}>Downloaded to your device and saved to Account Reports in Records.</div>
        <button onClick={()=>{ setStep("upload"); setPreviewData(null); }} style={{...BLUE_BTN, maxWidth:280}}>📂 Import Another Statement</button>
        <div style={{ marginTop:12 }}>
          <button onClick={onHome} style={{...OUTLINE_BTN, maxWidth:280}}>🏠 Home</button>
        </div>
      </div>
    </div>
  );
}


// ─── Profile Setup / Edit Screen ─────────────────────────────────────────────
// ─── Registered users stored in localStorage (device-local registry) ──────────
const REGISTRY_KEY = "wlg_registered_users"; // shared, not namespaced

function getRegisteredUsers() {
  try { return JSON.parse(localStorage.getItem(REGISTRY_KEY) || "[]"); } catch { return []; }
}
function saveRegisteredUser(entry) {
  // entry: { username, displayName, hash }
  const users = getRegisteredUsers();
  const idx = users.findIndex(u => u.username === entry.username);
  if (idx >= 0) users[idx] = entry; else users.push(entry);
  try { localStorage.setItem(REGISTRY_KEY, JSON.stringify(users)); } catch {}
}
function findUser(username) {
  const lower = username.trim().toLowerCase();
  // Check hardcoded admins first
  const admin = USERS.find(u => u.username.toLowerCase() === lower);
  if (admin) return admin;
  // Check registered users (emails stored lowercase)
  return getRegisteredUsers().find(u => u.username.toLowerCase() === lower) || null;
}
function usernameAvailable(email) {
  const lower = email.trim().toLowerCase();
  if (USERS.some(u => u.username.toLowerCase() === lower)) return false;
  return !getRegisteredUsers().some(u => u.username.toLowerCase() === lower);
}
// ─────────────────────────────────────────────────────────────────────────────

function ProfileForm({ initial, onSave, onBack, isSetup, onRegistered }) {
  const [form, setForm] = useState({
    companyName:    initial?.companyName    || "",
    companyType:    initial?.companyType    || "Limited company",
    companyNumber:  initial?.companyNumber  || "",
    vatRegNumber:   initial?.vatRegNumber   || "",
    companyAddr:    initial?.companyAddr    || "",
    companyPostcode: initial?.companyPostcode || "",
    companyTel:     initial?.companyTel     || "",
    companyEmail:   initial?.companyEmail   || "",
    companyWeb:     initial?.companyWeb     || "",
    gasSafeNo:      initial?.gasSafeNo      || "",
    engineerName:   initial?.engineerName   || "",
    gasId:          initial?.gasId          || "",
    logoImage:      initial?.logoImage      || null,
  });
  const [creds, setCreds] = useState({ username:"", password:"", confirm:"", showPw:false, showCf:false });
  const [error, setError] = useState("");
  const [saving, setSaving] = useState(false);
  const logoRef = useRef();

  function handleLogoUpload(e) {
    const file = e.target.files?.[0];
    if (!file) return;
    if (file.size > 500000) { setError("Logo must be under 500KB"); return; }
    const reader = new FileReader();
    reader.onload = ev => setForm(f => ({ ...f, logoImage: ev.target.result }));
    reader.readAsDataURL(file);
  }

  async function handleSave() {
    // Validate profile fields
    if (!form.companyName.trim()) { setError("Company name is required."); return; }
    if (!form.engineerName.trim()) { setError("Engineer name is required."); return; }
    if (!form.gasSafeNo.trim()) { setError("Gas Safe registration number is required."); return; }
    if (!form.gasId.trim()) { setError("Engineer ID is required."); return; }

    if (isSetup) {
      // Validate credentials
      const u = creds.username.trim().toLowerCase();
      if (!u) { setError("Please enter your email address."); return; }
      if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(u)) { setError("Please enter a valid email address."); return; }
      if (!usernameAvailable(u)) { setError("An account with that email already exists. Please sign in instead."); return; }
      if (!creds.password) { setError("Please choose a password."); return; }
      if (creds.password.length < 6) { setError("Password must be at least 6 characters."); return; }
      if (creds.password !== creds.confirm) { setError("Passwords don't match."); return; }

      setSaving(true);
      setError("");

      let hash = "";
      try { hash = await hashPassword(creds.password); } catch { setError("Failed to hash password. Please try again."); setSaving(false); return; }
      if (!hash) { setError("Failed to create account. Please try again."); setSaving(false); return; }

      // If Supabase is enabled, create a Supabase Auth account too
      let supabaseId = null;
      if (isSupabaseEnabled()) {
        try {
          const { user: sbUser } = await supabaseSignUp(u, creds.password, {
            engineerName: form.engineerName,
            companyName: form.companyName,
            gasSafeNo: form.gasSafeNo,
          });
          supabaseId = sbUser?.id || null;
        } catch (sbErr) {
          // If the email is already registered in Supabase, show a helpful message
          const msg = sbErr?.message || "";
          if (msg.includes("already registered") || msg.includes("already been registered")) {
            setError("This email is already registered. Please sign in instead.");
          } else {
            // Non-blocking: Supabase signup failed but local registration can proceed
            console.warn("[Auth] Supabase signUp failed (continuing with local):", msg);
          }
          if (msg.includes("already registered") || msg.includes("already been registered")) { setSaving(false); return; }
        }
      }

      const userEntry = { username: u, displayName: form.engineerName, hash, ...(supabaseId ? { supabaseId, isSupabaseUser: true } : {}) };
      try { saveRegisteredUser(userEntry); } catch { setError("Failed to save account. Please try again."); setSaving(false); return; }

      // Fire-and-forget notification email to admin
      sendNewUserNotification(u, form).catch(() => {});

      // Call onSave last — this will unmount this component so don't call setState after
      onSave({ ...form }, userEntry);
    } else {
      setError("");
      onSave({ ...form });
    }
  }

  const inp = (label, key, opts={}) => (
    <div style={{ marginBottom:14 }}>
      <div style={{ fontSize:12, fontWeight:600, color:"#555", marginBottom:4 }}>{label}{opts.required && <span style={{ color:"#d32f2f" }}> *</span>}</div>
      {opts.multiline
        ? <textarea value={form[key]} onChange={e=>setForm(f=>({...f,[key]:e.target.value}))} rows={opts.rows||2}
            style={{ width:"100%", padding:"11px 13px", border:"1px solid #ddd", borderRadius:8, fontSize:15, boxSizing:"border-box", fontFamily:"'Segoe UI',sans-serif", resize:"vertical" }}/>
        : <input value={form[key]} onChange={e=>setForm(f=>({...f,[key]:e.target.value}))} type={opts.type||"text"}
            style={{ width:"100%", padding:"11px 13px", border:"1px solid #ddd", borderRadius:8, fontSize:15, boxSizing:"border-box", fontFamily:"'Segoe UI',sans-serif" }}/>
      }
    </div>
  );

  return (
    <div style={{ minHeight:"100dvh", background:"linear-gradient(135deg, #0d1f2d 0%, #1a3a4a 60%, #35463d 100%)", fontFamily:"'Segoe UI',sans-serif", display:"flex", flexDirection:"column" }}>
      {/* Header */}
      <div style={{ padding:"20px 20px 12px", display:"flex", alignItems:"center", gap:12 }}>
        {onBack && (
          <button onClick={onBack} style={{ background:"rgba(255,255,255,0.15)", border:"none", borderRadius:"50%", width:36, height:36, display:"flex", alignItems:"center", justifyContent:"center", cursor:"pointer", color:"#fff", fontSize:20 }}>‹</button>
        )}
        <div style={{ flex:1 }}>
          <div style={{ color:"#fff200", fontWeight:800, fontSize:20 }}>{isSetup ? "Create Your Profile" : "Edit Profile"}</div>
          <div style={{ color:"rgba(255,255,255,0.7)", fontSize:13 }}>{isSetup ? "Set up your details — your email will be your username" : "Changes apply to new documents"}</div>
        </div>
      </div>

      <div style={{ flex:1, overflowY:"auto", padding:"0 16px 88px" }}>

        {/* Login credentials — setup only */}
        {isSetup && (
          <div style={{ background:"#fff", borderRadius:16, padding:20, marginBottom:14 }}>
            <div style={{ fontWeight:700, fontSize:15, color:"#0d1f2d", marginBottom:4, paddingBottom:10, borderBottom:"1px solid #f0f0f0" }}>🔐 Your Login Details</div>
            <p style={{ fontSize:13, color:"#666", margin:"0 0 14px" }}>Your email address will be your username to sign in.</p>
            <div style={{ marginBottom:12 }}>
              <div style={{ fontSize:12, fontWeight:600, color:"#555", marginBottom:4 }}>Email Address <span style={{ color:"#d32f2f" }}>*</span></div>
              <input type="email" value={creds.username} onChange={e=>{ setCreds(c=>({...c,username:e.target.value.trim().toLowerCase()})); setError(""); }}
                placeholder="e.g. john@example.com" autoCapitalize="none" autoCorrect="off" autoComplete="email"
                style={{ width:"100%", padding:"11px 13px", border:"1px solid #ddd", borderRadius:8, fontSize:15, boxSizing:"border-box", fontFamily:"'Segoe UI',sans-serif" }}/>
              <div style={{ fontSize:11, color:"#999", marginTop:3 }}>This will be your sign-in username.</div>
            </div>
            <div style={{ marginBottom:12 }}>
              <div style={{ fontSize:12, fontWeight:600, color:"#555", marginBottom:4 }}>Password <span style={{ color:"#d32f2f" }}>*</span></div>
              <div style={{ position:"relative" }}>
                <input type={creds.showPw?"text":"password"} value={creds.password}
                  onChange={e=>{ setCreds(c=>({...c,password:e.target.value})); setError(""); }}
                  placeholder="At least 6 characters"
                  style={{ width:"100%", padding:"11px 44px 11px 13px", border:"1px solid #ddd", borderRadius:8, fontSize:15, boxSizing:"border-box", fontFamily:"'Segoe UI',sans-serif" }}/>
                <button onClick={()=>setCreds(c=>({...c,showPw:!c.showPw}))} style={{ position:"absolute", right:12, top:"50%", transform:"translateY(-50%)", background:"none", border:"none", cursor:"pointer", fontSize:16, color:"#888", padding:0 }}>{creds.showPw?"🙈":"👁️"}</button>
              </div>
            </div>
            <div>
              <div style={{ fontSize:12, fontWeight:600, color:"#555", marginBottom:4 }}>Confirm Password <span style={{ color:"#d32f2f" }}>*</span></div>
              <div style={{ position:"relative" }}>
                <input type={creds.showCf?"text":"password"} value={creds.confirm}
                  onChange={e=>{ setCreds(c=>({...c,confirm:e.target.value})); setError(""); }}
                  placeholder="Repeat your password"
                  style={{ width:"100%", padding:"11px 44px 11px 13px", border:"1px solid #ddd", borderRadius:8, fontSize:15, boxSizing:"border-box", fontFamily:"'Segoe UI',sans-serif" }}/>
                <button onClick={()=>setCreds(c=>({...c,showCf:!c.showCf}))} style={{ position:"absolute", right:12, top:"50%", transform:"translateY(-50%)", background:"none", border:"none", cursor:"pointer", fontSize:16, color:"#888", padding:0 }}>{creds.showCf?"🙈":"👁️"}</button>
              </div>
            </div>
          </div>
        )}

        {/* Logo */}
        <div style={{ background:"#fff", borderRadius:16, padding:20, marginBottom:14 }}>
          <div style={{ fontWeight:700, fontSize:15, color:"#0d1f2d", marginBottom:14, paddingBottom:10, borderBottom:"1px solid #f0f0f0" }}>🏢 Company Logo</div>
          <div style={{ display:"flex", alignItems:"center", gap:16, marginBottom:8 }}>
            {form.logoImage
              ? <img src={form.logoImage} style={{ height:64, maxWidth:140, objectFit:"contain", borderRadius:8, border:"1px solid #eee" }} alt="Logo"/>
              : <div style={{ width:100, height:64, background:"#f5f5f5", borderRadius:8, display:"flex", alignItems:"center", justifyContent:"center", color:"#aaa", fontSize:12, border:"2px dashed #ddd" }}>No logo</div>
            }
            <div>
              <button onClick={()=>logoRef.current?.click()} style={{ background:"#1a3a4a", color:"#fff", border:"none", borderRadius:8, padding:"9px 18px", fontSize:14, fontWeight:600, cursor:"pointer", display:"block", marginBottom:6 }}>
                {form.logoImage ? "Change Logo" : "Upload Logo"}
              </button>
              {form.logoImage && <button onClick={()=>setForm(f=>({...f,logoImage:null}))} style={{ background:"none", color:"#d32f2f", border:"none", fontSize:13, cursor:"pointer", padding:0 }}>Remove</button>}
              <input ref={logoRef} type="file" accept="image/*" onChange={handleLogoUpload} style={{ display:"none" }}/>
              <div style={{ fontSize:11, color:"#999", marginTop:4 }}>PNG, JPG — max 500KB</div>
            </div>
          </div>
        </div>

        {/* Company details */}
        <div style={{ background:"#fff", borderRadius:16, padding:20, marginBottom:14 }}>
          <div style={{ fontWeight:700, fontSize:15, color:"#0d1f2d", marginBottom:14, paddingBottom:10, borderBottom:"1px solid #f0f0f0" }}>🏢 Company Details</div>
          {inp("Company Name", "companyName", { required:true })}
          {inp("Company Type (e.g. Limited company, Sole trader)", "companyType")}
          {inp("Companies House Number (optional)", "companyNumber")}
          {inp("VAT Registration Number (optional)", "vatRegNumber")}
          {inp("Address", "companyAddr", { multiline:true })}
          {inp("Postcode", "companyPostcode")}
          {inp("Phone Number", "companyTel", { type:"tel" })}
          {inp("Email Address", "companyEmail", { type:"email" })}
          {inp("Website (optional)", "companyWeb")}
        </div>

        {/* Engineer details */}
        <div style={{ background:"#fff", borderRadius:16, padding:20, marginBottom:14 }}>
          <div style={{ fontWeight:700, fontSize:15, color:"#0d1f2d", marginBottom:14, paddingBottom:10, borderBottom:"1px solid #f0f0f0" }}>👷 Engineer Details</div>
          {inp("Engineer Name", "engineerName", { required:true })}
          {inp("Gas Safe Registration No.", "gasSafeNo", { required:true })}
          {inp("Engineer ID (Gas Safe ID number)", "gasId", { required:true })}
        </div>

        {/* Engineer Signature */}
        <div style={{ background:"#fff", borderRadius:16, padding:20, marginBottom:14 }}>
          <div style={{ fontWeight:700, fontSize:15, color:"#0d1f2d", marginBottom:6, paddingBottom:10, borderBottom:"1px solid #f0f0f0" }}>✍️ My Signature</div>
          <div style={{ fontSize:13, color:"#666", marginBottom:12, lineHeight:1.5 }}>
            Draw your signature once here — it will automatically appear on all certificates.
          </div>
          <SigPad
            storageKey="gsc_engineer_sig"
            value={null}
            onChange={()=>{}}
          />
        </div>

        {error && <div style={{ background:"#fdecea", border:"1px solid #f5c6c6", borderRadius:8, padding:"10px 14px", color:"#d32f2f", fontSize:14, marginBottom:14 }}>{error}</div>}

        <button onClick={handleSave} disabled={saving}
          style={{ width:"100%", padding:17, background:saving?"#aaa":"#0d1f2d", color:saving?"#fff":"#fff200", border:"none", borderRadius:12, fontSize:17, fontWeight:700, cursor:saving?"default":"pointer", fontFamily:"inherit" }}>
          {saving ? "Saving…" : isSetup ? "Create Account →" : "Save Changes"}
        </button>
      </div>
    </div>
  );
}


// ─── Payment Details Screen (My Profile → Payment Details) ───────────────────
function PaymentDetailsScreen({ onBack, onHome }) {
  const DEFAULT_MESSAGE = "Includes your 1 year warranty, thank you for your business.";

  const loadDetails = () => {
    try {
      const p = JSON.parse(localStorage.getItem(sk("user_profile")) || "{}");
      return {
        accountName:     p.paymentAccountName    || "",
        sortCode:        p.paymentSortCode        || "",
        accountNumber:   p.paymentAccountNumber   || "",
        personalMessage: p.paymentPersonalMessage || DEFAULT_MESSAGE,
      };
    } catch { return { accountName:"", sortCode:"", accountNumber:"", personalMessage:DEFAULT_MESSAGE }; }
  };

  const [form, setForm] = useState(loadDetails);
  const [saved, setSaved] = useState(false);
  const [error, setError] = useState("");

  const set = (k, v) => { setForm(f=>({...f,[k]:v})); setSaved(false); setError(""); };

  function handleSave() {
    const sc = form.sortCode.replace(/[^0-9]/g,"");
    if (form.sortCode && sc.length !== 6) { setError("Sort code must be 6 digits (e.g. 12-34-56)."); return; }
    const an = form.accountNumber.replace(/[^0-9]/g,"");
    if (form.accountNumber && an.length !== 8) { setError("Account number must be 8 digits."); return; }
    try {
      const p = JSON.parse(localStorage.getItem(sk("user_profile")) || "{}");
      p.paymentAccountName    = form.accountName;
      p.paymentSortCode       = form.sortCode;
      p.paymentAccountNumber  = form.accountNumber;
      p.paymentPersonalMessage= form.personalMessage;
      localStorage.setItem(sk("user_profile"), JSON.stringify(p));
      setSaved(true);
      setError("");
    } catch { setError("Failed to save. Please try again."); }
  }

  const inputStyle = { width:"100%", padding:"13px 14px", border:"1px solid #ddd", borderRadius:10, fontSize:15, boxSizing:"border-box", fontFamily:"'Segoe UI',sans-serif", outline:"none", marginBottom:2 };

  return (
    <div style={{ minHeight:"100dvh", background:`linear-gradient(135deg,${DARK_BLUE},${BLUE})`, fontFamily:"'Segoe UI',sans-serif", display:"flex", flexDirection:"column" }}>
      <div style={{ padding:"20px 20px 12px", display:"flex", alignItems:"center", gap:12 }}>
        <button onClick={onBack} style={{ background:"rgba(255,255,255,0.15)", border:"none", borderRadius:"50%", width:36, height:36, display:"flex", alignItems:"center", justifyContent:"center", cursor:"pointer", color:"#fff", fontSize:20 }}>‹</button>
        <div style={{ flex:1 }}>
          <div style={{ color:"#fff200", fontWeight:800, fontSize:20 }}>Payment Details</div>
          <div style={{ color:"rgba(255,255,255,0.7)", fontSize:13 }}>Auto-populates invoice notes</div>
        </div>
      </div>

      <div style={{ flex:1, overflowY:"auto", padding:"0 16px 88px" }}>
        <div style={{ background:"#fff", borderRadius:16, padding:20, marginBottom:14 }}>
          <div style={{ fontWeight:700, fontSize:15, color:"#0d1f2d", marginBottom:6, paddingBottom:10, borderBottom:"1px solid #f0f0f0" }}>💳 Bank Details</div>
          <div style={{ fontSize:12, color:"#888", marginBottom:14, lineHeight:1.5 }}>
            These details will automatically appear in the Notes field on every invoice and quote you create.
          </div>

          <div style={{ marginBottom:14 }}>
            <div style={{ fontSize:12, fontWeight:600, color:"#555", marginBottom:4 }}>Account Name</div>
            <input value={form.accountName} onChange={e=>set("accountName",e.target.value)}
              placeholder="e.g. Your Company Name"
              style={inputStyle}/>
          </div>

          <div style={{ marginBottom:14 }}>
            <div style={{ fontSize:12, fontWeight:600, color:"#555", marginBottom:4 }}>Sort Code</div>
            <input value={form.sortCode} onChange={e=>set("sortCode",e.target.value)}
              placeholder="e.g. 12-34-56" maxLength={8}
              style={inputStyle}/>
            <div style={{ fontSize:11, color:"#aaa", marginTop:2 }}>6 digits</div>
          </div>

          <div style={{ marginBottom:14 }}>
            <div style={{ fontSize:12, fontWeight:600, color:"#555", marginBottom:4 }}>Account Number</div>
            <input value={form.accountNumber} onChange={e=>set("accountNumber",e.target.value)}
              placeholder="e.g. 12345678" maxLength={8}
              style={inputStyle}/>
            <div style={{ fontSize:11, color:"#aaa", marginTop:2 }}>8 digits</div>
          </div>

          <div>
            <div style={{ fontSize:12, fontWeight:600, color:"#555", marginBottom:4 }}>Personal Message</div>
            <textarea value={form.personalMessage} onChange={e=>set("personalMessage",e.target.value)}
              rows={3}
              style={{ ...inputStyle, resize:"vertical", minHeight:72 }}/>
          </div>
        </div>

        {error && <div style={{ background:"#fdecea", border:"1px solid #f5c6c6", borderRadius:8, padding:"10px 14px", color:"#d32f2f", fontSize:14, marginBottom:14 }}>{error}</div>}
        {saved && <div style={{ background:"#e8f5e9", border:"1px solid #a5d6a7", borderRadius:8, padding:"10px 14px", color:"#2e7d32", fontSize:14, marginBottom:14 }}>✅ Payment details saved!</div>}

        <button onClick={handleSave}
          style={{ width:"100%", padding:17, background:"#0d1f2d", color:"#fff200", border:"none", borderRadius:12, fontSize:17, fontWeight:700, cursor:"pointer", fontFamily:"inherit" }}>
          Save Payment Details
        </button>
      </div>
    </div>
  );
}
// ─────────────────────────────────────────────────────────────────────────────
function ProfileSetupScreen({ onSave, onBack }) {
  return <ProfileForm initial={null} onSave={onSave} isSetup={true} onBack={onBack}/>;
}

function ProfileEditScreen({ profile, onSave, onBack, onHome }) {
  const [subView, setSubView] = useState("profile"); // "profile" | "payment"
  if (subView === "payment") return <PaymentDetailsScreen onBack={()=>setSubView("profile")} onHome={onHome}/>;
  return (
    <>
      <ProfileForm initial={profile} onSave={onSave} onBack={onBack} isSetup={false}/>

    </>
  );
}
// ─────────────────────────────────────────────────────────────────────────────


// ─── Payment Screen ───────────────────────────────────────────────────────────
function PaywallScreen({ onLogout, onPaymentSubmitted, currentUser }) {
  const [step, setStep] = useState("paywall"); // "paywall" | "form" | "done"
  const [selectedPlan, setSelectedPlan] = useState("pro"); // "lite" | "pro" | "proplus"
  const [billingCycle, setBillingCycle] = useState("monthly"); // "monthly" | "annual"
  const PLANS = {
    lite:    { name:"Lite",  monthly:7.50,   annual:75,    features:["All Certificate Types","Up to 20 Certificates / Month","Invoicing & Quotes","Gas Rate Calculator","Job Sheets","Photographic Evidence"], excluded:["Accounts Feature","Annual Reminders","Multiple Engineers"] },
    pro:     { name:"Pro",   monthly:14.50,  annual:135,   features:["Everything in Lite","Unlimited Certificates","Accounts Feature","Annual Reminders","Business Analytics","Customer Database"], excluded:["Multiple Engineers"] },
    proplus: { name:"Pro+",  monthly:18.50, annual:175,   features:["Everything in Pro","Multiple Engineers","Unlimited Everything","Priority Support"], excluded:[] },
  };
  const plan = PLANS[selectedPlan];
  const price = billingCycle==="monthly" ? plan.monthly : plan.annual;
  const priceLabel = billingCycle==="monthly" ? `\u00a3${price.toFixed(2)}/mo` : `\u00a3${price}/yr`;
  const [form, setForm] = useState({ accountName:"", sortCode:"", accountNumber:"", email:"" });

  useEffect(() => {
    if (document.getElementById("wlg-pulse-style")) return;
    const s = document.createElement("style");
    s.id = "wlg-pulse-style";
    s.textContent = "@keyframes wlgPulse{0%{box-shadow:0 0 0 0 rgba(211,47,47,0.8);background:#c62828;}60%{box-shadow:0 0 0 16px rgba(211,47,47,0);background:#d32f2f;}100%{box-shadow:0 0 0 0 rgba(211,47,47,0);background:#c62828;}}.wlg-pulse{animation:wlgPulse 1.1s ease-in-out infinite;color:#fff!important;}";
    document.head.appendChild(s);
  }, []);
  const [error, setError] = useState("");
  const [submitting, setSubmitting] = useState(false);
  const trialStatus = getTrialStatus();
  const profile = (() => { try { return JSON.parse(localStorage.getItem(sk("user_profile"))||"{}"); } catch { return {}; } })();

  const inp = (key, placeholder, type="text", maxLen) => (
    <input type={type} value={form[key]} placeholder={placeholder}
      onChange={e => { setForm(f=>({...f,[key]:e.target.value})); setError(""); }}
      maxLength={maxLen}
      style={{ width:"100%", padding:"13px 14px", border:"2px solid #ddd", borderRadius:10, fontSize:15, boxSizing:"border-box", fontFamily:"inherit", marginBottom:12, outline:"none" }}/>
  );

  async function handleSubmit() {
    if (!form.accountName.trim()) { setError("Please enter the account holder name."); return; }
    const sc = form.sortCode.replace(/[^0-9]/g,"");
    if (sc.length !== 6) { setError("Sort code must be 6 digits (e.g. 12-34-56)."); return; }
    const an = form.accountNumber.replace(/[^0-9]/g,"");
    if (an.length !== 8) { setError("Account number must be 8 digits."); return; }
    if (!form.email.trim() || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(form.email)) { setError("Please enter a valid email address for payment confirmation."); return; }

    setSubmitting(true);
    setError("");
    try {
      // Notify admin via EmailJS
      const payload = {
        service_id: EMAILJS_SERVICE_ID,
        template_id: EMAILJS_TEMPLATE_ID,
        user_id: EMAILJS_PUBLIC_KEY,
        template_params: {
          to_email: "westlothiangas@gmail.com",
          username: currentUser?.username || "",
          engineer_name: profile.engineerName || "",
          company_name: profile.companyName || "",
          gas_safe_no: profile.gasSafeNo || "",
          registered_at: profile.registeredAt ? new Date(profile.registeredAt).toLocaleDateString("en-GB") : "",
          // Payment details
          account_name: form.accountName,
          sort_code: form.sortCode.replace(/[^0-9]/g,"").replace(/(\d{2})(\d{2})(\d{2})/,"$1-$2-$3"),
          account_number: form.accountNumber.replace(/[^0-9]/g,""),
          contact_email: form.email,
          subject: "New Direct Debit Mandate — Gas Safety App",
          message: `New payment mandate submitted:\n\nUser: ${currentUser?.username}\nEngineer: ${profile.engineerName}\nCompany: ${profile.companyName}\nGas Safe No: ${profile.gasSafeNo}\nPlan: ${plan.name} (${billingCycle}) — ${priceLabel}\n\nBank Details:\nAccount Name: ${form.accountName}\nSort Code: ${form.sortCode.replace(/[^0-9]/g,"").replace(/(\d{2})(\d{2})(\d{2})/,"$1-$2-$3")}\nAccount Number: ${form.accountNumber.replace(/[^0-9]/g,"")}\nContact Email: ${form.email}\n\nPlease set up the Direct Debit and then run:\nunlockUser("${currentUser?.username}") in the user\'s browser console, or update their profile directly.`,
        }
      };
      const res = await fetch("https://api.emailjs.com/api/v1.0/email/send", { method:"POST", headers:{"Content-Type":"application/json"}, body:JSON.stringify(payload) });
      if (!res.ok) throw new Error("Email send failed");
    } catch(e) { console.warn("Email failed:", e); }

    markPaymentSubmitted({ accountName:form.accountName, sortCode:form.sortCode, accountNumber:form.accountNumber, email:form.email }, selectedPlan);
    // Also persist plan separately in case markPaymentSubmitted is called without selectedPlan elsewhere
    try { const p = JSON.parse(localStorage.getItem(sk("user_profile")) || "{}"); p.plan = selectedPlan; localStorage.setItem(sk("user_profile"), JSON.stringify(p)); if (isSupabaseEnabled()) pushProfile(p); } catch {}
    setSubmitting(false);
    setStep("done");
    if (onPaymentSubmitted) onPaymentSubmitted();
  }

  if (step === "done") return (
    <div style={{ minHeight:"100dvh", background:`linear-gradient(135deg,${DARK_BLUE},${BLUE})`, display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center", fontFamily:"'Segoe UI',sans-serif", padding:24 }}>
      <div style={{ background:"#fff", borderRadius:20, padding:"40px 28px", width:"100%", maxWidth:400, textAlign:"center", boxShadow:"0 20px 60px rgba(0,0,0,0.3)" }}>
        <div style={{ fontSize:56, marginBottom:16 }}>✅</div>
        <h2 style={{ fontSize:22, fontWeight:700, color:"#0d1f2d", margin:"0 0 12px" }}>Payment details received</h2>
        <p style={{ fontSize:14, color:"#555", lineHeight:1.7, margin:"0 0 24px" }}>
          Thank you! Your Direct Debit mandate details have been sent to us. We'll set up your {plan.name} ({priceLabel}) subscription and restore full access within 24 hours.
        </p>
        <p style={{ fontSize:13, color:"#888", margin:"0 0 24px" }}>If you have any questions email <strong>westlothiangas@gmail.com</strong></p>
        <button onClick={onLogout} style={{ width:"100%", padding:14, background:"#0d1f2d", color:"#fff200", border:"none", borderRadius:10, fontSize:15, fontWeight:700, cursor:"pointer", fontFamily:"inherit" }}>Sign Out</button>
      </div>
    </div>
  );

  if (step === "form") return (
    <div style={{ minHeight:"100dvh", background:`linear-gradient(135deg,${DARK_BLUE},${BLUE})`, display:"flex", flexDirection:"column", fontFamily:"'Segoe UI',sans-serif" }}>
      <div style={{ padding:"20px 20px 12px", display:"flex", alignItems:"center", gap:12 }}>
        <button onClick={()=>setStep("paywall")} style={{ background:"rgba(255,255,255,0.15)", border:"none", borderRadius:"50%", width:36, height:36, display:"flex", alignItems:"center", justifyContent:"center", cursor:"pointer", color:"#fff", fontSize:20 }}>‹</button>
        <div style={{ color:"#fff200", fontWeight:800, fontSize:18 }}>Set Up Direct Debit</div>
      </div>
      <div style={{ flex:1, overflowY:"auto", padding:"0 16px 88px" }}>
        <div style={{ background:"#fff", borderRadius:16, padding:24, marginBottom:14 }}>
          <div style={{ display:"flex", alignItems:"center", gap:12, marginBottom:20, padding:"12px 16px", background:"#f0f9f0", borderRadius:10, border:"1px solid #c3e6cb" }}>
            <div style={{ fontSize:28 }}>🔒</div>
            <div>
              <div style={{ fontWeight:700, fontSize:14, color:"#1a3a4a" }}>{plan.name} — {priceLabel}</div>
              <div style={{ fontSize:12, color:"#555", lineHeight:1.5 }}>Your bank details are sent directly to us to set up your Direct Debit. We never store card details.</div>
            </div>
          </div>
          <div style={{ fontWeight:700, fontSize:14, color:"#333", marginBottom:16 }}>Your bank account details</div>
          <div style={{ fontSize:12, color:"#888", marginBottom:6 }}>Account holder name</div>
          {inp("accountName","e.g. John Smith")}
          <div style={{ fontSize:12, color:"#888", marginBottom:6 }}>Sort code</div>
          {inp("sortCode","e.g. 12-34-56","text",8)}
          <div style={{ fontSize:12, color:"#888", marginBottom:6 }}>Account number</div>
          {inp("accountNumber","8-digit account number","text",8)}
          <div style={{ fontSize:12, color:"#888", marginBottom:6 }}>Your email (for payment confirmation)</div>
          {inp("email","your@email.com","email")}
          {error && <div style={{ color:"#d32f2f", fontSize:13, marginBottom:12 }}>{error}</div>}
          <p style={{ fontSize:11, color:"#999", lineHeight:1.6, marginBottom:16 }}>
            By submitting you authorise Gas Safety App to collect {priceLabel} by Direct Debit under the Direct Debit Guarantee. You can cancel at any time by contacting us.
          </p>
          {(()=>{ const ok = !!(form.accountName.trim() && form.sortCode.replace(/\D/g,"").length===6 && form.accountNumber.replace(/\D/g,"").length===8 && /\S+@\S+\.\S+/.test(form.email)); return (
            <button onClick={handleSubmit} disabled={submitting}
              className={ok&&!submitting?"wlg-pulse":""}
              style={{ width:"100%", padding:16, background:submitting?"#aaa":ok?"#c62828":"#0d1f2d", color:"#fff", border:"none", borderRadius:12, fontSize:16, fontWeight:700, cursor:submitting?"default":"pointer", fontFamily:"inherit", transition:"background 0.4s" }}>
              {submitting ? "Submitting…" : ok ? "✅ Submit Direct Debit Details →" : "Submit Direct Debit Details →"}
            </button>
          ); })()}
        </div>
        <div style={{ textAlign:"center" }}>
          <button onClick={onLogout} style={{ background:"none", border:"none", color:"rgba(255,255,255,0.5)", fontSize:13, cursor:"pointer", textDecoration:"underline" }}>Sign out instead</button>
        </div>
      </div>
    </div>
  );

  // Paywall / trial expired screen
  const isPending = trialStatus === "pending";
  const planCard = (key, badge) => {
    const p = PLANS[key];
    const amt = billingCycle==="monthly" ? p.monthly : p.annual;
    const cadence = billingCycle==="monthly" ? "/mo" : "/yr";
    const sel = selectedPlan===key;
    return (
      <div onClick={()=>setSelectedPlan(key)} style={{ flex:1, cursor:"pointer", border:sel?"2.5px solid #fff200":"2px solid rgba(255,255,255,0.2)", borderRadius:14, padding:"14px 10px", background:sel?"rgba(255,242,0,0.08)":"rgba(255,255,255,0.04)", transition:"all 0.2s", position:"relative", textAlign:"center" }}>
        {badge && <div style={{ position:"absolute", top:-10, left:"50%", transform:"translateX(-50%)", background:"#fff200", color:"#0d1f2d", fontSize:9, fontWeight:800, padding:"3px 10px", borderRadius:20, whiteSpace:"nowrap" }}>{badge}</div>}
        <div style={{ color:sel?"#fff200":"rgba(255,255,255,0.5)", fontSize:11, fontWeight:700, marginBottom:4, textTransform:"uppercase", letterSpacing:1 }}>{p.name}</div>
        <div style={{ color:"#fff", fontSize:22, fontWeight:900 }}>£{amt%1===0?amt:amt.toFixed(2)}</div>
        <div style={{ color:"rgba(255,255,255,0.5)", fontSize:11 }}>{cadence} + VAT</div>
      </div>
    );
  };
  return (
    <div style={{ minHeight:"100dvh", background:`linear-gradient(135deg,${DARK_BLUE},${BLUE})`, display:"flex", flexDirection:"column", fontFamily:"'Segoe UI',sans-serif" }}>
      <div style={{ padding:"20px 24px", display:"flex", alignItems:"center", justifyContent:"space-between" }}>
        <div style={{ display:"flex", alignItems:"center", gap:10 }}>
          <img src={APP_LOGO_SVG} style={{ height:28, objectFit:"contain" }} alt="Gas Safety App"/>
          <div style={{ color:"#fff200", fontWeight:700, fontSize:15 }}>Gas Safety App</div>
        </div>
        <button onClick={onLogout} style={{ background:"rgba(255,255,255,0.15)", border:"1px solid rgba(255,255,255,0.3)", borderRadius:8, padding:"6px 14px", color:"#fff", fontSize:12, fontWeight:600, cursor:"pointer" }}>Sign Out</button>
      </div>
      <div style={{ flex:1, overflowY:"auto", padding:"0 16px 32px" }}>
        {isPending ? (
          <div style={{ background:"#fff", borderRadius:20, padding:"36px 28px", maxWidth:400, margin:"0 auto", textAlign:"center", boxShadow:"0 20px 60px rgba(0,0,0,0.3)" }}>
            <div style={{ fontSize:48, marginBottom:12 }}>⏳</div>
            <h2 style={{ fontSize:22, fontWeight:700, color:"#0d1f2d", margin:"0 0 12px" }}>Awaiting approval</h2>
            <p style={{ fontSize:14, color:"#555", lineHeight:1.7, margin:"0 0 20px" }}>
              We've received your Direct Debit details. Your account will be fully unlocked within 24 hours once we've processed your setup. If you have any questions email <strong>westlothiangas@gmail.com</strong>
            </p>
            <button onClick={onLogout} style={{ background:"none", border:"none", color:"#999", fontSize:13, cursor:"pointer", textDecoration:"underline" }}>Sign out</button>
          </div>
        ) : (
          <div style={{ maxWidth:440, margin:"0 auto" }}>
            <div style={{ textAlign:"center", marginBottom:20 }}>
              <img src={APP_LOGO_SVG} style={{ height:48, objectFit:"contain", marginBottom:10 }} alt="Gas Safety App"/>
              <h2 style={{ fontSize:20, fontWeight:700, color:"#fff", margin:"0 0 6px" }}>Your free trial has ended</h2>
              <p style={{ fontSize:13, color:"rgba(255,255,255,0.7)", margin:0 }}>Choose a plan to continue</p>
            </div>

            {/* Billing toggle */}
            <div style={{ display:"flex", justifyContent:"center", gap:4, marginBottom:18, background:"rgba(255,255,255,0.1)", borderRadius:30, padding:3, maxWidth:240, margin:"0 auto 18px" }}>
              {["monthly","annual"].map(c => (
                <button key={c} onClick={()=>setBillingCycle(c)} style={{ flex:1, padding:"8px 0", border:"none", borderRadius:28, fontSize:12, fontWeight:700, cursor:"pointer", fontFamily:"inherit", background:billingCycle===c?"#fff200":"transparent", color:billingCycle===c?"#0d1f2d":"rgba(255,255,255,0.6)", transition:"all 0.2s" }}>
                  {c==="monthly"?"Monthly":"Annual"}
                </button>
              ))}
            </div>

            {/* Plan cards */}
            <div style={{ display:"flex", gap:8, marginBottom:18 }}>
              {planCard("lite")}
              {planCard("pro","Most Popular")}
              {planCard("proplus")}
            </div>

            {/* Selected plan features */}
            <div style={{ background:"#fff", borderRadius:16, padding:"18px 16px", marginBottom:16 }}>
              <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:12 }}>
                <span style={{ fontSize:15, fontWeight:700, color:"#0d1f2d" }}>{plan.name}</span>
                <span style={{ fontSize:18, fontWeight:900, color:"#0d1f2d" }}>{priceLabel}</span>
              </div>
              {plan.features.map((f,i) => (
                <div key={i} style={{ fontSize:13, color:"#333", marginBottom:5, display:"flex", gap:8 }}>
                  <span style={{ color:"#1a3a4a", fontWeight:700 }}>✓</span>{f}
                </div>
              ))}
              {plan.excluded.map((f,i) => (
                <div key={"x"+i} style={{ fontSize:13, color:"#bbb", marginBottom:5, display:"flex", gap:8 }}>
                  <span style={{ fontWeight:700 }}>–</span>{f}
                </div>
              ))}
            </div>

            <button onClick={()=>{ const stripeKey = `${selectedPlan}_${billingCycle}`; try { const pk = sk("user_profile"); const pp = JSON.parse(localStorage.getItem(pk)||"{}"); pp.plan = selectedPlan; pp.paymentPending = true; localStorage.setItem(pk, JSON.stringify(pp)); } catch {} window.open(getStripeLink(stripeKey), '_blank'); }}
              style={{ width:"100%", padding:16, background:"#fff200", color:"#0d1f2d", border:"none", borderRadius:12, fontSize:16, fontWeight:700, cursor:"pointer", fontFamily:"inherit", marginBottom:12, display:"flex", alignItems:"center", justifyContent:"center", gap:8 }}>
              <span style={{ fontSize:20 }}>💳</span> Subscribe Now — {priceLabel}
            </button>

            <div style={{ display:"flex", alignItems:"center", gap:12, marginBottom:12 }}>
              <div style={{ flex:1, height:1, background:"rgba(255,255,255,0.2)" }}/>
              <span style={{ color:"rgba(255,255,255,0.5)", fontSize:12, fontWeight:600 }}>or</span>
              <div style={{ flex:1, height:1, background:"rgba(255,255,255,0.2)" }}/>
            </div>

            <button onClick={()=>setStep("form")}
              style={{ width:"100%", padding:12, background:"rgba(255,255,255,0.1)", color:"rgba(255,255,255,0.7)", border:"1px solid rgba(255,255,255,0.2)", borderRadius:10, fontSize:13, fontWeight:600, cursor:"pointer", fontFamily:"inherit", marginBottom:12 }}>
              Set Up Direct Debit Instead →
            </button>
            <div style={{ textAlign:"center" }}>
              <button onClick={onLogout} style={{ background:"none", border:"none", color:"rgba(255,255,255,0.5)", fontSize:13, cursor:"pointer", textDecoration:"underline" }}>Sign out</button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
