// ─── CLIENT CONTACTS ──────────────────────────────────────────────────────────

function ClientContactsScreen({ onBack, onHome }) {
  const [contacts, setContacts] = useState(() => {
    try { return JSON.parse(localStorage.getItem(sk("client_contacts")) || "[]"); }
    catch { return []; }
  });
  const [tab, setTab] = useState("list"); // "list" | "import"
  const [parseError, setParseError] = useState("");
  const [importCount, setImportCount] = useState(null);
  const [search, setSearch] = useState("");

  function saveContacts(updated) {
    setContacts(updated);
    try { localStorage.setItem(sk("client_contacts"), JSON.stringify(updated)); } catch {}
  }

  // Parse a Google Contacts CSV export
  function parseGoogleCSV(text) {
    const lines = text.split(/\r?\n/).filter(Boolean);
    if (lines.length < 2) return [];
    const headers = lines[0].split(",").map(h => h.replace(/^"|"$/g,"").trim());
    const parsed = [];
    for (let i = 1; i < lines.length; i++) {
      // Handle quoted fields with commas inside
      const row = [];
      let cur = "", inQ = false;
      for (const ch of lines[i]) {
        if (ch === "\"" ) { inQ = !inQ; }
        else if (ch === "," && !inQ) { row.push(cur.trim()); cur = ""; }
        else { cur += ch; }
      }
      row.push(cur.trim());
      const obj = {};
      headers.forEach((h, j) => { obj[h] = (row[j] || "").replace(/^"|"$/g,""); });
      // Map Google Contacts fields
      const name = obj["Name"] || [obj["Given Name"], obj["Family Name"]].filter(Boolean).join(" ");
      const phone = obj["Phone 1 - Value"] || obj["Mobile Phone"] || obj["Phone"] || "";
      const email = obj["E-mail 1 - Value"] || obj["Email"] || obj["E-mail Address"] || "";
      const company = obj["Organization Name"] || obj["Company"] || "";
      const addr = [obj["Address 1 - Street"], obj["Address 1 - City"], obj["Address 1 - Postcode"]].filter(Boolean).join(", ");
      if (name || phone || email) {
        parsed.push({ id: Date.now() + Math.random(), name, phone, email, company, addr });
      }
    }
    return parsed;
  }

  // Decode quoted-printable encoded text (RFC 2045)
  function decodeQP(str) {
    if (!str) return str;
    // Join soft line breaks (= at end of line, possibly followed by \r\n or \n)
    let s = str.replace(/=\r?\n/g, "");
    // Decode =XX hex sequences
    s = s.replace(/=([0-9A-Fa-f]{2})/g, (_, hex) => {
      try { return decodeURIComponent("%" + hex); } catch { return ""; }
    });
    return s;
  }

  // Parse a vCard (.vcf) file
  function parseVCF(text) {
    // First, unfold quoted-printable soft line breaks across the whole card text
    // vCards sometimes fold QP lines with =\r\n or =\n
    const unfoldedText = text.replace(/=\r?\n[ \t]?/g, "").replace(/\r?\n[ \t]/g, " ");
    const cards = unfoldedText.split("BEGIN:VCARD").slice(1);
    return cards.map(card => {
      const get = (field) => {
        // Match field name (possibly with params like ;TYPE=HOME) then colon then value to end of line
        const m = card.match(new RegExp(field + "[^:]*:([^\r\n]+)", "i"));
        if (!m) return "";
        const val = m[1].trim();
        // Always decode quoted-printable — some exporters don't include ENCODING param
        return decodeQP(val);
      };
      const fnVal = get("FN");
      const nameVal = get("N");
      let name = fnVal;
      if (!name && nameVal) {
        const parts = nameVal.split(";");
        name = [parts[1], parts[0]].filter(Boolean).join(" ");
      }
      const phone = get("TEL");
      const email = get("EMAIL");
      const org = get("ORG");
      // vCard ADR structure: PO Box;Extended;Street;City;Region;Postcode;Country
      const rawAdr = get("ADR");
      const adrParts = rawAdr.split(";").map(p => p.trim());
      // Positional extraction: [0]=PO Box, [1]=Extended, [2]=Street, [3]=City, [4]=Region, [5]=Postcode, [6]=Country
      const street = adrParts[2] || "";
      const city = adrParts[3] || "";
      const region = adrParts[4] || "";
      const postcode = adrParts[5] || "";
      // Build a readable address from non-empty parts (Street, City, Region, Postcode)
      const adr = [street, city, region, postcode].filter(Boolean).join(", ");
      if (name || phone || email) {
        return { id: Date.now() + Math.random(), name, phone, email, company: org, addr: adr, postcode };
      }
      return null;
    }).filter(Boolean);
  }

  // Chunked async VCF parser — processes cards in batches to avoid blocking the UI thread.
  // Calls onProgress(done, total) after each chunk, onDone(parsedArray) when complete.
  function parseVCFAsync(text, onProgress, onDone) {
    // First, unfold quoted-printable soft line breaks across the whole card text
    const unfoldedText = text.replace(/=\r?\n[ \t]?/g, "").replace(/\r?\n[ \t]/g, " ");
    const rawCards = unfoldedText.split("BEGIN:VCARD").slice(1);
    const total = rawCards.length;
    const CHUNK = 100;
    let idx = 0;
    const results = [];
    function processChunk() {
      const end = Math.min(idx + CHUNK, total);
      for (; idx < end; idx++) {
        const card = rawCards[idx];
        const get = (field) => {
          const m = card.match(new RegExp(field + "[^:]*:([^\r\n]+)", "i"));
          if (!m) return "";
          const val = m[1].trim();
          // Always decode quoted-printable — some exporters don't include ENCODING param
          return decodeQP(val);
        };
        const fnVal = get("FN");
        const nameVal = get("N");
        let name = fnVal;
        if (!name && nameVal) {
          const parts = nameVal.split(";");
          name = [parts[1], parts[0]].filter(Boolean).join(" ");
        }
        const phone = get("TEL");
        const email = get("EMAIL");
        const org = get("ORG");
        // vCard ADR structure: PO Box;Extended;Street;City;Region;Postcode;Country
        const rawAdr = get("ADR");
        const adrParts = rawAdr.split(";").map(p => p.trim());
        // Positional extraction: [0]=PO Box, [1]=Extended, [2]=Street, [3]=City, [4]=Region, [5]=Postcode, [6]=Country
        const street = adrParts[2] || "";
        const city = adrParts[3] || "";
        const region = adrParts[4] || "";
        const postcode = adrParts[5] || "";
        const adr = [street, city, region, postcode].filter(Boolean).join(", ");
        if (name || phone || email) {
          results.push({ id: Date.now() + Math.random(), name, phone, email, company: org, addr: adr, postcode });
        }
      }
      onProgress(idx, total);
      if (idx < total) {
        setTimeout(processChunk, 0); // yield to browser between chunks
      } else {
        onDone(results);
      }
    }
    setTimeout(processChunk, 0);
  }

  function handleFile(e) {
    const file = e.target.files?.[0];
    if (!file) return;
    setParseError("");
    setImportCount(null);
    const reader = new FileReader();
    reader.onload = ev => {
      const text = ev.target.result;
      if (file.name.toLowerCase().endsWith(".vcf")) {
        // Use chunked async parser to avoid blocking the UI on large VCF files (1,000+ contacts)
        setParseError("Importing contacts… please wait");
        parseVCFAsync(text,
          (done, total) => { setParseError(`Importing contacts… ${done} of ${total}`); },
          (parsed) => {
            setParseError("");
            if (!parsed.length) { setParseError("No contacts found in the file. Please check it is a valid vCard export."); return; }
            const existing = contacts;
            const newOnes = parsed.filter(p => !existing.some(ex =>
              (p.phone && ex.phone && p.phone === ex.phone) ||
              (p.email && ex.email && p.email === ex.email)
            ));
            const merged = [...existing, ...newOnes];
            saveContacts(merged);
            setImportCount(newOnes.length);
            setTab("list");
          }
        );
      } else if (file.name.toLowerCase().endsWith(".csv")) {
        const parsed = parseGoogleCSV(text);
        if (!parsed.length) { setParseError("No contacts found in the file. Please check it is a valid export."); return; }
        const existing = contacts;
        const newOnes = parsed.filter(p => !existing.some(ex =>
          (p.phone && ex.phone && p.phone === ex.phone) ||
          (p.email && ex.email && p.email === ex.email)
        ));
        const merged = [...existing, ...newOnes];
        saveContacts(merged);
        setImportCount(newOnes.length);
        setTab("list");
      } else {
        setParseError("Please upload a .csv (Google Contacts) or .vcf file.");
      }
    };
    reader.readAsText(file);
  }

  const filtered = contacts.filter(c => {
    const q = search.toLowerCase();
    return !q || c.name?.toLowerCase().includes(q) || c.phone?.includes(q) || c.company?.toLowerCase().includes(q);
  });

  const sec = (t, icon) => (
    <div style={{ display:"flex", alignItems:"center", gap:8, fontWeight:700, fontSize:14, color:"#1a3a4a",
      borderBottom:"2px solid #1a3a4a30", paddingBottom:6, marginBottom:12, marginTop:4 }}>
      <span style={{ fontSize:18 }}>{icon}</span>{t}
    </div>
  );

  const ImportTab = () => (
    <div style={{ padding:16, paddingBottom:80 }}>
      {/* Step-by-step guide */}
      <div style={{ background:"#fff", borderRadius:12, padding:16, marginBottom:14, boxShadow:"0 1px 4px rgba(0,0,0,0.06)" }}>
        {sec("How to import your contacts", "📱")}
        <div style={{ fontSize:13, color:"#444", lineHeight:1.7 }}>
          Follow these steps to export your business contacts from your phone and import them here.
        </div>

        {/* Step 1 */}
        <div style={{ marginTop:16, marginBottom:12 }}>
          <div style={{ fontWeight:700, fontSize:13, color:"#0d1f2d", marginBottom:6, display:"flex", alignItems:"center", gap:8 }}>
            <span style={{ background:"#1a3a4a", color:"#fff200", borderRadius:"50%", width:22, height:22, display:"inline-flex", alignItems:"center", justifyContent:"center", fontSize:12, fontWeight:800, flexShrink:0 }}>1</span>
            Export from your iPhone (iOS)
          </div>
          <div style={{ fontSize:13, color:"#555", lineHeight:1.7, paddingLeft:30 }}>
            Open <strong>Contacts</strong> app → tap your name at the top → tap <strong>Contacts on iCloud.com</strong> → on the iCloud website, select the contacts you want → click the gear icon ⚙️ → <strong>Export vCard</strong> → save the .vcf file → upload it below.
          </div>
        </div>

        {/* Step 2 */}
        <div style={{ marginBottom:12 }}>
          <div style={{ fontWeight:700, fontSize:13, color:"#0d1f2d", marginBottom:6, display:"flex", alignItems:"center", gap:8 }}>
            <span style={{ background:"#1a3a4a", color:"#fff200", borderRadius:"50%", width:22, height:22, display:"inline-flex", alignItems:"center", justifyContent:"center", fontSize:12, fontWeight:800, flexShrink:0 }}>2</span>
            Export from Android
          </div>
          <div style={{ fontSize:13, color:"#555", lineHeight:1.7, paddingLeft:30 }}>
            Open <strong>Contacts</strong> app → tap the <strong>three-dot menu</strong> → <strong>Import/Export</strong> → <strong>Export to .vcf file</strong> → save it → upload it below.
          </div>
        </div>

        {/* Step 3 */}
        <div style={{ marginBottom:4 }}>
          <div style={{ fontWeight:700, fontSize:13, color:"#0d1f2d", marginBottom:6, display:"flex", alignItems:"center", gap:8 }}>
            <span style={{ background:"#1a3a4a", color:"#fff200", borderRadius:"50%", width:22, height:22, display:"inline-flex", alignItems:"center", justifyContent:"center", fontSize:12, fontWeight:800, flexShrink:0 }}>3</span>
            Export from Google Contacts (any phone)
          </div>
          <div style={{ fontSize:13, color:"#555", lineHeight:1.7, paddingLeft:30 }}>
            On your computer go to <strong style={{ color:"#1a3a4a" }}>contacts.google.com</strong> → on the left sidebar tap <strong>Export</strong> → choose <strong>Google CSV</strong> or <strong>vCard (for iOS Contacts)</strong> → click Export → upload the file below.
          </div>
        </div>
      </div>

      {/* Upload area */}
      <div style={{ background:"#fff", borderRadius:12, padding:16, marginBottom:14, boxShadow:"0 1px 4px rgba(0,0,0,0.06)" }}>
        {sec("Upload your contacts file", "📂")}
        <div style={{ fontSize:13, color:"#888", marginBottom:12, lineHeight:1.6 }}>
          Supported formats: <strong>.vcf</strong> (vCard — from iPhone, Android or Google) or <strong>.csv</strong> (Google Contacts export).
        </div>
        <label style={{ display:"block", border:"2.5px dashed #1a3a4a", borderRadius:12, padding:"28px 20px",
          textAlign:"center", cursor:"pointer", background:"#f0f9f4", marginBottom:12 }}>
          <div style={{ fontSize:36, marginBottom:8 }}>📤</div>
          <div style={{ fontWeight:700, fontSize:15, color:"#1a3a4a", marginBottom:4 }}>Tap to choose file</div>
          <div style={{ fontSize:12, color:"#888" }}>.vcf or .csv — from iPhone, Android or Google Contacts</div>
          <input type="file" accept=".vcf,.csv" onChange={handleFile} style={{ display:"none" }}/>
        </label>
        {parseError && (
          <div style={{ background:"#fdecea", border:"1px solid #f5c6c6", borderRadius:8, padding:"10px 14px",
            color:"#d32f2f", fontSize:13, marginBottom:8 }}>{parseError}</div>
        )}
        {importCount !== null && (
          <div style={{ background:"#f0f9f0", border:"1px solid #c3e6cb", borderRadius:8, padding:"10px 14px",
            color:"#1a3a4a", fontSize:13, fontWeight:600 }}>
            ✅ {importCount > 0 ? `${importCount} new contact${importCount!==1?"s":""} imported!` : "All contacts already in your list — no duplicates added."}
          </div>
        )}
      </div>
    </div>
  );

  const ListTab = () => (
    <div style={{ padding:16, paddingBottom:80 }}>
      {importCount !== null && (
        <div style={{ background:"#f0f9f0", border:"1px solid #c3e6cb", borderRadius:8, padding:"10px 14px",
          color:"#1a3a4a", fontSize:13, fontWeight:600, marginBottom:12 }}>
          ✅ {importCount} new contact{importCount!==1?"s":""} imported successfully!
        </div>
      )}
      {contacts.length === 0 ? (
        <div style={{ textAlign:"center", marginTop:60 }}>
          <div style={{ fontSize:52, marginBottom:14 }}>👥</div>
          <div style={{ fontWeight:700, fontSize:17, color:"#222", marginBottom:8 }}>No contacts yet</div>
          <div style={{ fontSize:14, color:"#888", marginBottom:20, lineHeight:1.6 }}>
            Import your business contacts from your phone to quickly fill in client details on certificates and invoices.
          </div>
          <button onClick={()=>setTab("import")}
            style={{ padding:"13px 28px", background:"#1a3a4a", color:"#fff200", border:"none", borderRadius:12,
              fontSize:15, fontWeight:700, cursor:"pointer", fontFamily:"inherit" }}>
            📤 Import Contacts
          </button>
        </div>
      ) : (
        <>
          <div style={{ display:"flex", gap:8, marginBottom:14, alignItems:"center" }}>
            <input value={search} onChange={e=>setSearch(e.target.value)}
              placeholder="🔍  Search contacts..."
              style={{ flex:1, padding:"11px 14px", border:"2px solid #1a3a4a30", borderRadius:10,
                fontSize:14, outline:"none", fontFamily:"inherit" }}/>
            <button onClick={()=>setTab("import")}
              style={{ padding:"11px 14px", background:"#1a3a4a", color:"#fff200", border:"none",
                borderRadius:10, fontSize:13, fontWeight:700, cursor:"pointer", fontFamily:"inherit", whiteSpace:"nowrap" }}>
              + Import
            </button>
          </div>
          <div style={{ fontSize:12, color:"#888", marginBottom:10 }}>
            {filtered.length} of {contacts.length} contact{contacts.length!==1?"s":""}
          </div>
          {filtered.map((c, i) => (
            <div key={c.id||i} style={{ background:"#fff", borderRadius:10, padding:"12px 14px", marginBottom:8,
              boxShadow:"0 1px 4px rgba(0,0,0,0.06)", borderLeft:"4px solid #1a3a4a" }}>
              <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start" }}>
                <div style={{ flex:1 }}>
                  <div style={{ fontWeight:700, fontSize:15, color:"#222" }}>{c.name||"—"}</div>
                  {c.company && <div style={{ fontSize:12, color:"#1a3a4a", fontWeight:600, marginTop:1 }}>{c.company}</div>}
                  {c.phone && (
                    <a href={"tel:"+c.phone.replace(/\s/g,"")} style={{ fontSize:13, color:"#444", marginTop:3, display:"block", textDecoration:"none" }}>
                      📞 {c.phone}
                    </a>
                  )}
                  {c.email && <div style={{ fontSize:12, color:"#888", marginTop:1 }}>{c.email}</div>}
                  {c.addr && <div style={{ fontSize:11, color:"#aaa", marginTop:2 }}>{c.addr}</div>}
                </div>
                <button onClick={()=>{ const updated = contacts.filter((_,j)=>j!==contacts.indexOf(c)); saveContacts(updated); }}
                  style={{ background:"none", border:"none", color:"#e0e0e0", fontSize:18, cursor:"pointer",
                    padding:"2px 4px", lineHeight:1, flexShrink:0, marginLeft:8 }}>×</button>
              </div>
            </div>
          ))}
        </>
      )}
    </div>
  );

  return (
    <div style={{ display:"flex", flexDirection:"column", height:"100dvh", background:LIGHT_BG, fontFamily:"'Segoe UI',sans-serif" }}>
      <Header title="👥 Client Contacts" onBack={onBack} onHome={onHome}/>
      {/* Tab bar */}
      <div style={{ display:"flex", borderBottom:"2px solid #e8eee8", background:"#fff" }}>
        {[["list","📋 My Contacts"], ["import","📤 Import"]].map(([key, label]) => (
          <button key={key} onClick={()=>setTab(key)}
            style={{ flex:1, padding:"12px 8px", border:"none", background:"none", cursor:"pointer",
              fontWeight:700, fontSize:14, fontFamily:"inherit",
              color: tab===key ? "#1a3a4a" : "#999",
              borderBottom: tab===key ? "3px solid #1a3a4a" : "3px solid transparent",
              marginBottom:-2, transition:"all 0.15s" }}>
            {label}
          </button>
        ))}
      </div>
      <div style={{ flex:1, overflowY:"auto" }}>
        {tab === "import" ? <ImportTab/> : <ListTab/>}
      </div>
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════════
// ADMIN DASHBOARD — View all engineers, certs, search, audit trail
// Only accessible to admin user. Fetches data from Supabase via admin API.
// ═══════════════════════════════════════════════════════════════════════════════
function AdminDashboardScreen({ onBack, onHome, records, invoices, quotes }) {
  const [tab, setTab] = useState("overview");
  const [search, setSearch] = useState("");

  // Local data stats (from localStorage — always available even without Supabase)
  const now = new Date();
  const thisMonth = (records || []).filter(r => !r.isDemo && r.savedAt && new Date(r.savedAt).getMonth() === now.getMonth() && new Date(r.savedAt).getFullYear() === now.getFullYear());
  const allReal = (records || []).filter(r => !r.isDemo);
  const allInv = (invoices || []).filter(r => !r.isDemo);
  const allQt = (quotes || []).filter(r => !r.isDemo);

  // Group certs by type
  const certsByType = {};
  allReal.forEach(r => {
    const t = r.certType || r.type || "unknown";
    certsByType[t] = (certsByType[t] || 0) + 1;
  });

  // Search filter
  const filtered = search.trim()
    ? allReal.filter(r => {
        const s = search.toLowerCase();
        return (
          (r.clientName || "").toLowerCase().includes(s) ||
          (r.instAddr1 || "").toLowerCase().includes(s) ||
          (r.instAddr2 || "").toLowerCase().includes(s) ||
          (r.instPostcode || "").toLowerCase().includes(s) ||
          (r.fileRef || r.fileReference || "").toLowerCase().includes(s)
        );
      })
    : allReal;

  const cardStyle = { background: "#fff", borderRadius: 14, padding: "16px 18px", boxShadow: "0 2px 8px rgba(0,0,0,0.06)", marginBottom: 12 };
  const statBox = { background: "#f8fafc", borderRadius: 10, padding: "12px 14px", textAlign: "center", flex: 1, minWidth: 80 };

  return (
    <div style={{ minHeight: "100dvh", background: "#f1f5f9", fontFamily: "'Segoe UI',sans-serif" }}>
      {/* Header */}
      <div style={{ background: "#0d1f2d", padding: "16px 20px", display: "flex", alignItems: "center", gap: 12 }}>
        <button onClick={onBack} style={{ background: "rgba(255,255,255,0.15)", border: "none", borderRadius: 8, padding: "6px 12px", color: "#fff", fontSize: 14, cursor: "pointer" }}>← Back</button>
        <div style={{ flex: 1 }}>
          <div style={{ color: "#ef4444", fontWeight: 800, fontSize: 16 }}>Admin Dashboard</div>
          <div style={{ color: "rgba(255,255,255,0.6)", fontSize: 11 }}>Gas Safety App</div>
        </div>
        <button onClick={onHome} style={{ background: "rgba(255,255,255,0.1)", border: "none", borderRadius: 8, padding: "6px 12px", color: "#fff", fontSize: 12, cursor: "pointer" }}>🏠 Home</button>
      </div>

      {/* Tab bar */}
      <div style={{ display: "flex", background: "#fff", borderBottom: "1px solid #e5e7eb", padding: "0 12px" }}>
        {["overview", "certificates", "search"].map(t => (
          <button key={t} onClick={() => setTab(t)}
            style={{ flex: 1, padding: "12px 8px", border: "none", background: "none", fontWeight: tab === t ? 800 : 500, fontSize: 13, color: tab === t ? "#0d1f2d" : "#94a3b8", borderBottom: tab === t ? "3px solid #ef4444" : "3px solid transparent", cursor: "pointer", textTransform: "capitalize" }}>
            {t}
          </button>
        ))}
      </div>

      <div style={{ padding: "16px 16px 80px" }}>
        {/* OVERVIEW TAB */}
        {tab === "overview" && (
          <>
            <div style={{ display: "flex", gap: 10, marginBottom: 16 }}>
              <div style={statBox}>
                <div style={{ fontSize: 28, fontWeight: 900, color: "#0d1f2d" }}>{allReal.length}</div>
                <div style={{ fontSize: 11, color: "#94a3b8", fontWeight: 600 }}>Total Certs</div>
              </div>
              <div style={statBox}>
                <div style={{ fontSize: 28, fontWeight: 900, color: "#2563eb" }}>{thisMonth.length}</div>
                <div style={{ fontSize: 11, color: "#94a3b8", fontWeight: 600 }}>This Month</div>
              </div>
              <div style={statBox}>
                <div style={{ fontSize: 28, fontWeight: 900, color: "#059669" }}>{allInv.length}</div>
                <div style={{ fontSize: 11, color: "#94a3b8", fontWeight: 600 }}>Invoices</div>
              </div>
              <div style={statBox}>
                <div style={{ fontSize: 28, fontWeight: 900, color: "#d97706" }}>{allQt.length}</div>
                <div style={{ fontSize: 11, color: "#94a3b8", fontWeight: 600 }}>Quotes</div>
              </div>
            </div>

            {/* Cert type breakdown */}
            <div style={cardStyle}>
              <div style={{ fontWeight: 700, fontSize: 14, marginBottom: 10, color: "#0d1f2d" }}>Certificates by Type</div>
              {Object.entries(certsByType).sort((a,b) => b[1] - a[1]).map(([type, count]) => (
                <div key={type} style={{ display: "flex", justifyContent: "space-between", padding: "6px 0", borderBottom: "1px solid #f1f5f9", fontSize: 13 }}>
                  <span style={{ color: "#475569", textTransform: "uppercase", fontWeight: 600, letterSpacing: 0.3 }}>{type}</span>
                  <span style={{ fontWeight: 700, color: "#0d1f2d" }}>{count}</span>
                </div>
              ))}
              {Object.keys(certsByType).length === 0 && <div style={{ color: "#94a3b8", fontSize: 13 }}>No certificates yet</div>}
            </div>

            {/* Recent activity */}
            <div style={cardStyle}>
              <div style={{ fontWeight: 700, fontSize: 14, marginBottom: 10, color: "#0d1f2d" }}>Recent Certificates</div>
              {allReal.slice(0, 10).map((r, i) => (
                <div key={i} style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "8px 0", borderBottom: "1px solid #f1f5f9" }}>
                  <div>
                    <div style={{ fontSize: 13, fontWeight: 600, color: "#0d1f2d" }}>{r.clientName || "Unnamed"}</div>
                    <div style={{ fontSize: 11, color: "#94a3b8" }}>{r.instAddr1 || ""}{r.instPostcode ? `, ${r.instPostcode}` : ""}</div>
                  </div>
                  <div style={{ textAlign: "right" }}>
                    <div style={{ fontSize: 11, fontWeight: 700, color: "#2563eb", textTransform: "uppercase" }}>{r.certType || r.type || "cert"}</div>
                    <div style={{ fontSize: 10, color: "#94a3b8" }}>{r.savedAt ? new Date(r.savedAt).toLocaleDateString("en-GB") : ""}</div>
                  </div>
                </div>
              ))}
              {allReal.length === 0 && <div style={{ color: "#94a3b8", fontSize: 13 }}>No certificates yet</div>}
            </div>
          </>
        )}

        {/* CERTIFICATES TAB */}
        {tab === "certificates" && (
          <div style={cardStyle}>
            <div style={{ fontWeight: 700, fontSize: 14, marginBottom: 10, color: "#0d1f2d" }}>All Certificates ({allReal.length})</div>
            {allReal.map((r, i) => (
              <div key={i} style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "10px 0", borderBottom: "1px solid #f1f5f9" }}>
                <div style={{ flex: 1, minWidth: 0 }}>
                  <div style={{ fontSize: 13, fontWeight: 600, color: "#0d1f2d", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{r.fileRef || r.fileReference || `Cert #${i+1}`}</div>
                  <div style={{ fontSize: 12, color: "#475569" }}>{r.clientName || ""}</div>
                  <div style={{ fontSize: 11, color: "#94a3b8" }}>{r.instAddr1 || ""}{r.instPostcode ? `, ${r.instPostcode}` : ""}</div>
                </div>
                <div style={{ textAlign: "right", flexShrink: 0 }}>
                  <div style={{ fontSize: 11, fontWeight: 700, color: "#2563eb", textTransform: "uppercase", background: "#eff6ff", padding: "2px 8px", borderRadius: 4 }}>{r.certType || r.type || "cert"}</div>
                  <div style={{ fontSize: 10, color: "#94a3b8", marginTop: 4 }}>{r.savedAt ? new Date(r.savedAt).toLocaleDateString("en-GB") : ""}</div>
                </div>
              </div>
            ))}
            {allReal.length === 0 && <div style={{ color: "#94a3b8", fontSize: 13, padding: 16, textAlign: "center" }}>No certificates yet</div>}
          </div>
        )}

        {/* SEARCH TAB */}
        {tab === "search" && (
          <>
            <div style={{ marginBottom: 12 }}>
              <input value={search} onChange={e => setSearch(e.target.value)}
                placeholder="Search by name, address, postcode, or file ref..."
                style={{ width: "100%", padding: "12px 16px", borderRadius: 10, border: "1.5px solid #e5e7eb", fontSize: 14, fontFamily: "inherit", outline: "none", boxSizing: "border-box" }}/>
            </div>
            <div style={cardStyle}>
              <div style={{ fontWeight: 700, fontSize: 14, marginBottom: 10, color: "#0d1f2d" }}>
                {search.trim() ? `${filtered.length} result${filtered.length !== 1 ? "s" : ""}` : "Enter a search term"}
              </div>
              {filtered.slice(0, 50).map((r, i) => (
                <div key={i} style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "10px 0", borderBottom: "1px solid #f1f5f9" }}>
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={{ fontSize: 13, fontWeight: 600, color: "#0d1f2d" }}>{r.clientName || "Unnamed"}</div>
                    <div style={{ fontSize: 12, color: "#475569" }}>{r.instAddr1 || ""}{r.instAddr2 ? `, ${r.instAddr2}` : ""}</div>
                    <div style={{ fontSize: 11, color: "#94a3b8" }}>{r.instPostcode || ""} · {r.fileRef || r.fileReference || ""}</div>
                  </div>
                  <div style={{ textAlign: "right", flexShrink: 0 }}>
                    <div style={{ fontSize: 11, fontWeight: 700, color: "#2563eb", textTransform: "uppercase" }}>{r.certType || r.type || "cert"}</div>
                    <div style={{ fontSize: 10, color: "#94a3b8" }}>{r.savedAt ? new Date(r.savedAt).toLocaleDateString("en-GB") : ""}</div>
                  </div>
                </div>
              ))}
              {search.trim() && filtered.length === 0 && <div style={{ color: "#94a3b8", fontSize: 13, padding: 16, textAlign: "center" }}>No matching certificates</div>}
            </div>
          </>
        )}
      </div>
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════════
// ─── PROPERTY SAFETY CHECK (PSC) ─────────────────────────────────────────────
// Based on IGEM/G/11 Edition 2 with Amendments (July 2025)
// ═══════════════════════════════════════════════════════════════════════════════

