// ─── PDF ──────────────────────────────────────────────────────────────────────

function LPGPDF({ formData, engineerData, onClose, onSave, autoDownload, onDownloadDone, onCombineCapture }) {
  const certRef = useRef(null);
  const serviceRef = useRef(null);
  const [downloading, setDownloading] = useState(false);
  const [saved, setSaved] = useState(false);
  const autoDownloadDoneRef = useRef(null);
  useEffect(() => {
    if (onCombineCapture) { onCombineCapture(certRef, "landscape"); return; }
    if (autoDownload && !autoDownloadDoneRef.current) {
      autoDownloadDoneRef.current = true;
      setTimeout(() => { downloadPDF().then(() => { if (onDownloadDone) onDownloadDone(); }); }, 600);
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const fd = formData || {};
  // Auto-populate dates — fall back to today if blank
  const today = new Date().toISOString().slice(0,10);
  const effSigDate = fd.sigDate || today;
  const effCustDate = fd.sigCustomerDate || fd.sigDate || today;
  const effEngDate = fd.sigEngDate || fd.sigDate || today;
  const effCliDate = fd.sigClientDate || today;

  const eng = engineerData || {};
  const apps = fd.appliances || [];
  const faults = fd.faults || [];

  const fmtDate = (iso) => {
    if (!iso) return "";
    const d = new Date(iso);
    if (isNaN(d)) return iso;
    const days = ["Sun","Mon","Tue","Wed","Thu","Fri","Sat"];
    const months = ["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"];
    return days[d.getDay()] + "-" + String(d.getDate()).padStart(2,"0") + "-" + months[d.getMonth()] + "-" + d.getFullYear();
  };

  const downloadPDF = async () => {
    setDownloading(true);
    try {
      await Promise.all([
        new Promise((res,rej)=>{ if(window.html2canvas) return res(); const s=document.createElement("script"); s.src="https://cdnjs.cloudflare.com/ajax/libs/html2canvas/1.4.1/html2canvas.min.js"; s.onload=res; s.onerror=rej; document.head.appendChild(s); }),
        new Promise((res,rej)=>{ if(window.jspdf) return res(); const s=document.createElement("script"); s.src="https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.5.1/jspdf.umd.min.js"; s.onload=res; s.onerror=rej; document.head.appendChild(s); }),
      ]);
      const el = certRef.current;
      const W = 1200;
      const prev = {w:el.style.width,max:el.style.maxWidth,min:el.style.minWidth};
      el.style.width=W+"px"; el.style.maxWidth=W+"px"; el.style.minWidth=W+"px";
      await new Promise(r=>setTimeout(r,300));
      const canvas = await window.html2canvas(el, { scale:2, useCORS:true, logging:false, width:W, height:el.scrollHeight, windowWidth:W, scrollX:0, scrollY:0 });
      el.style.width=prev.w; el.style.maxWidth=prev.max; el.style.minWidth=prev.min;
      const { jsPDF } = window.jspdf;
      const pdf = new jsPDF({ orientation:"landscape", unit:"mm", format:"a4" });
      const pdfW=297;
      pdf.addImage(canvas.toDataURL("image/jpeg",0.95),"JPEG",0,0,pdfW,pdfW*canvas.height/canvas.width);
      const ref = (fd.certRef||fd.certNo||"LPG").replace(/[^a-zA-Z0-9]/g,"_");
      await appendAttachmentPages(pdf, fd.attachments, "landscape");
      pdf.save("LPGSafetyRecord_"+ref+".pdf");
    } catch(e) { alert("PDF error: "+e.message); }
    setDownloading(false);
  };

  const b = "1px solid #aaa";
  const S = { borderCollapse:"collapse", width:"100%" };
  const c = (w, extra) => Object.assign({ border:b, padding:"2px 3px", fontSize:"6.5px", verticalAlign:"middle", lineHeight:1.2, width:w||"auto" }, extra||{});
  const cHdr = (extra) => Object.assign(c("auto"), { background:"#2d3748", color:"#fff", fontWeight:700, padding:"3px 4px", fontSize:"7px" }, extra||{});
  const cVal = (extra) => Object.assign(c("auto"), { background:"#f5f5f5", textAlign:"center", fontWeight:600 }, extra||{});
  const cRot = (w, label) => (
    <th style={{ border:b, width:w, padding:"2px 1px", verticalAlign:"bottom", background:"#2d3748" }}>
      <div style={{ writingMode:"vertical-rl", transform:"rotate(180deg)", fontSize:"6px", color:"#fff", fontWeight:700, padding:"2px 1px", whiteSpace:"nowrap", height:60, display:"flex", alignItems:"center" }}>{label}</div>
    </th>
  );

  const filledApps = Array(5).fill(null).map((_,i) => apps[i]||{});
  const filledFaults = Array(5).fill(null).map((_,i) => faults[i]||{});

  return (
    <div style={{ position:"fixed", inset:0, background:"#0d1f2d", zIndex:2000, overflowY:"auto", fontFamily:"Arial,Helvetica,sans-serif" }}>
      <div style={{ background:"#0d1f2d", padding:"10px 16px", display:"flex", alignItems:"center", gap:12, position:"sticky", top:0, zIndex:10 }}>
        <button onClick={onClose} style={{ background:"rgba(255,255,255,0.2)", border:"none", borderRadius:"50%", width:36, height:36, cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center" }}>
          <svg width="18" height="18" viewBox="0 0 18 18" fill="none"><path d="M11 3L5 9L11 15" stroke="white" strokeWidth="2.2" strokeLinecap="round"/></svg>
        </button>
        <span style={{ color:"#fff", fontWeight:700, fontSize:15, flex:1 }}>LPG Safety Record — Preview</span>
        <button onClick={()=>{ if(!saved){ onSave(); setSaved(true); } }} disabled={saved}
          style={{ background:saved?"#555":"rgba(255,255,255,0.2)", border:"2px solid rgba(255,255,255,0.6)", borderRadius:8, padding:"6px 14px", color:"#fff", fontWeight:700, fontSize:13, cursor:saved?"default":"pointer", marginRight:8 }}>
          {saved?"✓ Saved":"Save"}
        </button>
        <button onClick={downloadPDF} disabled={downloading}
          style={{ background:"#fff200", border:"none", borderRadius:8, padding:"6px 14px", color:"#111", fontWeight:700, fontSize:13, cursor:"pointer", opacity:downloading?0.7:1 }}>
          {downloading?"Generating...":"PDF (Landscape)"}
        </button>
      </div>

      <div style={{ padding:"12px", display:"flex", justifyContent:"center" }}>
        <div ref={certRef} style={{ width:"100%", maxWidth:1200, background:"#fff", fontFamily:"Arial,Helvetica,sans-serif", fontSize:"6.5px", lineHeight:1.2, padding:0, boxShadow:"0 4px 20px rgba(0,0,0,0.3)" }}>

          {/* TITLE */}
          <table style={S}>
            <tbody>
              <tr>
                <td style={{ padding:"6px 10px", verticalAlign:"middle", width:"12%", border:b }}>
                  <img src={GSR_LOGO} style={{ height:36, objectFit:"contain" }} alt="Gas Safe"/>
                </td>
                <td style={{ textAlign:"center", verticalAlign:"middle", padding:"4px 8px", border:b }}>
                  <div style={{ fontWeight:900, fontSize:"16px" }}>{fd._titleOverride||"Liquid Petroleum Gas Safety Record"}</div>
                  <div style={{ fontSize:"7px", color:"#555", marginTop:3 }}>Safety inspection and reporting carried out in accordance with Gas Safety (Installation and Use) Regulations and the Gas Industry Unsafe Situations Procedure.</div>
                  <div style={{ fontSize:"7px", color:"#555" }}>Unless stated otherwise, no detailed internal inspection of flues (Integrity, Construction and Lining) has been carried out.</div>
                </td>
                <td style={{ width:"16%", padding:"4px 6px", verticalAlign:"top", border:b }}>
                  <div style={{ fontSize:"6px", color:"#888" }}>Certificate Reference</div>
                  <div style={{ fontWeight:700, fontSize:"8px", marginBottom:4 }}>{fd.certRef||""}</div>
                  <div style={{ fontSize:"6px", color:"#888" }}>Certificate No:</div>
                  <div style={{ fontWeight:700, fontSize:"8px" }}>{fd.certNo||""}</div>
                </td>
              </tr>
            </tbody>
          </table>

          {/* ENGINEERS / INSTALLATION / CLIENT */}
          <table style={S}>
            <tbody>
              <tr>
                <td style={{ width:"33.3%", border:b, verticalAlign:"top", padding:0 }}>
                  <table style={S}>
                    <tbody>
                      <tr><td style={cHdr()} colSpan={2}>Engineers Details</td></tr>
                      <tr><td style={c("30%")}>Trading Title</td><td style={c()}>{fd.tradingTitle||eng.companyName||""}</td></tr>
                      <tr><td style={c("25%")} rowSpan={2}>Address</td><td style={c()}>{fd.engAddr||eng.companyAddr||""}</td></tr>
                      <tr><td style={c()}>{fd.engCity||""}</td></tr>
                      <tr><td style={{ ...c("100%"), textAlign:"right" }} colSpan={2}>Post Code: {fd.engPostcode||eng.companyPostcode||""}</td></tr>
                      <tr><td style={c("30%")}>Gas Safe No:</td><td style={c()}>{fd.gasSafeNo||eng.gasSafeNo||""}</td></tr>
                      <tr><td style={c("40%")}>Telephone No:</td><td style={c()}>{fd.engTel||eng.companyTel||""}</td></tr>
                    </tbody>
                  </table>
                </td>
                <td style={{ width:"33.3%", border:b, verticalAlign:"top", padding:0 }}>
                  <table style={S}>
                    <tbody>
                      <tr><td style={cHdr()} colSpan={2}>Installation Details</td></tr>
                      <tr><td style={c("35%")} rowSpan={2}>Installation Address</td><td style={c()}>{fd.instAddr||""}</td></tr>
                      <tr><td style={c()}>{fd.instCity||""}</td></tr>
                      <tr><td style={{ ...c("100%"), textAlign:"right" }} colSpan={2}>Post Code: {fd.instPostcode||""}</td></tr>
                      <tr><td style={c("40%")}>Telephone No:</td><td style={c()}>{fd.instTel||""}</td></tr>
                    </tbody>
                  </table>
                </td>
                <td style={{ width:"33.3%", border:b, verticalAlign:"top", padding:0 }}>
                  <table style={S}>
                    <tbody>
                      <tr><td style={cHdr()} colSpan={2}>Client Details</td></tr>
                      <tr><td style={c("25%")} rowSpan={2}>Client Address</td><td style={c()}>{fd.clientAddr||""}</td></tr>
                      <tr><td style={c()}>{fd.clientCity||""}</td></tr>
                      <tr><td style={{ ...c("100%"), textAlign:"right" }} colSpan={2}>Post Code: {fd.clientPostcode||""}</td></tr>
                      <tr><td style={c("40%")}>Telephone No:</td><td style={c()}>{fd.clientTel||""}</td></tr>
                    </tbody>
                  </table>
                </td>
              </tr>
            </tbody>
          </table>

          {/* APPLIANCE TABLE with rotated headers */}
          <table style={S}>
            <thead>
              <tr>
                <th style={{ ...cHdr(), textAlign:"center", width:"3%" }} rowSpan={2}></th>
                <th style={{ ...cHdr(), width:"9%" }}>Location</th>
                <th style={{ ...cHdr(), width:"9%" }}>Appliance Type</th>
                <th style={{ ...cHdr(), width:"8%" }}>Make</th>
                <th style={{ ...cHdr(), width:"8%" }}>Model</th>
                {cRot("4%","CO₂ Reading")}
                {cRot("4%","CO Reading")}
                {cRot("4%","Flue Type (OF/RS/FL)")}
                {cRot("4%","Appliance Inspected (YES/NO/NA)")}
                {cRot("5%","Combustion Analysis Reading (CO/CO₂)")}
                {cRot("5%","Operating Pressure (mbar)")}
                {cRot("4%","Landlord's Appliance (YES/NO/NA)")}
                {cRot("4%","Heat Input (kw)")}
                {cRot("5%","Safety Device(s) Correct Operation (YES/NO/NA)")}
                {cRot("4%","Ventilation Provision Satisfactory (YES/NO)")}
                {cRot("5%","Visual Condition of Flue and Termination Satisfactory (YES/NO/NA)")}
                {cRot("5%","Flue Performance(Test) (Pass/Fail/NA)")}
                {cRot("4%","Appliance Serviced (YES/NO/NA)")}
                {cRot("4%","Appliance Safe To Use (YES/NO)")}
              </tr>
            </thead>
            <tbody>
              {filledApps.map((app,i)=>(
                <tr key={i}>
                  <td style={c("3%",{textAlign:"center",fontWeight:700})}>{i+1}</td>
                  <td style={c("9%")}>{app.location||""}</td>
                  <td style={c("9%")}>{app.type||""}</td>
                  <td style={c("8%")}>{app.make||""}</td>
                  <td style={c("8%")}>{app.model||""}</td>
                  <td style={cVal({width:"4%"})}>{app.co2Reading||""}</td>
                  <td style={cVal({width:"4%"})}>{app.coReading||""}</td>
                  <td style={cVal({width:"4%"})}>{app.flueType||""}</td>
                  <td style={cVal({width:"4%"})}>{app.applianceInspected||""}</td>
                  <td style={cVal({width:"5%"})}>{app.combustionReading||""}</td>
                  <td style={cVal({width:"5%"})}>{app.opPressure||""}</td>
                  <td style={cVal({width:"4%"})}>{app.landlordsAppliance||""}</td>
                  <td style={cVal({width:"4%"})}>{app.heatInput||""}</td>
                  <td style={cVal({width:"5%"})}>{app.safetyDevices||""}</td>
                  <td style={cVal({width:"4%"})}>{app.ventilation||""}</td>
                  <td style={cVal({width:"5%"})}>{app.flueCondition||""}</td>
                  <td style={cVal({width:"5%",color:app.fluePerformance==="PASS"?"#166534":app.fluePerformance==="FAIL"?"#991b1b":"#333"})}>{app.fluePerformance||""}</td>
                  <td style={cVal({width:"4%"})}>{app.applianceServiced||""}</td>
                  <td style={cVal({width:"4%"})}>{app.safeToUse||""}</td>
                </tr>
              ))}
            </tbody>
          </table>

          {/* FAULTS / REMEDIAL / WARNING */}
          <table style={S}>
            <thead>
              <tr>
                <th style={cHdr({width:"3%"})}></th>
                <th style={cHdr({width:"40%"})}>Faults/Notes</th>
                <th style={cHdr({width:"40%"})}>Remedial Work Taken</th>
                <th style={cHdr({width:"17%",textAlign:"center"})}>Warning Notice Fixed</th>
              </tr>
            </thead>
            <tbody>
              {filledFaults.map((f,i)=>(
                <tr key={i}>
                  <td style={c("3%",{textAlign:"center",fontWeight:700})}>{i+1}</td>
                  <td style={c("40%")}>{f.fault||""}</td>
                  <td style={c("40%")}>{f.remedial||""}</td>
                  <td style={cVal({width:"17%"})}>{f.warningFixed||""}</td>
                </tr>
              ))}
            </tbody>
          </table>

          {/* BOTTOM: LPG Checks + Signatures */}
          <table style={S}>
            <tbody>
              <tr style={{ verticalAlign:"top" }}>
                {/* Left: LPG checks */}
                <td style={{ width:"35%", border:b, padding:"3px 5px", verticalAlign:"top" }}>
                  {[
                    ["Gas Tightness Test:", fd.gasTightness],
                    ["Gas Installation Pipework Visual Inspection satisfactory:", fd.pipeworkInspection],
                  ].map(([label,val],i)=>(
                    <div key={i} style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:3, fontSize:"6.5px" }}>
                      <span>{label}</span>
                      <span style={{ border:b, padding:"1px 6px", minWidth:30, textAlign:"center", fontWeight:700, background:"#f5f5f5" }}>{val||""}</span>
                    </div>
                  ))}
                  <div style={{ display:"flex", gap:12, fontSize:"6.5px", marginBottom:3 }}>
                    <span>Regulator Lock up Pressure: <strong style={{ border:b, padding:"1px 5px", background:"#f5f5f5" }}>{fd.regulatorLockup||""}</strong></span>
                  </div>
                  <div style={{ display:"flex", gap:12, fontSize:"6.5px", marginBottom:3 }}>
                    <span>Regulator Operating Pressure: <strong style={{ border:b, padding:"1px 5px", background:"#f5f5f5" }}>{fd.regulatorOperating||""}</strong></span>
                  </div>
                  <div style={{ display:"flex", gap:16, fontSize:"6.5px", marginBottom:3 }}>
                    <span>Hose(s) Check: <strong style={{ border:b, padding:"1px 6px", background:"#f5f5f5" }}>{fd.hosesCheck||""}</strong></span>
                    <span>ECV Check: <strong style={{ border:b, padding:"1px 6px", background:"#f5f5f5" }}>{fd.ecvCheck||""}</strong></span>
                  </div>
                  <div style={{ fontSize:"6.5px" }}>
                    NEXT INSPECTION DUE ON OR BEFORE: <strong>{fmtDate(fd.nextInspection)||""}</strong>
                  </div>
                </td>

                {/* Middle: Signatures */}
                <td style={{ width:"50%", border:b, padding:"3px 5px", verticalAlign:"top" }}>
                  <div style={{ fontWeight:700, fontSize:"7px", marginBottom:4, background:"#2d3748", color:"#fff", padding:"2px 4px" }}>Signatures</div>
                  <div style={{ marginBottom:6 }}>
                    <div style={{ fontSize:"6.5px", fontWeight:700, marginBottom:2 }}>Report Issued By:</div>
                    <div style={{ display:"flex", gap:8, alignItems:"center", flexWrap:"wrap" }}>
                      <span style={{ fontSize:"6.5px" }}>Name: <strong>{fd.sigEngineerName||eng.engineerName||""}</strong></span>
                      {fd.sigEngineerImg ? <img src={fd.sigEngineerImg} style={{ height:22, maxWidth:100, verticalAlign:"middle" }} alt="sig"/> : <span style={{ borderBottom:"1px solid #999", minWidth:70, display:"inline-block" }}>&nbsp;</span>}
                      <span style={{ fontSize:"6.5px" }}>Date: <strong>{fmtDate(effSigDate)||""}</strong></span>
                    </div>
                  </div>
                  <div>
                    <div style={{ fontSize:"6.5px", fontWeight:700, marginBottom:2 }}>Report Received By:</div>
                    <div style={{ display:"flex", gap:8, alignItems:"center", flexWrap:"wrap" }}>
                      <span style={{ fontSize:"6.5px" }}>Name: <strong>{fd.sigCustomerName||""}</strong></span>
                      {fd.sigCustomerImg ? <img src={fd.sigCustomerImg} style={{ height:22, maxWidth:100, verticalAlign:"middle" }} alt="sig"/> : <span style={{ borderBottom:"1px solid #999", minWidth:70, display:"inline-block" }}>&nbsp;</span>}
                      <span style={{ fontSize:"6.5px" }}>Date: <strong>{fmtDate(effCustDate)||""}</strong></span>
                    </div>
                  </div>
                </td>

                {/* Right: Gas ID */}
                <td style={{ width:"15%", border:b, padding:"3px 5px", verticalAlign:"middle", textAlign:"center" }}>
                  <div style={{ fontSize:"6.5px", fontWeight:700, marginBottom:4 }}>Gas ID Number:</div>
                  <div style={{ fontSize:"11px", fontWeight:900 }}>{fd.gasId||eng.gasId||""}</div>
                </td>
              </tr>
            </tbody>
          </table>

          {/* FOOTER */}
          <div style={{ textAlign:"center", fontSize:"6px", color:"#666", padding:"2px 8px", borderTop:b }}>
            This Gas Safety Report was created by {eng.companyName||""}{eng.gasSafeNo?" | Gas Safe Reg: "+eng.gasSafeNo:""}{eng.companyTel?" | Tel: "+eng.companyTel:""}
          </div>

        </div>
      </div>
    </div>
  );
}

// ─── ORCHESTRATOR ─────────────────────────────────────────────────────────────

function LPGScreen({ engineerData, onBack, onHome, onSave, initialData }) {
  const [step, setStep] = useState("fileRef");
  const [showPDF, setShowPDF] = useState(false);
  const today = new Date().toISOString().slice(0,10);
  const eng = engineerData || {};

  const [data, setData] = useState({
    certRef:"", certNo:"",
    tradingTitle:eng.companyName||"", engAddr:eng.companyAddr||"", engCity:"",
    engPostcode:eng.companyPostcode||"", gasSafeNo:eng.gasSafeNo||"",
    engTel:eng.companyTel||"", gasId:eng.gasId||"",
    instAddr:"", instCity:"", instPostcode:"", instTel:"",
    clientAddr:"", clientCity:"", clientPostcode:"", clientTel:"",
    appliances: Array(5).fill(null).map(()=>({})),
    faults: Array(5).fill(null).map(()=>({})),
    gasTightness:"", pipeworkInspection:"",
    regulatorLockup:"", regulatorOperating:"",
    hosesCheck:"", ecvCheck:"", nextInspection:"",
    sigEngineerName:eng.engineerName||"", sigDate:today,
    sigCustomerName:"", sigCustomerDate:today,
    sigEngineerImg:null, sigCustomerImg:null,
    ...(initialData||{}),
  });

  if (showPDF) return <LPGPDF
    formData={data} engineerData={engineerData}
    onClose={()=>setShowPDF(false)}
    onSave={()=>{ onSave({ type:"lpg_gsc", certLabel:"Liquified Petroleum Gas Safety Record", form:data, engineerData, savedAt:new Date().toISOString() }); alert("Certificate saved to Records!"); }}/>;

  const steps = {
    fileRef:     <LPGStepFileRef     data={data} onChange={setData} onBack={onBack}                     onHome={onHome} onNext={()=>setStep("details")} title="LPG Safety Record"/>,
    details:     <LPGStepDetails     data={data} onChange={setData} onBack={()=>setStep("fileRef")}     onHome={onHome} onNext={()=>setStep("appliances")}/>,
    appliances:  <LPGStepAppliances  data={data} onChange={setData} onBack={()=>setStep("details")}    onHome={onHome} onNext={()=>setStep("faults")}/>,
    faults:      <LPGStepFaults      data={data} onChange={setData} onBack={()=>setStep("appliances")} onHome={onHome} onNext={()=>setStep("attachments")}/>,
    attachments: <AttachmentsStep     data={data} onChange={setData} onBack={()=>setStep("faults")}     onHome={onHome} onNext={()=>setStep("declaration")} accentColor={LPG_COLOR} nextLabel="Next: Declaration"/>,
    declaration: <LPGStepDeclaration data={data} onChange={setData} onBack={()=>setStep("attachments")}     onHome={onHome} onNext={()=>setStep("customerSig")}/>,
    customerSig: <CustomerSigStep     data={data} onChange={setData} onBack={()=>setStep("declaration")} onHome={onHome} onNext={()=>setShowPDF(true)} accentColor={LPG_COLOR}/>,
  };
  return steps[step] || null;
}

// ─── 7 DAY COOLING OFF PERIOD EXEMPTION ──────────────────────────────────────

const COOL_COLOR = "#0891b2";

function CoolOffStepFileRef({ data, onChange, onNext, onBack, onHome }) {
  const inp = { width:"100%", boxSizing:"border-box", padding:"13px 15px", border:"1px solid #2a4058", borderRadius:10, background:"#1e3044", color:"#e8edf2", fontSize:15, fontFamily:"'Segoe UI',sans-serif", outline:"none", marginBottom:12 };
  return (
    <div style={{ display:"flex", flexDirection:"column", height:"100dvh", background:LIGHT_BG, fontFamily:"'Segoe UI',sans-serif" }}>
      <Header title="7 Day Cooling Off Period Exemption" onBack={onBack} onHome={onHome}/>
      <div style={{ flex:1, display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center", padding:24, paddingBottom:80 }}>
        <p style={{ color:"rgba(255,255,255,0.5)", fontSize:14, marginBottom:20, textAlign:"center" }}>Enter a reference and certificate number</p>
        <input value={data.fileRef} onChange={e=>onChange({...data,fileRef:e.target.value})} placeholder="Reference" style={inp}/>
        <input value={data.certNo} onChange={e=>onChange({...data,certNo:e.target.value})} placeholder="Certificate No" style={inp}/>
      </div>
      <BottomBar onHome={onHome} onNext={onNext}/>
    </div>
  );
}

function CoolOffStepDetails({ data, onChange, onNext, onBack, onHome }) {
  const [_pickerCoolOffStepDetails, _setPickerCoolOffStepDetails] = useState(null); // "client"|"inst"|null
  const _handlePickCoolOffStepDetails = (target, c) => {
    const f = contactToFields(c);
    if (target === "client") onChange({...data, clientName:f.name||data.clientName||'', clientAddr1:f.addr1||data.clientAddr1||'', clientAddr2:f.addr2||data.clientAddr2||'', clientAddr3:f.addr3||data.clientAddr3||'', clientPostcode:f.postcode||data.clientPostcode||'', clientTel:f.phone||data.clientTel||'', clientEmail:f.email||data.clientEmail||''});
    else onChange({...data, instName:f.name||data.instName||'', instAddr1:f.addr1||data.instAddr1||'', instAddr2:f.addr2||data.instAddr2||'', instAddr3:f.addr3||data.instAddr3||'', instPostcode:f.postcode||data.instPostcode||'', instTel:f.phone||data.instTel||''});
    _setPickerCoolOffStepDetails(null);
  };
  const copyClientToInst = () => onChange({...data, instName:data.clientName||"", instAddr1:data.clientAddr1||"", instAddr2:data.clientAddr2||"", instAddr3:data.clientAddr3||"", instPostcode:data.clientPostcode||"", instTel:data.clientTel||""});
  const ContactBtn = ({target}) => <button onClick={()=>_setPickerCoolOffStepDetails(target)} style={{display:"flex",alignItems:"center",gap:6,background:"rgba(59,130,246,0.15)",border:"1px solid rgba(59,130,246,0.4)",borderRadius:20,padding:"6px 14px",color:"#3b82f6",fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:"'Segoe UI',sans-serif"}}>Add Contact</button>;
  const CopyBtn = () => <button onClick={copyClientToInst} style={{background:"rgba(34,197,94,0.12)",border:"1px solid rgba(34,197,94,0.4)",borderRadius:20,padding:"6px 14px",color:"#22c55e",fontSize:12,fontWeight:700,cursor:"pointer",display:"flex",alignItems:"center",gap:5,fontFamily:"inherit"}}>Copy</button>;
  return (
    <div style={{ display:"flex", flexDirection:"column", height:"100dvh", background:LIGHT_BG, fontFamily:"'Segoe UI',sans-serif" }}>
      <Header title="Engineers, Client & Installation Details" onBack={onBack}/>
      <div style={{ flex:1, overflowY:"auto" }}>
        <SectionHeader title="Engineers Details"/>
        <FormInput label="Trading Title / Company Name" placeholder="Company name" value={data.engCompany||""} onChange={v=>onChange({...data,engCompany:v})}/>
        <FormInput label="Address" placeholder="Address" value={data.engAddr1||""} onChange={v=>onChange({...data,engAddr1:v})}/>
        <FormInput label="Town / City" placeholder="Town or city" value={data.engAddr2||""} onChange={v=>onChange({...data,engAddr2:v})}/>
        <FormInput label="Post Code" placeholder="Postcode" value={data.engPostcode||""} onChange={v=>onChange({...data,engPostcode:v})}/>
        <FormInput label="Gas Safe No" placeholder="Gas Safe registration number" value={data.gasSafeNo||""} onChange={v=>onChange({...data,gasSafeNo:v})}/>
        <FormInput label="Telephone No" placeholder="Telephone" value={data.engTel||""} onChange={v=>onChange({...data,engTel:v})}/>
        <FormInput label="Engineer Name" placeholder="Engineer name" value={data.engName||""} onChange={v=>onChange({...data,engName:v})}/>
        <FormInput label="Gas ID Number (Engineer ID)" placeholder="Engineer ID card number" value={data.gasId||""} onChange={v=>onChange({...data,gasId:v})}/>
        <SectionHeader title="Client Details" actions={[<ContactBtn key="cp" target="client"/>]}/>
        <FormInput placeholder="Name" value={data.clientName||""} onChange={v=>onChange({...data,clientName:v})}/>
        <FormInput placeholder="Address line 1" value={data.clientAddr1||""} onChange={v=>onChange({...data,clientAddr1:v})}/>
        <FormInput placeholder="Address line 2" value={data.clientAddr2||""} onChange={v=>onChange({...data,clientAddr2:v})}/>
        <FormInput placeholder="Address line 3" value={data.clientAddr3||""} onChange={v=>onChange({...data,clientAddr3:v})}/>
        <FormInput placeholder="Postcode" value={data.clientPostcode||""} onChange={v=>onChange({...data,clientPostcode:v})}/>
        <FormInput placeholder="Telephone" value={data.clientTel||""} onChange={v=>onChange({...data,clientTel:v})}/>
        <FormInput placeholder="Email" value={data.clientEmail||""} onChange={v=>onChange({...data,clientEmail:v})}/>
        <SectionHeader title="Installation Details" actions={[<CopyBtn key="copy"/>, <ContactBtn key="cp" target="inst"/>]}/>
        <FormInput placeholder="Name" value={data.instName||""} onChange={v=>onChange({...data,instName:v})}/>
        <FormInput placeholder="Address line 1" value={data.instAddr1||""} onChange={v=>onChange({...data,instAddr1:v})}/>
        <FormInput placeholder="Address line 2" value={data.instAddr2||""} onChange={v=>onChange({...data,instAddr2:v})}/>
        <FormInput placeholder="Address line 3" value={data.instAddr3||""} onChange={v=>onChange({...data,instAddr3:v})}/>
        <FormInput placeholder="Postcode" value={data.instPostcode||""} onChange={v=>onChange({...data,instPostcode:v})}/>
        <FormInput placeholder="Telephone" value={data.instTel||""} onChange={v=>onChange({...data,instTel:v})}/>
        <div style={{ height:20 }}/>
      </div>
      <BottomBar onHome={onHome} onNext={onNext}/>
      {_pickerCoolOffStepDetails && <ContactPickerModal
        title={_pickerCoolOffStepDetails==="client" ? "Choose Client" : _pickerCoolOffStepDetails==="inst" ? "Choose Installation" : "Choose Contact"}
        onSelect={c=>_handlePickCoolOffStepDetails(_pickerCoolOffStepDetails,c)}
        onClose={()=>_setPickerCoolOffStepDetails(null)}/>}
    </div>
  );
}

function CoolOffStepEngineering({ data, onChange, onNext, onBack, onHome }) {
  const inp = { width:"100%", boxSizing:"border-box", padding:"11px 13px", border:"1px solid #ddd", borderRadius:8, fontSize:14, fontFamily:"'Segoe UI',sans-serif", outline:"none", marginBottom:2 };
  const lbl = (t) => <div style={{ fontSize:12, fontWeight:600, color:"#555", marginBottom:4, marginTop:10 }}>{t}</div>;
  const sec = (t) => <div style={{ fontWeight:700, fontSize:14, color:COOL_COLOR, borderBottom:`2px solid ${COOL_COLOR}30`, paddingBottom:6, marginBottom:4, marginTop:14 }}>{t}</div>;
  return (
    <div style={{ display:"flex", flexDirection:"column", height:"100dvh", background:LIGHT_BG, fontFamily:"'Segoe UI',sans-serif" }}>
      <Header title="Engineering Details & Signatures" onBack={onBack} onHome={onHome}/>
      <div style={{ flex:1, overflowY:"auto", padding:16, paddingBottom:80 }}>
        <div style={{ background:"rgba(255,255,255,0.04)", borderRadius:12, padding:16, marginBottom:12, border:"1px solid rgba(255,255,255,0.08)" }}>
          {sec("Engineering Details")}
          {lbl("Trading Title / Company Name")}<input value={data.tradingTitle} onChange={e=>onChange({...data,tradingTitle:e.target.value})} placeholder="Company name" style={inp}/>
          {lbl("Address")}<input value={data.engAddr} onChange={e=>onChange({...data,engAddr:e.target.value})} placeholder="Street address" style={inp}/>
          {lbl("Town / City")}<input value={data.engCity} onChange={e=>onChange({...data,engCity:e.target.value})} placeholder="Town or city" style={inp}/>
          {lbl("Post Code")}<input value={data.engPostcode} onChange={e=>onChange({...data,engPostcode:e.target.value})} placeholder="Postcode" style={inp}/>
          {lbl("Gas Safe No")}<input value={data.gasSafeNo} onChange={e=>onChange({...data,gasSafeNo:e.target.value})} placeholder="Gas Safe Registration No" style={inp}/>
          {lbl("Tel No")}<input value={data.engTel} onChange={e=>onChange({...data,engTel:e.target.value})} placeholder="Telephone" style={inp}/>
        </div>
        <div style={{ background:"rgba(255,255,255,0.04)", borderRadius:12, padding:16, marginBottom:12, border:"1px solid rgba(255,255,255,0.08)" }}>
          {sec("Engineer's Signature")}
          {lbl("Draw engineer signature")}
          <SigPad value={data.sigEngineerImg} storageKey="gsc_engineer_sig" onChange={v=>onChange({...data,sigEngineerImg:v})}/>
          {lbl("Printed name")}<input value={data.sigEngineer||""} onChange={e=>onChange({...data,sigEngineer:e.target.value})} placeholder="Engineer full name" style={inp}/>
          {lbl("Date")}<input type="date" value={data.sigEngDate||(()=>{if(!data.sigEngDate){const t=new Date().toISOString().slice(0,10);return t;}return "";})()}
            onChange={e=>onChange({...data,sigEngDate:e.target.value})} style={inp}/>
          {data.sigEngDate && <div style={{ fontSize:12, color:"#888", marginTop:4 }}>{(()=>{ const d=new Date(data.sigEngDate); if(isNaN(d)) return data.sigEngDate; const m=["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"]; return String(d.getDate()).padStart(2,"0")+"-"+m[d.getMonth()]+"-"+d.getFullYear(); })()}</div>}
        </div>

      </div>
      <BottomBar onHome={onHome} onNext={()=>onNext()} nextLabel="Preview PDF"/>
    </div>
  );
}

// ─── PDF ──────────────────────────────────────────────────────────────────────

function CoolOffPDF({ formData, engineerData, onClose, onSave, autoDownload, onDownloadDone, onCombineCapture }) {
  const certRef = useRef(null);
  const [downloading, setDownloading] = useState(false);
  const [saved, setSaved] = useState(false);
  const autoDownloadDoneRef = useRef(null);
  useEffect(() => {
    if (onCombineCapture) { onCombineCapture(certRef, "portrait"); return; }
    if (autoDownload && !autoDownloadDoneRef.current) {
      autoDownloadDoneRef.current = true;
      setTimeout(() => { downloadPDF().then(() => { if (onDownloadDone) onDownloadDone(); }); }, 600);
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const fd = formData || {};
  // Auto-populate dates — fall back to today if blank
  const today = new Date().toISOString().slice(0,10);
  const effSigDate = fd.sigDate || today;
  const effCustDate = fd.sigCustomerDate || fd.sigDate || today;
  const effEngDate = fd.sigEngDate || fd.sigDate || today;
  const effCliDate = fd.sigClientDate || today;

  const eng = engineerData || {};

  const fmtDate = (iso) => {
    if (!iso) return "";
    const d = new Date(iso);
    if (isNaN(d)) return iso;
    const months = ["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"];
    return String(d.getDate()).padStart(2,"0") + "-" + months[d.getMonth()] + "-" + d.getFullYear();
  };

  const downloadPDF = async () => {
    setDownloading(true);
    try {
      await Promise.all([
        new Promise((res,rej)=>{ if(window.html2canvas) return res(); const s=document.createElement("script"); s.src="https://cdnjs.cloudflare.com/ajax/libs/html2canvas/1.4.1/html2canvas.min.js"; s.onload=res; s.onerror=rej; document.head.appendChild(s); }),
        new Promise((res,rej)=>{ if(window.jspdf) return res(); const s=document.createElement("script"); s.src="https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.5.1/jspdf.umd.min.js"; s.onload=res; s.onerror=rej; document.head.appendChild(s); }),
      ]);
      const el = certRef.current;
      const W = 900;
      const prev = {w:el.style.width,max:el.style.maxWidth,min:el.style.minWidth};
      el.style.width=W+"px"; el.style.maxWidth=W+"px"; el.style.minWidth=W+"px";
      await new Promise(r=>setTimeout(r,300));
      const canvas = await window.html2canvas(el, { scale:2, useCORS:true, logging:false, width:W, height:el.scrollHeight, windowWidth:W, scrollX:0, scrollY:0 });
      el.style.width=prev.w; el.style.maxWidth=prev.max; el.style.minWidth=prev.min;
      const { jsPDF } = window.jspdf;
      const pdf = new jsPDF({ orientation:"portrait", unit:"mm", format:"a4" });
      const pdfW=210;
      pdf.addImage(canvas.toDataURL("image/jpeg",0.95),"JPEG",0,0,pdfW,pdfW*canvas.height/canvas.width);
      const ref = (fd.fileRef||fd.certNo||"COOL").replace(/[^a-zA-Z0-9]/g,"_");
      await appendAttachmentPages(pdf, fd.attachments, "portrait");
      pdf.save("CoolingOff_"+ref+".pdf");
    } catch(e) { alert("PDF error: "+e.message); }
    setDownloading(false);
  };

  const b = "1px solid #999";
  const bLight = "1px solid #ccc";
  const S = { borderCollapse:"collapse", width:"100%" };

  return (
    <div style={{ position:"fixed", inset:0, background:"#0d1f2d", zIndex:2000, overflowY:"auto", fontFamily:"Arial,Helvetica,sans-serif" }}>
      {/* Toolbar */}
      <div style={{ background:"#0d1f2d", padding:"10px 16px", display:"flex", alignItems:"center", gap:12, position:"sticky", top:0, zIndex:10 }}>
        <button onClick={onClose} style={{ background:"rgba(255,255,255,0.2)", border:"none", borderRadius:"50%", width:36, height:36, cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center" }}>
          <svg width="18" height="18" viewBox="0 0 18 18" fill="none"><path d="M11 3L5 9L11 15" stroke="white" strokeWidth="2.2" strokeLinecap="round"/></svg>
        </button>
        <span style={{ color:"#fff", fontWeight:700, fontSize:15, flex:1 }}>7 Day Cooling Off Period Exemption — Preview</span>
        <button onClick={()=>{ if(!saved){ onSave(); setSaved(true); } }} disabled={saved}
          style={{ background:saved?"#555":"rgba(255,255,255,0.2)", border:"2px solid rgba(255,255,255,0.6)", borderRadius:8, padding:"6px 14px", color:"#fff", fontWeight:700, fontSize:13, cursor:saved?"default":"pointer", marginRight:8 }}>
          {saved?"✓ Saved":"Save"}
        </button>
        <button onClick={downloadPDF} disabled={downloading}
          style={{ background:"#fff200", border:"none", borderRadius:8, padding:"6px 14px", color:"#111", fontWeight:700, fontSize:13, cursor:"pointer", opacity:downloading?0.7:1 }}>
          {downloading?"Generating...":"PDF"}
        </button>
      </div>

      <div style={{ padding:"12px", display:"flex", justifyContent:"center" }}>
        <div ref={certRef} style={{ width:"100%", maxWidth:900, background:"#fff", fontFamily:"Arial,Helvetica,sans-serif", fontSize:"10px", lineHeight:1.5, padding:"20px 24px", boxShadow:"0 4px 20px rgba(0,0,0,0.3)" }}>

          {/* HEADER */}
          <table style={S}>
            <tbody>
              <tr>
                <td style={{ width:"30%", verticalAlign:"middle", paddingBottom:8 }}>
                  <img src={GSR_LOGO} style={{ height:44, objectFit:"contain" }} alt="Gas Safe"/>
                </td>
                <td style={{ width:"40%", verticalAlign:"middle" }}></td>
                <td style={{ width:"30%", verticalAlign:"top", textAlign:"right", fontSize:"9px" }}>
                  <div style={{ display:"flex", alignItems:"center", justifyContent:"flex-end", gap:6, marginBottom:3 }}>
                    <span>Reference</span>
                    <span style={{ border:b, padding:"2px 8px", minWidth:100, display:"inline-block", background:"#fff" }}>{fd.fileRef||""}</span>
                  </div>
                  <div style={{ textAlign:"right", fontSize:"8.5px", color:"#333" }}>Certificate No: {fd.certNo||""}</div>
                </td>
              </tr>
            </tbody>
          </table>

          {/* TITLE */}
          <div style={{ textAlign:"center", fontWeight:900, fontSize:"22px", lineHeight:1.3, margin:"10px 0 18px", fontFamily:"Arial,Helvetica,sans-serif" }}>
            Work Commencing Prior To The Expiry<br/>Of The Cancelation Period
          </div>

          {/* INSTALLATION + CLIENT side by side */}
          <table style={{ ...S, marginBottom:20 }}>
            <tbody>
              <tr style={{ verticalAlign:"top" }}>
                {/* Installation Details */}
                <td style={{ width:"48%", paddingRight:16 }}>
                  <div style={{ background:"#555", color:"#fff", fontWeight:700, fontSize:"10px", padding:"3px 8px", marginBottom:6 }}>Installation Details</div>
                  <table style={S}>
                    <tbody>
                      <tr>
                        <td style={{ fontSize:"9px", verticalAlign:"top", width:"28%", paddingTop:2 }}>Installation<br/>Address:</td>
                        <td style={{ border:b, padding:"4px 8px", fontSize:"9.5px", lineHeight:1.6 }}>
                          {fd.instName||""}{fd.instName&&<br/>}
                          {fd.instAddr2||""}{fd.instAddr2&&<br/>}
                          {fd.instEmail&&<><br/>{fd.instEmail}</>}
                          <div style={{ textAlign:"right", fontSize:"9px", marginTop:2 }}>Post Code: {fd.instPostcode||""}</div>
                        </td>
                      </tr>
                      <tr>
                        <td style={{ fontSize:"9px", paddingTop:4 }}>Telephone No:</td>
                        <td style={{ border:b, padding:"3px 8px", fontSize:"9.5px" }}>{fd.instTel||""}</td>
                      </tr>
                    </tbody>
                  </table>
                </td>
                <td style={{ width:"4%" }}></td>
                {/* Client Details */}
                <td style={{ width:"48%" }}>
                  <div style={{ background:"#555", color:"#fff", fontWeight:700, fontSize:"10px", padding:"3px 8px", marginBottom:6 }}>Client Details</div>
                  <table style={S}>
                    <tbody>
                      <tr>
                        <td style={{ fontSize:"9px", verticalAlign:"top", width:"28%", paddingTop:2 }}>Client Address:</td>
                        <td style={{ border:b, padding:"4px 8px", fontSize:"9.5px", lineHeight:1.6 }}>
                          {fd.clientName||""}{fd.clientName&&<br/>}
                          {fd.clientAddr2||""}{fd.clientAddr2&&<br/>}
                          {fd.clientEmail&&<><br/>{fd.clientEmail}</>}
                          <div style={{ textAlign:"right", fontSize:"9px", marginTop:2 }}>Post Code: {fd.clientPostcode||""}</div>
                        </td>
                      </tr>
                      <tr>
                        <td style={{ fontSize:"9px", paddingTop:4 }}>Telephone No:</td>
                        <td style={{ border:b, padding:"3px 8px", fontSize:"9.5px" }}>{fd.clientTel||""}</td>
                      </tr>
                    </tbody>
                  </table>
                </td>
              </tr>
            </tbody>
          </table>

          {/* DEAR CLIENT LETTER */}
          <div style={{ fontSize:"10.5px", lineHeight:2.0, marginBottom:18 }}>
            <p style={{ margin:"0 0 14px" }}>Dear Client,</p>
            <p style={{ margin:"0 0 14px" }}>You agree that the engineer and or company below may commence work on the date (see below) on the installation (see above), before your cancellation period expires. You understand that if you decide to cancel within 15 days you may be required to pay for any work that has been carried out prior to your cancellation request.</p>
          </div>

          {/* NOTE */}
          <div style={{ fontSize:"10px", lineHeight:1.8, marginBottom:24, color:"#222" }}>
            <p style={{ margin:0 }}>Note: Notice of Right To Cancel Requests must be made within 15 days of today's date (see below) in Writing or by Email or hand delivered. If sending by letter you are advised to send by recorded delivery. Cancellation is deemed to have started once the notice has been posted. Your Notice Of Rights To Cancel must include your details, the installation details, the reference number (see above) and must be signed and dated by the client.</p>
          </div>

          {/* ENGINEERING DETAILS + SIGNATURES */}
          <table style={{ ...S, marginBottom:12 }}>
            <tbody>
              <tr style={{ verticalAlign:"top" }}>
                {/* Engineering Details */}
                <td style={{ width:"48%", paddingRight:16 }}>
                  <div style={{ background:"#555", color:"#fff", fontWeight:700, fontSize:"10px", padding:"3px 8px", marginBottom:6 }}>Engineering Details</div>
                  <table style={S}>
                    <tbody>
                      <tr>
                        <td style={{ fontSize:"9px", width:"28%", paddingTop:4 }}>Trading Title</td>
                        <td style={{ border:b, padding:"3px 8px", fontSize:"9.5px" }}>{fd.tradingTitle||eng.companyName||""}</td>
                      </tr>
                      <tr>
                        <td style={{ fontSize:"9px", verticalAlign:"top", paddingTop:4 }}>Address</td>
                        <td style={{ border:b, padding:"4px 8px", fontSize:"9.5px", lineHeight:1.6 }}>
                          {fd.engAddr||eng.companyAddr||""}{(fd.engAddr||eng.companyAddr)&&<br/>}
                          {fd.engCity||""}{fd.engCity&&<br/>}
                          <div style={{ textAlign:"right" }}>{fd.engPostcode||eng.companyPostcode||""}</div>
                        </td>
                      </tr>
                      <tr>
                        <td style={{ fontSize:"9px", paddingTop:4 }}>Gas Safe No</td>
                        <td style={{ padding:"3px 0", fontSize:"9.5px" }}>
                          <table style={{ width:"100%", borderCollapse:"collapse" }}>
                            <tbody>
                              <tr>
                                <td style={{ border:b, padding:"3px 8px", width:"50%" }}>{fd.gasSafeNo||eng.gasSafeNo||""}</td>
                                <td style={{ fontSize:"9px", padding:"3px 6px", textAlign:"right" }}>Tel No</td>
                                <td style={{ border:b, padding:"3px 8px" }}>{fd.engTel||eng.companyTel||""}</td>
                              </tr>
                            </tbody>
                          </table>
                        </td>
                      </tr>
                    </tbody>
                  </table>
                </td>
                <td style={{ width:"4%" }}></td>
                {/* Signatures */}
                <td style={{ width:"48%" }}>
                  <div style={{ marginBottom:12 }}>
                    <div style={{ fontSize:"10px", marginBottom:4 }}>Client's Signature/Date</div>
                    <div style={{ border:b, minHeight:50, padding:"4px 8px", display:"flex", flexDirection:"column", justifyContent:"space-between" }}>
                      {fd.sigClientImg ? <img src={fd.sigClientImg} style={{ maxHeight:34, maxWidth:"100%", objectFit:"contain", alignSelf:"flex-start" }} alt="sig"/> : <div style={{ flex:1 }}/>}
                      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-end" }}>
                        <div style={{ fontSize:"8px", color:"#333" }}>{fd.sigClient||""}</div>
                        <div style={{ textAlign:"right", fontSize:"9px" }}>{fmtDate(effCliDate)||""}</div>
                      </div>
                    </div>
                  </div>
                  <div>
                    <div style={{ fontSize:"10px", marginBottom:4 }}>Engineer's Signature/Date</div>
                    <div style={{ border:b, minHeight:50, padding:"4px 8px", display:"flex", flexDirection:"column", justifyContent:"space-between" }}>
                      {fd.sigEngineerImg ? <img src={fd.sigEngineerImg} style={{ maxHeight:34, maxWidth:"100%", objectFit:"contain", alignSelf:"flex-start" }} alt="sig"/> : <div style={{ flex:1 }}/>}
                      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-end" }}>
                        <div style={{ fontSize:"8px", color:"#333" }}>{fd.sigEngineer||""}</div>
                        <div style={{ textAlign:"right", fontSize:"9px" }}>{fmtDate(effEngDate)||""}</div>
                      </div>
                    </div>
                  </div>
                </td>
              </tr>
            </tbody>
          </table>

          {/* FOOTER */}
          <div style={{ textAlign:"center", fontSize:"8px", color:"#666", borderTop:"1px solid #ccc", paddingTop:6, marginTop:8 }}>
            This Gas Safety Report was created by {eng.companyName||""}{eng.gasSafeNo?" | Gas Safe Reg: "+eng.gasSafeNo:""}{eng.companyTel?" | Tel: "+eng.companyTel:""}
          </div>

        </div>
      </div>
    </div>
  );
}

// ─── ORCHESTRATOR ─────────────────────────────────────────────────────────────

function CoolOffScreen({ engineerData, onBack, onHome, onSave, initialData }) {
  const [step, setStep] = useState("fileRef");
  const [showPDF, setShowPDF] = useState(false);
  const today = new Date().toISOString().slice(0,10);
  const eng = engineerData || {};

  const [data, setData] = useState({
    fileRef:"", certNo:"",
    instName:"", instAddr2:"", instEmail:"", instPostcode:"", instTel:"",
    clientName:"", clientAddr2:"", clientEmail:"", clientPostcode:"", clientTel:"",
    tradingTitle:eng.companyName||"", engAddr:eng.companyAddr||"", engCity:"",
    engPostcode:eng.companyPostcode||"", gasSafeNo:eng.gasSafeNo||"", engTel:eng.companyTel||"",
    sigClient:"", sigClientDate:today, sigClientImg:null,
    sigEngineer:eng.engineerName||"", sigEngDate:today, sigEngineerImg:null,
    ...(initialData||{}),
  });

  if (showPDF) return <CoolOffPDF
    formData={data} engineerData={engineerData}
    onClose={()=>setShowPDF(false)}
    onSave={()=>{ onSave({ type:"cooling_off", certLabel:"7 Day Cooling Off Period Exemption", form:data, engineerData, savedAt:new Date().toISOString() }); alert("Certificate saved to Records!"); }}/>;

  const steps = {
    fileRef:     <CoolOffStepFileRef     data={data} onChange={setData} onBack={onBack}                     onHome={onHome} onNext={()=>setStep("details")}/>,
    details:     <CoolOffStepDetails     data={data} onChange={setData} onBack={()=>setStep("fileRef")}     onHome={onHome} onNext={()=>setStep("engineering")}/>,
    engineering: <CoolOffStepEngineering data={data} onChange={setData} onBack={()=>setStep("details")}     onHome={onHome} onNext={()=>setStep("attachments")}/>,
    attachments: <AttachmentsStep         data={data} onChange={setData} onBack={()=>setStep("engineering")} onHome={onHome} onNext={()=>setStep("engineerSig")} accentColor={COOL_COLOR} nextLabel="Next: Signatures"/>,
    engineerSig: <SharedSigStep          data={data} onChange={setData} onBack={()=>setStep("attachments")} onHome={onHome} onNext={()=>setStep("customerSig")} accentColor={COOL_COLOR} certTitle="7 Day Cooling Off Period Exemption"/>,
    customerSig: <CustomerSigStep        data={data} onChange={setData} onBack={()=>setStep("engineerSig")} onHome={onHome} onNext={()=>setShowPDF(true)} accentColor={COOL_COLOR}/>,
  };
  return steps[step] || null;
}


